
const questions = [
    { id: 1, text: "Nền văn hóa khảo cổ nào tiêu biểu cho thời kỳ Hùng Vương dựng nước?", options: ["A. Văn hóa Sa Huỳnh", "B. Văn hóa Óc Eo", "C. Văn hóa Đông Sơn", "D. Văn hóa Chăm Pa"], correctAnswer: "C. Văn hóa Đông Sơn" },
  { id: 2, text: "Nhà nước Văn Lang tồn tại qua bao nhiêu đời Vua Hùng?", options: ["A. 12 đời", "B. 18 đời", "C. 36 đời", "D. 100 đời"], correctAnswer: "B. 18 đời" },
  { id: 3, text: "Kinh đô của nhà nước Âu Lạc dưới thời An Dương Vương là ở đâu?", options: ["A. Phong Châu", "B. Cổ Loa", "C. Hoa Lư", "D. Thăng Long"], correctAnswer: "B. Cổ Loa" },
  { id: 4, text: "Cuộc khởi nghĩa Hai Bà Trưng bùng nổ vào năm nào?", options: ["A. Năm 40 SCN", "B. Năm 43 SCN", "C. Năm 248 SCN", "D. Năm 542 SCN"], correctAnswer: "A. Năm 40 SCN" },
  { id: 5, text: "Tên nước Vạn Xuân được đặt dưới triều đại nào?", options: ["A. Nhà Ngô", "B. Nhà Đinh", "C. Nhà Tiền Lý", "D. Nhà Ngô"], correctAnswer: "C. Nhà Tiền Lý" },
  { id: 6, text: "Ai là người lãnh đạo cuộc khởi nghĩa lật đổ ách đô hộ của nhà Lương, thành lập nhà nước Vạn Xuân?", options: ["A. Lý Bí", "B. Mai Thúc Loan", "C. Phùng Hưng", "D. Khúc Thừa Dụ"], correctAnswer: "A. Lý Bí" },
  { id: 7, text: "Trận chiến trên sông Bạch Đằng năm 938, Ngô Quyền đã đánh tan quân xâm lược của triều đại phong kiến phương Bắc nào?", options: ["A. Nhà Hán", "B. Nhà Tùy", "C. Nhà Đường", "D. Nhà Nam Hán"], correctAnswer: "D. Nhà Nam Hán" },
  { id: 8, text: "Sau chiến thắng Bạch Đằng năm 938, Ngô Quyền đã làm gì để khẳng định nền độc lập dân tộc?", options: ["A. Lên ngôi Hoàng đế", "B. Xây dựng kinh đô ở Hoa Lư", "C. Bỏ chức Tiết độ sứ, xưng vương, đóng đô ở Cổ Loa", "D. Chia nước làm 12 sứ quân"], correctAnswer: "C. Bỏ chức Tiết độ sứ, xưng vương, đóng đô ở Cổ Loa" },
  { id: 9, text: "Thời kỳ \"Loạn 12 sứ quân\" diễn ra sau sự kiện nào?", options: ["A. Nhà Ngô suy yếu và sụp đổ", "B. Nhà Đinh thành lập", "C. Nhà Tiền Lê thành lập", "D. Khúc Thừa Dụ giành quyền tự chủ"], correctAnswer: "A. Nhà Ngô suy yếu và sụp đổ" },
  { id: 10, text: "Ai là người đã dẹp tan \"Loạn 12 sứ quân\", thống nhất đất nước và lên ngôi Hoàng đế?", options: ["A. Đinh Bộ Lĩnh", "B. Lê Hoàn", "C. Lý Công Uẩn", "D. Trần Cảnh"], correctAnswer: "A. Đinh Bộ Lĩnh" },
  { id: 11, text: "Nhà Đinh đặt quốc hiệu là gì?", options: ["A. Đại Cồ Việt", "B. Đại Việt", "C. Việt Nam", "D. Đại Nam"], correctAnswer: "A. Đại Cồ Việt" },
  { id: 12, text: "Kinh đô của nhà Đinh và nhà Tiền Lê đặt ở đâu?", options: ["A. Cổ Loa", "B. Thăng Long", "C. Hoa Lư", "D. Phú Xuân"], correctAnswer: "C. Hoa Lư" },
  { id: 13, text: "Ai là người lãnh đạo cuộc kháng chiến chống Tống lần thứ nhất vào năm 981?", options: ["A. Đinh Tiên Hoàng", "B. Lê Hoàn", "C. Lý Thường Kiệt", "D. Trần Quốc Tuấn"], correctAnswer: "B. Lê Hoàn" },
  { id: 14, text: "Triều đại nào đã dời đô từ Hoa Lư về Thăng Long (Hà Nội ngày nay)?", options: ["A. Nhà Đinh", "B. Nhà Tiền Lê", "C. Nhà Lý", "D. Nhà Trần"], correctAnswer: "C. Nhà Lý" },
  { id: 15, text: "Bộ luật thành văn đầu tiên của Việt Nam có tên là gì, được ban hành dưới triều đại nào?", options: ["A. Hình Thư (nhà Lý)", "B. Hình Luật (nhà Trần)", "C. Quốc Triều Hình Luật (nhà Hậu Lê)", "D. Hoàng Việt Luật Lệ (nhà Nguyễn)"], correctAnswer: "A. Hình Thư (nhà Lý)" },
  { id: 16, text: "Tác phẩm \"Nam quốc sơn hà\" được coi là bản Tuyên ngôn độc lập đầu tiên của Việt Nam, gắn liền với cuộc kháng chiến chống quân Tống dưới sự lãnh đạo của ai?", options: ["A. Lê Hoàn", "B. Lý Thường Kiệt", "C. Trần Quốc Tuấn", "D. Nguyễn Huệ"], correctAnswer: "B. Lý Thường Kiệt" },
  { id: 17, text: "Ba lần kháng chiến chống quân Mông - Nguyên thắng lợi vang dội diễn ra dưới triều đại nào?", options: ["A. Nhà Lý", "B. Nhà Trần", "C. Nhà Hồ", "D. Nhà Hậu Lê"], correctAnswer: "B. Nhà Trần" },
  { id: 18, text: "Hội nghị Diên Hồng là biểu tượng của sự đoàn kết toàn dân trong cuộc kháng chiến chống quân Mông - Nguyên lần thứ mấy?", options: ["A. Lần thứ nhất", "B. Lần thứ hai", "C. Lần thứ ba", "D. Cả ba lần"], correctAnswer: "B. Lần thứ hai" },
  { id: 19, text: "Ai là tác giả của \"Hịch tướng sĩ\", có tác dụng cổ vũ tinh thần chiến đấu của quân dân nhà Trần?", options: ["A. Trần Hưng Đạo (Trần Quốc Tuấn)", "B. Trần Quang Khải", "C. Trần Thủ Độ", "D. Trần Nhân Tông"], correctAnswer: "A. Trần Hưng Đạo (Trần Quốc Tuấn)" },
  { id: 20, text: "Triều đại nào được coi là đỉnh cao của chế độ phong kiến Việt Nam về mọi mặt (kinh tế, chính trị, văn hóa, giáo dục)?", options: ["A. Nhà Lý", "B. Nhà Trần", "C. Nhà Hồ", "D. Nhà Hậu Lê (thời Lê Sơ)"], correctAnswer: "D. Nhà Hậu Lê (thời Lê Sơ)" },
  { id: 21, text: "Ai là người đã lãnh đạo cuộc khởi nghĩa Lam Sơn đánh đuổi quân Minh, giành lại độc lập cho đất nước vào thế kỷ XV?", options: ["A. Trần Hưng Đạo", "B. Lê Lợi", "C. Nguyễn Trãi", "D. Nguyễn Huệ"], correctAnswer: "B. Lê Lợi" },
  { id: 22, text: "Tác phẩm \"Bình Ngô đại cáo\" là bản tuyên ngôn độc lập lần thứ hai của Việt Nam, do ai sáng tác?", options: ["A. Lê Lợi", "B. Nguyễn Trãi", "C. Trần Nguyên Hãn", "D. Lê Thánh Tông"], correctAnswer: "B. Nguyễn Trãi" },
  { id: 23, text: "Vua Lê Thánh Tông đã thực hiện cuộc cải cách hành chính quan trọng nào?", options: ["A. Chia cả nước thành các lộ", "B. Chia cả nước thành các đạo", "C. Chia cả nước thành các tỉnh", "D. Chia cả nước thành 13 đạo thừa tuyên"], correctAnswer: "D. Chia cả nước thành 13 đạo thừa tuyên" },
  { id: 24, text: "Giai đoạn Trịnh - Nguyễn phân tranh (Đàng Ngoài - Đàng Trong) diễn ra vào thời kỳ nào?", options: ["A. Cuối nhà Trần", "B. Nhà Hồ", "C. Nhà Hậu Lê (thời Lê Trung Hưng)", "D. Nhà Tây Sơn"], correctAnswer: "C. Nhà Hậu Lê (thời Lê Trung Hưng)" },
  { id: 25, text: "Ai là người đã lập nên vương triều Tây Sơn, lãnh đạo các cuộc khởi nghĩa nông dân và đánh bại các thế lực phong kiến khác?", options: ["A. Nguyễn Huệ", "B. Nguyễn Nhạc", "C. Nguyễn Lữ", "D. Cả A, B, C"], correctAnswer: "D. Cả A, B, C" },
  { id: 26, text: "Trận Rạch Gầm - Xoài Mút (năm 1785), nghĩa quân Tây Sơn đã đánh tan quân xâm lược của quốc gia nào?", options: ["A. Xiêm La", "B. Thanh", "C. Chân Lạp", "D. Vạn Tượng"], correctAnswer: "A. Xiêm La" },
  { id: 27, text: "Trận Ngọc Hồi - Đống Đa (Xuân Kỷ Dậu 1789), Quang Trung - Nguyễn Huệ đã đánh tan quân xâm lược của triều đại nào?", options: ["A. Xiêm La", "B. Thanh", "C. Mãn Thanh", "D. Minh"], correctAnswer: "C. Mãn Thanh" },
  { id: 28, text: "Nhà Nguyễn được thành lập vào năm nào?", options: ["A. Năm 1789", "B. Năm 1802", "C. Năm 1858", "D. Năm 1945"], correctAnswer: "B. Năm 1802" },
  { id: 29, text: "Vua Gia Long là người đã thống nhất đất nước sau thời kỳ Tây Sơn và lập ra triều Nguyễn, tên thật của ông là gì?", options: ["A. Nguyễn Huệ", "B. Nguyễn Nhạc", "C. Nguyễn Ánh", "D. Nguyễn Lữ"], correctAnswer: "C. Nguyễn Ánh" },
  { id: 30, text: "Kinh đô của nhà Nguyễn đặt ở đâu?", options: ["A. Thăng Long", "B. Hoa Lư", "C. Phú Xuân (Huế)", "D. Gia Định"], correctAnswer: "C. Phú Xuân (Huế)" },
  { id: 31, text: "Thực dân Pháp bắt đầu xâm lược Việt Nam vào năm nào, tại địa điểm nào?", options: ["A. Năm 1858 tại Đà Nẵng", "B. Năm 1862 tại Sài Gòn", "C. Năm 1884 tại Thuận An", "D. Năm 1897 trên toàn Đông Dương"], correctAnswer: "A. Năm 1858 tại Đà Nẵng" },
  { id: 32, text: "Hiệp ước Patơnốt (1884) đã chính thức chấm dứt sự tồn tại độc lập của triều Nguyễn và Việt Nam trở thành thuộc địa của Pháp. Triều đình nhà Nguyễn ký hiệp ước này dưới thời vua nào?", options: ["A. Vua Tự Đức", "B. Vua Hàm Nghi", "C. Vua Đồng Khánh", "D. Vua Kiến Phúc"], correctAnswer: "D. Vua Kiến Phúc" },
  { id: 33, text: "Phong trào Cần Vương là phong trào đấu tranh chống Pháp của tầng lớp nào trong xã hội Việt Nam cuối thế kỷ XIX?", options: ["A. Nông dân", "B. Văn thân, sĩ phu yêu nước", "C. Công nhân", "D. Tư sản dân tộc"], correctAnswer: "B. Văn thân, sĩ phu yêu nước" },
  { id: 34, text: "Ai là người đã ra chiếu Cần Vương, kêu gọi toàn dân kháng chiến chống Pháp?", options: ["A. Vua Hàm Nghi", "B. Tôn Thất Thuyết", "C. Phan Đình Phùng", "D. Hoàng Hoa Thám"], correctAnswer: "A. Vua Hàm Nghi" },
  { id: 35, text: "Cuộc khởi nghĩa Yên Thế do ai lãnh đạo, kéo dài trong khoảng thời gian nào?", options: ["A. Phan Đình Phùng (1885-1895)", "B. Hoàng Hoa Thám (1884-1913)", "C. Nguyễn Thái Học (1930)", "D. Lương Ngọc Quyến (1917)"], correctAnswer: "B. Hoàng Hoa Thám (1884-1913)" },
  { id: 36, text: "Phong trào Đông Du do ai khởi xướng, nhằm mục đích gì?", options: ["A. Phan Châu Trinh - Cải cách xã hội", "B. Phan Bội Châu - Sang Nhật Bản học tập và chuẩn bị lực lượng chống Pháp", "C. Nguyễn Ái Quốc - Tìm đường cứu nước", "D. Hoàng Hoa Thám - Duy trì cuộc sống tự do ở Yên Thế"], correctAnswer: "B. Phan Bội Châu - Sang Nhật Bản học tập và chuẩn bị lực lượng chống Pháp" },
  { id: 37, text: "Tổ chức tiền thân của Đảng Cộng sản Việt Nam được thành lập vào năm 1925 với tên gọi là gì?", options: ["A. Hội Việt Nam Cách mạng Thanh niên", "B. Tân Việt Cách mạng Đảng", "C. Việt Nam Quốc dân Đảng", "D. Đông Dương Cộng sản Đảng"], correctAnswer: "A. Hội Việt Nam Cách mạng Thanh niên" },
  { id: 38, text: "Đông Dương Cộng sản Đảng và An Nam Cộng sản Đảng được thành lập từ sự phân hóa của tổ chức nào?", options: ["A. Việt Nam Quốc dân Đảng", "B. Tân Việt Cách mạng Đảng", "C. Hội Việt Nam Cách mạng Thanh niên", "D. Thanh niên Cao Vọng"], correctAnswer: "C. Hội Việt Nam Cách mạng Thanh niên" },
  { id: 39, text: "Đảng Cộng sản Việt Nam được thành lập vào ngày, tháng, năm nào?", options: ["A. 3/2/1930", "B. 3/2/1931", "C. 1/5/1930", "D. 1/5/1931"], correctAnswer: "A. 3/2/1930" },
  { id: 40, text: "Nguyễn Ái Quốc đã chủ trì Hội nghị hợp nhất các tổ chức cộng sản tại đâu để thành lập Đảng Cộng sản Việt Nam?", options: ["A. Quảng Châu (Trung Quốc)", "B. Hương Cảng (Trung Quốc)", "C. Pari (Pháp)", "D. Matxcova (Liên Xô)"], correctAnswer: "B. Hương Cảng (Trung Quốc)" },
  { id: 41, text: "Cao trào cách mạng 1930-1931 mà đỉnh cao là Xô Viết Nghệ Tĩnh là phong trào đấu tranh của lực lượng nào dưới sự lãnh đạo của Đảng Cộng sản Việt Nam?", options: ["A. Công nhân", "B. Nông dân", "C. Tiểu tư sản", "D. Công nhân và nông dân"], correctAnswer: "D. Công nhân và nông dân" },
  { id: 42, text: "Mặt trận Việt Minh được thành lập vào năm nào?", options: ["A. Năm 1930", "B. Năm 1936", "C. Năm 1941", "D. Năm 1945"], correctAnswer: "C. Năm 1941" },
  { id: 43, text: "Đội Việt Nam Tuyên truyền Giải phóng quân, tiền thân của Quân đội nhân dân Việt Nam, được thành lập vào ngày, tháng, năm nào?", options: ["A. 22/12/1944", "B. 19/8/1945", "C. 2/9/1945", "D. 7/5/1954"], correctAnswer: "A. 22/12/1944" },
  { id: 44, text: "Cuộc đảo chính của Nhật lật đổ Pháp ở Đông Dương diễn ra vào thời gian nào?", options: ["A. Tháng 3 năm 1945", "B. Tháng 8 năm 1945", "C. Tháng 9 năm 1945", "D. Tháng 12 năm 1944"], correctAnswer: "A. Tháng 3 năm 1945" },
  { id: 45, text: "Khẩu hiệu \"Đánh đuổi phát xít Nhật\" và \"Thành lập chính quyền cách mạng của nhân dân\" là chủ trương của Đảng ta trong thời kỳ nào?", options: ["A. Trước Chiến tranh thế giới thứ hai", "B. Trong Chiến tranh thế giới thứ hai, khi Nhật đảo chính Pháp", "C. Sau Chiến tranh thế giới thứ hai", "D. Trong phong trào 1936-1939"], correctAnswer: "B. Trong Chiến tranh thế giới thứ hai, khi Nhật đảo chính Pháp" },
  { id: 46, text: "Tổng khởi nghĩa giành chính quyền trong Cách mạng tháng Tám năm 1945 diễn ra thành công nhanh chóng và ít đổ máu là do đâu?", options: ["A. Kẻ thù chính là Nhật Bản đã đầu hàng Đồng minh", "B. Sự lãnh đạo đúng đắn của Đảng và Mặt trận Việt Minh", "C. Tinh thần yêu nước và sự chuẩn bị chu đáo của nhân dân", "D. Tất cả các yếu tố trên"], correctAnswer: "D. Tất cả các yếu tố trên" },
  { id: 47, text: "Vua Bảo Đại thoái vị, chấm dứt chế độ phong kiến ở Việt Nam vào thời gian nào?", options: ["A. Ngày 19 tháng 8 năm 1945", "B. Ngày 23 tháng 8 năm 1945", "C. Ngày 30 tháng 8 năm 1945", "D. Ngày 2 tháng 9 năm 1945"], correctAnswer: "C. Ngày 30 tháng 8 năm 1945" },
  { id: 48, text: "Chủ tịch Hồ Chí Minh đọc bản Tuyên ngôn độc lập, khai sinh ra nước Việt Nam Dân chủ Cộng hòa vào ngày, tháng, năm nào?", options: ["A. Ngày 19 tháng 8 năm 1945", "B. Ngày 23 tháng 8 năm 1945", "C. Ngày 30 tháng 8 năm 1945", "D. Ngày 2 tháng 9 năm 1945"], correctAnswer: "D. Ngày 2 tháng 9 năm 1945" },
  { id: 49, text: "Thủ đô của nước Việt Nam Dân chủ Cộng hòa sau Cách mạng tháng Tám năm 1945 là ở đâu?", options: ["A. Huế", "B. Sài Gòn", "C. Hà Nội", "D. Cổ Loa"], correctAnswer: "C. Hà Nội" },  { id: 50, text: "Sau Cách mạng tháng Tám, Việt Nam phải đối mặt với những khó khăn \"thù trong giặc ngoài\" nào?", options: ["A. Quân Tưởng Giới Thạch ở miền Bắc, quân Anh và Pháp ở miền Nam", "B. Nạn đói, nạn dốt, ngân sách trống rỗng", "C. Các đảng phái phản cách mạng nổi dậy chống phá", "D. Tất cả các khó khăn trên"], correctAnswer: "D. Tất cả các khó khăn trên" },
  { id: 51, text: "Thực dân Pháp bắt đầu quay trở lại xâm lược Việt Nam lần thứ hai vào thời gian nào?", options: ["A. Tháng 9 năm 1945 tại Sài Gòn", "B. Tháng 12 năm 1946 tại Hà Nội", "C. Tháng 5 năm 1954 tại Điện Biên Phủ", "D. Tháng 7 năm 1954 tại Giơnevơ"], correctAnswer: "A. Tháng 9 năm 1945 tại Sài Gòn" },
  { id: 52, text: "Lời kêu gọi Toàn quốc kháng chiến của Chủ tịch Hồ Chí Minh được đưa ra vào ngày, tháng, năm nào?", options: ["A. 19/12/1946", "B. 20/12/1946", "C. 6/1/1947", "D. 7/5/1954"], correctAnswer: "A. 19/12/1946" },
  { id: 53, text: "Chiến dịch Biên giới Thu Đông năm 1950 thắng lợi đã có ý nghĩa quan trọng gì?", options: ["A. Đánh dấu sự chuyển sang giai đoạn phản công của quân đội ta", "B. Giành quyền chủ động trên chiến trường chính (Bắc Bộ)", "C. Chọc thủng vòng vây biên giới, khai thông con đường liên lạc với các nước xã hội chủ nghĩa", "D. Cả B và C"], correctAnswer: "D. Cả B và C" },
  { id: 54, text: "Đại hội đại biểu toàn quốc lần thứ II của Đảng Cộng sản Đông Dương (năm 1951) đã quyết định đổi tên Đảng thành gì?", options: ["A. Đảng Cộng sản Việt Nam", "B. Đảng Lao động Việt Nam", "C. Đảng Cộng sản Đông Dương", "D. Đảng Công nhân Việt Nam"], correctAnswer: "B. Đảng Lao động Việt Nam" },
  { id: 55, text: "Chiến dịch Điện Biên Phủ diễn ra vào thời gian nào?", options: ["A. Cuối năm 1953", "B. Đầu năm 1954", "C. Từ tháng 3 đến tháng 5 năm 1954", "D. Tháng 7 năm 1954"], correctAnswer: "C. Từ tháng 3 đến tháng 5 năm 1954" },
  { id: 56, text: "Ai là Tổng tư lệnh của Chiến dịch Điện Biên Phủ?", options: ["A. Chủ tịch Hồ Chí Minh", "B. Đại tướng Võ Nguyên Giáp", "C. Tổng Bí thư Trường Chinh", "D. Thủ tướng Phạm Văn Đồng"], correctAnswer: "B. Đại tướng Võ Nguyên Giáp" },
  { id: 57, text: "Chiến thắng Điện Biên Phủ (7/5/1954) đã có tác động quyết định đến sự kiện nào?", options: ["A. Hiệp định Sơ bộ (1946)", "B. Tạm ước (1946)", "C. Hội nghị Giơnevơ về Đông Dương (1954)", "D. Hiệp định Pari (1973)"], correctAnswer: "C. Hội nghị Giơnevơ về Đông Dương (1954)" },
  { id: 58, text: "Theo Hiệp định Giơnevơ năm 1954, Việt Nam tạm thời bị chia cắt làm hai miền tại vĩ tuyến bao nhiêu?", options: ["A. Vĩ tuyến 16", "B. Vĩ tuyến 17", "C. Vĩ tuyến 18", "D. Vĩ tuyến 20"], correctAnswer: "B. Vĩ tuyến 17" },
  { id: 59, text: "Sau Hiệp định Giơnevơ, miền Bắc Việt Nam bước vào thời kỳ nào?", options: ["A. Kháng chiến chống Mỹ", "B. Xây dựng chủ nghĩa xã hội", "C. Đấu tranh thống nhất đất nước", "D. Tất cả các phương án trên"], correctAnswer: "B. Xây dựng chủ nghĩa xã hội" },
  { id: 60, text: "Sau Hiệp định Giơnevơ, đế quốc Mỹ đã làm gì ở miền Nam Việt Nam?", options: ["A. Thi hành Hiệp định Giơnevơ", "B. Rút quân khỏi miền Nam", "C. Hất cẳng Pháp, dựng lên chính quyền tay sai Ngô Đình Diệm", "D. Tôn trọng độc lập, chủ quyền và toàn vẹn lãnh thổ của Việt Nam"], correctAnswer: "C. Hất cẳng Pháp, dựng lên chính quyền tay sai Ngô Đình Diệm" },
  { id: 61, text: "Phong trào Đồng khởi (1959-1960) ở miền Nam Việt Nam là sự bùng nổ của lực lượng nào chống lại chính quyền Ngô Đình Diệm?", options: ["A. Công nhân", "B. Nông dân", "C. Học sinh, sinh viên", "D. Toàn dân"], correctAnswer: "D. Toàn dân" },
  { id: 62, text: "Mặt trận Dân tộc Giải phóng miền Nam Việt Nam được thành lập vào thời gian nào?", options: ["A. Năm 1954", "B. Năm 1959", "C. Năm 1960", "D. Năm 1965"], correctAnswer: "C. Năm 1960" },
  { id: 63, text: "Chiến lược chiến tranh nào của đế quốc Mỹ ở miền Nam Việt Nam sử dụng khẩu hiệu \"tìm và diệt\"?", options: ["A. Chiến tranh đặc biệt", "B. Chiến tranh cục bộ", "C. Việt Nam hóa chiến tranh", "D. Đông Dương hóa chiến tranh"], correctAnswer: "B. Chiến tranh cục bộ" },
  { id: 64, text: "Chiến thắng Ấp Bắc (năm 1963) là thắng lợi mở màn của quân dân miền Nam chống lại chiến lược chiến tranh nào của Mỹ?", options: ["A. Chiến tranh đặc biệt", "B. Chiến tranh cục bộ", "C. Việt Nam hóa chiến tranh", "D. Đông Dương hóa chiến tranh"], correctAnswer: "A. Chiến tranh đặc biệt" },
  { id: 65, text: "Mỹ bắt đầu tiến hành chiến tranh phá hoại miền Bắc lần thứ nhất vào thời gian nào?", options: ["A. Năm 1963", "B. Năm 1964", "C. Năm 1965", "D. Năm 1968"], correctAnswer: "C. Năm 1965" },
  { id: 66, text: "Sự kiện Tết Mậu Thân năm 1968 là cuộc tổng tiến công và nổi dậy của quân dân miền Nam trên khắp các đô thị, có ý nghĩa gì?", options: ["A. Buộc Mỹ phải ngừng ném bom miền Bắc", "B. Mở ra cuộc đàm phán Pari về Việt Nam", "C. Đánh dấu sự phá sản của chiến lược Chiến tranh cục bộ", "D. Tất cả các ý trên"], correctAnswer: "D. Tất cả các ý trên" },
  { id: 67, text: "Chiến lược \"Việt Nam hóa chiến tranh\" của Mỹ nhằm mục đích gì?", options: ["A. Tăng cường quân đội Mỹ tại miền Nam", "B. Rút dần quân Mỹ và tăng cường lực lượng quân đội Sài Gòn", "C. Mở rộng chiến tranh ra toàn Đông Dương", "D. Sử dụng vũ khí hạt nhân để kết thúc chiến tranh"], correctAnswer: "B. Rút dần quân Mỹ và tăng cường lực lượng quân đội Sài Gòn" },
  { id: 68, text: "Hiệp định Pari về chấm dứt chiến tranh, lập lại hòa bình ở Việt Nam được ký kết vào thời gian nào?", options: ["A. Năm 1968", "B. Năm 1972", "C. Năm 1973", "D. Năm 1975"], correctAnswer: "C. Năm 1973" },
  { id: 69, text: "Theo Hiệp định Pari năm 1973, ai là đại diện ký kết của Chính phủ Việt Nam Dân chủ Cộng hòa?", options: ["A. Lê Đức Thọ", "B. Nguyễn Duy Trinh", "C. Xuân Thủy", "D. Phạm Văn Đồng"], correctAnswer: "C. Xuân Thủy" },
  { id: 70, text: "Sau Hiệp định Pari, Mỹ rút hết quân về nước nhưng vẫn tiếp tục viện trợ cho chính quyền Sài Gòn. Ta đã mở cuộc Tổng tiến công và nổi dậy mùa Xuân năm 1975, bắt đầu bằng chiến dịch nào?", options: ["A. Chiến dịch Tây Nguyên", "B. Chiến dịch Huế - Đà Nẵng", "C. Chiến dịch Hồ Chí Minh", "D. Chiến dịch đường 9 - Nam Lào"], correctAnswer: "A. Chiến dịch Tây Nguyên" },
  { id: 71, text: "Chiến dịch Hồ Chí Minh lịch sử giải phóng hoàn toàn miền Nam, thống nhất đất nước diễn ra vào thời gian nào?", options: ["A. Từ tháng 3 đến tháng 5 năm 1975", "B. Từ ngày 26 tháng 4 đến ngày 30 tháng 4 năm 1975", "C. Ngày 30 tháng 4 năm 1975", "D. Tháng 5 năm 1975"], correctAnswer: "B. Từ ngày 26 tháng 4 đến ngày 30 tháng 4 năm 1975" },
  { id: 72, text: "Tổng thống cuối cùng của chế độ Việt Nam Cộng hòa đã đầu hàng vào trưa ngày 30/4/1975 là ai?", options: ["A. Nguyễn Văn Thiệu", "B. Nguyễn Cao Kỳ", "C. Dương Văn Minh", "D. Ngô Đình Diệm"], correctAnswer: "C. Dương Văn Minh" },
  { id: 73, text: "Sau khi miền Nam hoàn toàn giải phóng, cả nước bước vào giai đoạn nào?", options: ["A. Khôi phục kinh tế sau chiến tranh", "B. Xây dựng chủ nghĩa xã hội trên cả nước", "C. Đấu tranh bảo vệ biên giới", "D. Thực hiện công cuộc đổi mới"], correctAnswer: "B. Xây dựng chủ nghĩa xã hội trên cả nước" },
  { id: 74, text: "Kỳ họp Quốc hội khóa VI (năm 1976) đã quyết định đổi tên nước thành gì?", options: ["A. Việt Nam Dân chủ Cộng hòa", "B. Cộng hòa Xã hội chủ nghĩa Việt Nam", "C. Quốc gia Việt Nam", "D. Liên bang Đông Dương"], correctAnswer: "B. Cộng hòa Xã hội chủ nghĩa Việt Nam" },
  { id: 75, text: "Thành phố Sài Gòn - Gia Định được đổi tên thành Thành phố Hồ Chí Minh vào năm nào?", options: ["A. Năm 1975", "B. Năm 1976", "C. Năm 1977", "D. Năm 1986"], correctAnswer: "B. Năm 1976" },
  { id: 76, text: "Đại hội lần thứ IV của Đảng (năm 1976) đã đề ra đường lối cách mạng xã hội chủ nghĩa trong giai đoạn mới, với nhiệm vụ trọng tâm là gì?", options: ["A. Xây dựng và bảo vệ Tổ quốc xã hội chủ nghĩa", "B. Phát triển công nghiệp hóa, hiện đại hóa", "C. Xây dựng nền kinh tế thị trường định hướng xã hội chủ nghĩa", "D. Thực hiện công cuộc đổi mới toàn diện đất nước"], correctAnswer: "A. Xây dựng và bảo vệ Tổ quốc xã hội chủ nghĩa" },
  { id: 77, text: "Việt Nam gia nhập Liên Hợp Quốc vào năm nào?", options: ["A. Năm 1975", "B. Năm 1976", "C. Năm 1977", "D. Năm 1986"], correctAnswer: "C. Năm 1977" },
  { id: 78, text: "Cuộc chiến tranh bảo vệ biên giới Tây Nam của Tổ quốc diễn ra vào thời gian nào?", options: ["A. Năm 1975-1977", "B. Năm 1977-1978", "C. Năm 1978-1979", "D. Năm 1979-1989"], correctAnswer: "C. Năm 1978-1979" },
  { id: 79, text: "Cuộc chiến tranh bảo vệ biên giới phía Bắc của Tổ quốc diễn ra vào thời gian nào?", options: ["A. Năm 1978", "B. Năm 1979", "C. Năm 1979-1989", "D. Năm 1986"], correctAnswer: "B. Năm 1979" },
  { id: 80, text: "Giai đoạn từ năm 1976 đến năm 1985, Việt Nam gặp phải những khó khăn chủ yếu nào về kinh tế?", options: ["A. Nền kinh tế còn mang nặng tính tự cung tự cấp", "B. Hậu quả chiến tranh nặng nề, các thế lực thù địch bao vây cấm vận", "C. Cơ chế quản lý kinh tế tập trung quan liêu bao cấp bộc lộ nhiều yếu kém", "D. Tất cả các khó khăn trên"], correctAnswer: "D. Tất cả các khó khăn trên" },
  { id: 81, text: "Bối cảnh quốc tế chủ yếu tác động đến việc Việt Nam thực hiện công cuộc đổi mới vào năm 1986 là gì?", options: ["A. Sự sụp đổ của hệ thống xã hội chủ nghĩa ở Đông Âu và Liên Xô", "B. Cuộc cách mạng khoa học - kỹ thuật đang phát triển mạnh mẽ", "C. Xu thế toàn cầu hóa và hội nhập quốc tế diễn ra mạnh mẽ", "D. Cả B và C"], correctAnswer: "D. Cả B và C" },
  { id: 82, text: "Đại hội đại biểu toàn quốc lần thứ VI của Đảng Cộng sản Việt Nam (năm 1986) đã đề ra đường lối gì?", options: ["A. Đường lối kháng chiến toàn dân, toàn diện", "B. Đường lối xây dựng chủ nghĩa xã hội", "C. Đường lối đổi mới toàn diện đất nước", "D. Đường lối công nghiệp hóa, hiện đại hóa"], correctAnswer: "C. Đường lối đổi mới toàn diện đất nước" },
  { id: 83, text: "Nội dung cơ bản của đường lối đổi mới do Đảng Cộng sản Việt Nam đề ra năm 1986 là gì?", options: ["A. Đổi mới về chính trị là trọng tâm", "B. Đổi mới về kinh tế là trọng tâm", "C. Đổi mới toàn diện, đồng bộ, có kế thừa", "D. Chỉ đổi mới về kinh tế, giữ nguyên về chính trị"], correctAnswer: "C. Đổi mới toàn diện, đồng bộ, có kế thừa" },
  { id: 84, text: "Quan điểm \"Nhìn thẳng vào sự thật, đánh giá đúng sự thật, nói rõ sự thật\" được đề cao tại Đại hội nào của Đảng?", options: ["A. Đại hội IV (1976)", "B. Đại hội V (1982)", "C. Đại hội VI (1986)", "D. Đại hội VII (1991)"], correctAnswer: "C. Đại hội VI (1986)" },
  { id: 85, text: "Chủ trương phát triển nền kinh tế hàng hóa nhiều thành phần, vận hành theo cơ chế thị trường có sự quản lý của Nhà nước được đề ra tại Đại hội nào của Đảng?", options: ["A. Đại hội V (1982)", "B. Đại hội VI (1986)", "C. Đại hội VII (1991)", "D. Đại hội VIII (1996)"], correctAnswer: "B. Đại hội VI (1986)" },
  { id: 86, text: "Công cuộc đổi mới ở Việt Nam (từ năm 1986) đã chuyển đổi nền kinh tế từ cơ chế nào sang cơ chế nào?", options: ["A. Từ kinh tế thị trường sang kinh tế kế hoạch hóa tập trung", "B. Từ kinh tế kế hoạch hóa tập trung sang kinh tế thị trường", "C. Từ kinh tế tự cung tự cấp sang kinh tế hàng hóa", "D. Từ kinh tế nông nghiệp sang kinh tế công nghiệp"], correctAnswer: "B. Từ kinh tế kế hoạch hóa tập trung sang kinh tế thị trường" },
  { id: 87, text: "Thành tựu nổi bật nhất mà Việt Nam đạt được sau những năm đầu thực hiện công cuộc đổi mới (từ 1986) là gì?", options: ["A. Thoát khỏi tình trạng khủng hoảng kinh tế - xã hội", "B. Bình thường hóa quan hệ với Mỹ", "C. Gia nhập ASEAN", "D. Xuất khẩu gạo đứng đầu thế giới"], correctAnswer: "A. Thoát khỏi tình trạng khủng hoảng kinh tế - xã hội" },
  { id: 88, text: "Việc Việt Nam bình thường hóa quan hệ với Trung Quốc (năm 1991) và Mỹ (năm 1995) có ý nghĩa quan trọng gì?", options: ["A. Phá vỡ sự bao vây cấm vận của các thế lực thù địch", "B. Mở ra cơ hội hội nhập quốc tế rộng lớn", "C. Cải thiện môi trường đối ngoại cho công cuộc đổi mới", "D. Tất cả các ý trên"], correctAnswer: "D. Tất cả các ý trên" },
  { id: 89, text: "Việt Nam chính thức gia nhập Hiệp hội các quốc gia Đông Nam Á (ASEAN) vào năm nào?", options: ["A. Năm 1986", "B. Năm 1991", "C. Năm 1995", "D. Năm 2007"], correctAnswer: "C. Năm 1995" },
  { id: 90, text: "Công cuộc đổi mới đã mang lại những thay đổi căn bản nào cho xã hội Việt Nam?", options: ["A. Đời sống vật chất và tinh thần của nhân dân được cải thiện rõ rệt", "B. Vị thế của Việt Nam trên trường quốc tế được nâng cao", "C. Hệ thống chính trị ngày càng được củng cố và hoàn thiện", "D. Tất cả các thay đổi trên"], correctAnswer: "D. Tất cả các thay đổi trên" },
  { id: 91, text: "Cương lĩnh xây dựng đất nước trong thời kỳ quá độ lên chủ nghĩa xã hội (năm 1991) đã xác định mô hình kinh tế tổng quát là gì?", options: ["A. Kinh tế kế hoạch hóa tập trung", "B. Kinh tế thị trường", "C. Kinh tế thị trường định hướng xã hội chủ nghĩa", "D. Kinh tế nhiều thành phần"], correctAnswer: "C. Kinh tế thị trường định hướng xã hội chủ nghĩa" },
  { id: 92, text: "Đại hội nào của Đảng Cộng sản Việt Nam đã chính thức đưa ra khái niệm \"Kinh tế thị trường định hướng xã hội chủ nghĩa\"?", options: ["A. Đại hội VI (1986)", "B. Đại hội VII (1991)", "C. Đại hội VIII (1996)", "D. Đại hội IX (2001)"], correctAnswer: "B. Đại hội VII (1991)" },
  { id: 93, text: "Mục tiêu tổng quát của công cuộc đổi mới ở Việt Nam là gì?", options: ["A. Xây dựng đất nước giàu mạnh, dân chủ, công bằng, văn minh", "B. Đưa Việt Nam trở thành nước công nghiệp phát triển", "C. Nâng cao đời sống vật chất và tinh thần của nhân dân", "D. Hội nhập sâu rộng vào nền kinh tế thế giới"], correctAnswer: "A. Xây dựng đất nước giàu mạnh, dân chủ, công bằng, văn minh" },
  { id: 94, text: "Từ năm 1986 đến thời điểm hiện tại, công cuộc đổi mới ở Việt Nam đã trải qua bao nhiêu kỳ Đại hội Đảng?", options: ["A. 6 kỳ", "B. 7 kỳ", "C. 8 kỳ", "D. 9 kỳ"], correctAnswer: "C. 8 kỳ" },
  { id: 95, text: "Nghị quyết Hội nghị Trung ương 5 khóa VIII (năm 1998) đã xác định xây dựng nền văn hóa Việt Nam tiên tiến, đậm đà bản sắc dân tộc là gì?", options: ["A. Mục tiêu hàng đầu", "B. Động lực cho sự phát triển", "C. Nền tảng tinh thần của xã hội", "D. Yếu tố quyết định thắng lợi của công cuộc đổi mới"], correctAnswer: "C. Nền tảng tinh thần của xã hội" },
  { id: 96, text: "Về đối ngoại, đường lối đổi mới của Việt Nam chủ trương gì?", options: ["A. Đa dạng hóa, đa phương hóa quan hệ quốc tế", "B. Hội nhập quốc tế sâu rộng", "C. Là bạn, là đối tác tin cậy của các nước, chủ động và tích cực hội nhập quốc tế", "D. Tất cả các phương án trên"], correctAnswer: "D. Tất cả các phương án trên" },
  { id: 97, text: "Việc Việt Nam gia nhập Tổ chức Thương mại Thế giới (WTO) vào năm 2007 có ý nghĩa quan trọng gì?", options: ["A. Đánh dấu sự hội nhập toàn diện vào nền kinh tế toàn cầu", "B. Mở ra thị trường xuất khẩu rộng lớn", "C. Thu hút đầu tư nước ngoài", "D. Tất cả các ý trên"], correctAnswer: "D. Tất cả các ý trên" },
  { id: 98, text: "Thành tựu về kinh tế nổi bật nhất của Việt Nam trong những năm thực hiện đổi mới là gì?", options: ["A. Tốc độ tăng trưởng kinh tế cao liên tục", "B. Cơ cấu kinh tế chuyển dịch theo hướng công nghiệp hóa, hiện đại hóa", "C. Đời sống vật chất và tinh thần của nhân dân được cải thiện rõ rệt", "D. Tất cả các ý trên"], correctAnswer: "D. Tất cả các ý trên" },
  { id: 99, text: "Bên cạnh những thành tựu, công cuộc đổi mới ở Việt Nam cũng đặt ra những thách thức lớn nào?", options: ["A. Nguy cơ tụt hậu về kinh tế so với các nước trong khu vực và thế giới", "B. Sự phân hóa giàu nghèo ngày càng gia tăng", "C. Những vấn đề về môi trường, xã hội", "D. Tất cả các thách thức trên"], correctAnswer: "D. Tất cả các thách thức trên" },  { id: 100, text: "Bài học kinh nghiệm quan trọng nhất được rút ra từ công cuộc đổi mới ở Việt Nam là gì?", options: ["A. Phải luôn kiên định mục tiêu độc lập dân tộc và chủ nghĩa xã hội", "B. Phải phát huy vai trò lãnh đạo của Đảng Cộng sản Việt Nam", "C. Phải dựa vào dân, vì dân", "D. Tất cả các bài học trên"], correctAnswer: "D. Tất cả các bài học trên" },
  { id: 101, text: "Vị danh sĩ mang họ Ngô nào từng soạn bộ \"Lê triều sử ký\"?", options: ["A. Ngô Thì Nhậm", "B. Ngô Quyền", "C. Ngô Sĩ Liên", "D. Ngô Văn Sở"], correctAnswer: "A. Ngô Thì Nhậm" },
  { id: 102, text: "Ai là danh tướng dưới triều Lý, từng dẹp Chiêm Thành và đánh thắng quân Tống?", options: ["A. Trần Hưng Đạo", "B. Lý Thường Kiệt", "C. Lê Hoàn", "D. Trần Quốc Tuấn"], correctAnswer: "B. Lý Thường Kiệt" },
  { id: 103, text: "Vị vua nào được dân gian mô tả với \"gương mặt sắt đen sì\"?", options: ["A. Đinh Tiên Hoàng", "B. Lý Thái Tổ", "C. Mai Hắc Đế", "D. Ngô Quyền"], correctAnswer: "C. Mai Hắc Đế" },
  { id: 104, text: "Tên của người thợ lặn giỏi đã đục thùng thuyền giặc trên sông Bạch Đằng?", options: ["A. Trần Bình Trọng", "B. Yết Kiêu", "C. Phạm Ngũ Lão", "D. Dã Tượng"], correctAnswer: "B. Yết Kiêu" },
  { id: 105, text: "\"Đầu thần chưa rơi xuống đất, bệ hạ đừng lo\" là câu nói của ai thời nhà Trần?", options: ["A. Trần Quốc Tuấn", "B. Trần Thủ Độ", "C. Trần Quang Khải", "D. Trần Khánh Dư"], correctAnswer: "B. Trần Thủ Độ" },
  { id: 106, text: "Vị đại vương nào nổi tiếng với chuyện bè gây sừng trâu?", options: ["A. Lý Nam Đế", "B. Triệu Quang Phục", "C. Phùng Hưng", "D. Mai Thúc Loan"], correctAnswer: "C. Phùng Hưng" },
  { id: 107, text: "Nữ tướng triều Trưng lừng danh ở miền Châu Diên, tên là gì?", options: ["A. Trưng Trắc", "B. Trưng Nhị", "C. Lê Chân", "D. Bùi Thị Xuân"], correctAnswer: "C. Lê Chân" },
  { id: 108, text: "Vị danh nhân nào nổi tiếng quản lý đất đai ven biển thời Nguyễn, còn gọi là Dinh điền sứ?", options: ["A. Nguyễn Du", "B. Nguyễn Công Trứ", "C. Cao Bá Quát", "D. Phạm Ngũ Lão"], correctAnswer: "B. Nguyễn Công Trứ" },
  { id: 109, text: "Ai là minh quân nhà Lý, từng cho lập Văn Miếu để đề cao Nho giáo?", options: ["A. Lý Thái Tông", "B. Lý Thánh Tông", "C. Lý Nhân Tông", "D. Lý Anh Tông"], correctAnswer: "B. Lý Thánh Tông" },
  { id: 110, text: "Ai đã đổi long bào để cứu vua Lê Thái Tổ?", options: ["A. Lê Lợi", "B. Lê Lai", "C. Nguyễn Trãi", "D. Trần Nguyên Hãn"], correctAnswer: "B. Lê Lai" },
  { id: 111, text: "Hà-Ninh tổng đốc nào tuẫn tiết tại thành khi đối mặt quân Pháp?", options: ["A. Nguyễn Tri Phương", "B. Hoàng Diệu", "C. Trương Định", "D. Phan Đình Phùng"], correctAnswer: "B. Hoàng Diệu" },
  { id: 112, text: "Vị vua đầu triều Tiền Lê, từng lãnh đạo đánh thắng quân Tống năm 981 là ai?", options: ["A. Đinh Tiên Hoàng", "B. Lê Hoàn (Lê Đại Hành)", "C. Lê Long Đĩnh", "D. Lý Công Uẩn"], correctAnswer: "B. Lê Hoàn (Lê Đại Hành)" },
  { id: 113, text: "Vị vua khai sáng nhà Lý, thời còn nhỏ từng nương nhờ cửa chùa, tên là gì?", options: ["A. Lý Thái Tông", "B. Lý Công Uẩn", "C. Lý Nhân Tông", "D. Lý Thường Kiệt"], correctAnswer: "B. Lý Công Uẩn" },
  { id: 114, text: "Danh y lỗi lạc, tác giả \"Hải Thượng y tông tâm lĩnh\" được dân gian tôn quý là ai?", options: ["A. Tuệ Tĩnh", "B. Hải Thượng Lãn Ông (Lê Hữu Trác)", "C. Phạm Công Trứ", "D. Đào Duy Từ"], correctAnswer: "B. Hải Thượng Lãn Ông (Lê Hữu Trác)" },
  { id: 115, text: "Cuộc đại thắng quân Thanh diễn ra vào mùa xuân năm nào?", options: ["A. Mậu Tuất", "B. Kỷ Dậu", "C. Canh Tý", "D. Tân Sửu"], correctAnswer: "B. Kỷ Dậu" },
  { id: 116, text: "Ai là vị vua được rùa thần dâng nỏ giúp xây thành?", options: ["A. Lê Lợi", "B. An Dương Vương", "C. Lý Thái Tổ", "D. Đinh Bộ Lĩnh"], correctAnswer: "B. An Dương Vương" },
  { id: 117, text: "Tướng tài thời Tây Sơn, người đã \"bẻ gậy phò vua\" là ai?", options: ["A. Hoàng Hoa Thám", "B. Quang Trung", "C. Bùi Thị Xuân", "D. Trần Quang Diệu"], correctAnswer: "B. Quang Trung" },
  { id: 118, text: "Danh tướng nào đánh tan quân Thanh, giữ vững giang sơn thời Tây Sơn?", options: ["A. Nguyễn Ánh", "B. Quang Trung", "C. Nguyễn Lữ", "D. Nguyễn Nhạc"], correctAnswer: "B. Quang Trung" },
  { id: 119, text: "Ai được gọi là anh hùng trong đại thắng Đống Đa?", options: ["A. Nguyễn Huệ", "B. Phan Bội Châu", "C. Hoàng Hoa Thám", "D. Phạm Ngũ Lão"], correctAnswer: "A. Nguyễn Huệ" },
  { id: 120, text: "Nữ tướng xuất chúng của phong trào Tây Sơn, tên là gì?", options: ["A. Nguyễn Thị Minh Khai", "B. Bùi Thị Xuân", "C. Đoàn Thị Điểm", "D. Hồ Xuân Hương"], correctAnswer: "B. Bùi Thị Xuân" },
  { id: 121, text: "Vị vua cuối triều Tiền Lê thường nằm khi thiết triều, còn được gọi là Lê Ngọa Triều, là ai?", options: ["A. Lê Long Đĩnh", "B. Lê Đại Hành", "C. Lê Thái Tổ", "D. Lê Thánh Tông"], correctAnswer: "A. Lê Long Đĩnh" },
  { id: 122, text: "Ai từng dâng sớ chém kẻ nịnh thần nhưng không thành, sau đó từ quan?", options: ["A. Nguyễn Trãi", "B. Chu Văn An", "C. Nguyễn Bỉnh Khiêm", "D. Lương Thế Vinh"], correctAnswer: "B. Chu Văn An" },
  { id: 123, text: "Ai là thủ lĩnh khởi nghĩa ở núi Lam, mặc áo nâu, giành độc lập cho dân tộc?", options: ["A. Trần Quốc Tuấn", "B. Lê Lợi", "C. Nguyễn Huệ", "D. Đinh Bộ Lĩnh"], correctAnswer: "B. Lê Lợi" },
  { id: 124, text: "Ở hội nghị Bình Than, ai nắm quả cam bày tỏ quyết tâm diệt giặc?", options: ["A. Trần Hưng Đạo", "B. Trần Quốc Toản", "C. Trần Quang Khải", "D. Trần Thủ Độ"], correctAnswer: "B. Trần Quốc Toản" },
  { id: 125, text: "Tác giả mù lòa nào đã viết truyện thơ \"Lục Vân Tiên\"?", options: ["A. Nguyễn Du", "B. Nguyễn Đình Chiểu", "C. Hồ Xuân Hương", "D. Bà Huyện Thanh Quan"], correctAnswer: "B. Nguyễn Đình Chiểu" },
  { id: 126, text: "Vua nào thời Hậu Lê sáng lập hội thơ Tao Đàn?", options: ["A. Lê Thái Tổ", "B. Lê Thánh Tông", "C. Lê Hiến Tông", "D. Lê Tương Dực"], correctAnswer: "B. Lê Thánh Tông" },
  { id: 127, text: "Vị quan họ Phan nào từng được trao ấn Khâm sai, nổi danh học vấn sâu rộng?", options: ["A. Phan Bội Châu", "B. Phan Huy Chú", "C. Phan Thanh Giản", "D. Phan Châu Trinh"], correctAnswer: "B. Phan Huy Chú" },
  { id: 128, text: "Tướng Nguyên - Mông nào phải chui ống đồng rút chạy về phương Bắc?", options: ["A. Toa Đô", "B. Ô Mã Nhi", "C. Thoát Hoan", "D. Bình Chương A Lý"], correctAnswer: "C. Thoát Hoan" },
  { id: 129, text: "Ai bị lừa vì rắc lông ngỗng, dẫn đến kết cục \"nghe chàng hại cha\"?", options: ["A. Mỵ Nương", "B. Mỵ Châu", "C. Thị Kính", "D. Vương Thuý Kiều"], correctAnswer: "B. Mỵ Châu" },
  { id: 130, text: "Tác giả \"Truyện Kiều\" được mệnh danh là \"Hồng Sơn liệp hộ\" của triều Tây Sơn?", options: ["A. Nguyễn Trãi", "B. Nguyễn Du", "C. Hồ Xuân Hương", "D. Nguyễn Công Trứ"], correctAnswer: "B. Nguyễn Du" },
  { id: 131, text: "Nữ tướng \"Ra trận quấn khăn vàng\" ở bờ Hóa Giang, được dân gian ca tụng, là ai?", options: ["A. Trưng Trắc", "B. Bà Triệu", "C. Bùi Thị Xuân", "D. Lê Chân"], correctAnswer: "B. Bà Triệu" },
  { id: 132, text: "Vị \"Trạng Trình\" từng ẩn cư ở Am Bạch Vân, không màng danh lợi là ai?", options: ["A. Nguyễn Trãi", "B. Nguyễn Bỉnh Khiêm", "C. Lê Quý Đôn", "D. Lương Thế Vinh"], correctAnswer: "B. Nguyễn Bỉnh Khiêm" },
  { id: 133, text: "Vị vua dựng nước Âu Lạc, được cho là cháu Đế Minh, là ai?", options: ["A. Kinh Dương Vương", "B. Hùng Vương", "C. An Dương Vương", "D. Lạc Long Quân"], correctAnswer: "C. An Dương Vương" },
  { id: 134, text: "\"Vua Bà\" lừng lẫy, khởi nghĩa ở vùng núi Nưa, khiến quân Ngô kinh sợ, tên là gì?", options: ["A. Trưng Trắc", "B. Bà Triệu", "C. Lê Chân", "D. Bùi Thị Xuân"], correctAnswer: "B. Bà Triệu" },
  { id: 135, text: "Ai là vị quan thời chúa Nguyễn, nổi tiếng xây dựng thành lũy, họ Đào?", options: ["A. Nguyễn Hữu Cảnh", "B. Đào Duy Từ", "C. Mạc Thiên Tích", "D. Trần Thượng Xuyên"], correctAnswer: "B. Đào Duy Từ" },
  { id: 136, text: "Thi nhân \"sông Vị\" nổi bật về tài văn chương?", options: ["A. Nguyễn Khuyến", "B. Tú Xương", "C. Nguyễn Đình Chiểu", "D. Cao Bá Quát"], correctAnswer: "B. Tú Xương" },
  { id: 137, text: "Hoàng đế khai sáng nhà Nguyễn có húy danh là gì?", options: ["A. Nguyễn Phúc Ánh", "B. Nguyễn Ánh (có bản ghi Nguyễn Ýnh)", "C. Nguyễn Huệ", "D. Nguyễn Nhạc"], correctAnswer: "B. Nguyễn Ánh (có bản ghi Nguyễn Ýnh)" },
  { id: 138, text: "Mẹ nào sinh ra trăm trứng, nở thành trăm người con của dân tộc Việt?", options: ["A. Nữ Oa", "B. Mẹ Âu Cơ", "C. Bà Triệu", "D. Lê Chân"], correctAnswer: "B. Mẹ Âu Cơ" },
  { id: 139, text: "Ai là vị vua Tây Sơn từng cưới công chúa Lê Ngọc Hân?", options: ["A. Nguyễn Nhạc", "B. Nguyễn Lữ", "C. Quang Trung", "D. Cảnh Thịnh"], correctAnswer: "C. Quang Trung" },
  { id: 140, text: "Chuyện \"Bóp nát quả cam\" là giai thoại nói về ai?", options: ["A. Trần Hưng Đạo", "B. Trần Quốc Toản", "C. Trần Khắc Chung", "D. Trần Quang Khải"], correctAnswer: "B. Trần Quốc Toản" },
  { id: 141, text: "Vị nữ tướng nào \"giữ trọn lời thề\" ở sông Hóa, khởi nghĩa năm 248?", options: ["A. Trưng Trắc", "B. Bà Triệu", "C. Bùi Thị Xuân", "D. Lê Chân"], correctAnswer: "B. Bà Triệu" },
  { id: 142, text: "\"Tú tài\" nổi danh ở vùng Đại Từ, được dân địa phương xưng tụng, tên là gì?", options: ["A. Tú Xương", "B. Tú Xuất", "C. Nguyễn Khuyến", "D. Cao Bá Quát"], correctAnswer: "B. Tú Xuất" },
  { id: 143, text: "Nhà thơ họ Cao, nổi tiếng vì tâm hồn phản kháng mạnh mẽ, là ai?", options: ["A. Nguyễn Du", "B. Cao Bá Quát", "C. Nguyễn Đình Chiểu", "D. Hồ Xuân Hương"], correctAnswer: "B. Cao Bá Quát" },
  { id: 144, text: "Ai là tác giả \"Hịch tướng sĩ\", kêu gọi toàn quân đoàn kết chống giặc Nguyên-Mông?", options: ["A. Trần Quang Khải", "B. Trần Hưng Đạo (Trần Quốc Tuấn)", "C. Phạm Ngũ Lão", "D. Yết Kiêu"], correctAnswer: "B. Trần Hưng Đạo (Trần Quốc Tuấn)" },
  { id: 145, text: "\"Chinh phụ ngâm\" phiên bản chữ Hán được dịch ra chữ Nôm bởi nữ sĩ nào?", options: ["A. Hồ Xuân Hương", "B. Đoàn Thị Điểm", "C. Bà Huyện Thanh Quan", "D. Sương Nguyệt Anh"], correctAnswer: "B. Đoàn Thị Điểm" },
  { id: 146, text: "Vị vua triều Nguyễn chống Pháp, bị đày ra châu Phi, là ai?", options: ["A. Thành Thái", "B. Hàm Nghi", "C. Duy Tân", "D. Khải Định"], correctAnswer: "B. Hàm Nghi" },
  { id: 147, text: "Ai là người chủ xướng phong trào Đông Du, đưa thanh niên sang Nhật du học?", options: ["A. Phan Châu Trinh", "B. Phan Bội Châu", "C. Nguyễn Thái Học", "D. Huỳnh Thúc Kháng"], correctAnswer: "B. Phan Bội Châu" },
  { id: 148, text: "Ai lãnh đạo trận Rạch Gầm-Xoài Mút thắng lớn, khiến quân Xiêm thảm bại?", options: ["A. Nguyễn Ánh", "B. Nguyễn Huệ", "C. Nguyễn Nhạc", "D. Lý Thường Kiệt"], correctAnswer: "B. Nguyễn Huệ" },
  { id: 149, text: "Vị anh hùng \"cưỡi ngựa sắt phun lửa\" giải cứu đất nước khi mới ba tuổi là ai?", options: ["A. Sơn Tinh", "B. Thánh Gióng", "C. Phù Đổng Thiên Vương", "D. Mai An Tiêm"], correctAnswer: "B. Thánh Gióng" },  { id: 150, text: "Danh xưng \"Dạ Trạch Vương\" thuộc về ai, người lập căn cứ ở Đầm Dạ Trạch?", options: ["A. Mai Hắc Đế", "B. Dạ Trạch Vương - Triệu Quang Phục", "C. Phùng Hưng", "D. Đinh Bộ Lĩnh"], correctAnswer: "B. Dạ Trạch Vương - Triệu Quang Phục" },
  { id: 151, text: "Tướng nào khảng khái tuyên bố \"Ta thà làm quý nước Nam...\" và không nhận tước vương của giặc?", options: ["A. Trần Quang Khải", "B. Trần Bình Trọng", "C. Phạm Ngũ Lão", "D. Trần Quốc Tuấn"], correctAnswer: "B. Trần Bình Trọng" },
  { id: 152, text: "Vị thiếu niên cầm đầu đám trẻ chăn trâu, tập trận bằng cờ lau, rồi thống nhất đất nước?", options: ["A. Lê Lợi", "B. Đinh Bộ Lĩnh", "C. Nguyễn Huệ", "D. Trần Quốc Toản"], correctAnswer: "B. Đinh Bộ Lĩnh" },
  { id: 153, text: "Ai gắn liền với tích \"người chài đò\" và nàng Mỵ Nương, tạo nên câu chuyện tương tư cảm động?", options: ["A. Trọng Thủy - Mỵ Châu", "B. Trương Chỉ - Mỵ Nương", "C. Kim Trọng - Thúy Kiều", "D. Lương Sơn Bá - Chúc Anh Đài"], correctAnswer: "B. Trương Chỉ - Mỵ Nương" },
  { id: 154, text: "Vị vua Lê nào còn được tôn là \"Nguyên súy hội Tao Đàn\"?", options: ["A. Lê Thái Tổ", "B. Lê Thánh Tông", "C. Lê Hiến Tông", "D. Lê Chiêu Thống"], correctAnswer: "B. Lê Thánh Tông" },
  { id: 155, text: "Ngày mùng mấy tháng ba hằng năm diễn ra lễ hội Đền Hùng?", options: ["A. Mùng 5 tháng 3", "B. 10-3", "C. 15 tháng 3", "D. Mùng 1 tháng 4"], correctAnswer: "B. 10-3" },
  { id: 156, text: "Vị vua trẻ của phong trào Cần Vương, sau bị Pháp đày đi châu Phi, là ai?", options: ["A. Hàm Nghi", "B. Duy Tân", "C. Thành Thái", "D. Khải Định"], correctAnswer: "B. Duy Tân" },
  { id: 157, text: "Cha rồng kết duyên cùng Mẹ Âu Cơ, sinh ra dòng giống Lạc Hồng, là ai?", options: ["A. Thần Nông", "B. Lạc Long Quân", "C. Kinh Dương Vương", "D. Hùng Vương"], correctAnswer: "B. Lạc Long Quân" },
  { id: 158, text: "Ai mượn gươm thần rồi hoàn kiếm lại cho rùa vàng ở hồ Tả Vọng?", options: ["A. Lê Lai", "B. Lê Lợi", "C. Nguyễn Trãi", "D. Trần Nguyên Hãn"], correctAnswer: "B. Lê Lợi" },
  { id: 159, text: "Vị nữ tướng nào khóc trên lưng voi khi đánh quân Ngô, ở vùng Hóa Giang?", options: ["A. Trưng Nhị", "B. Bà Triệu", "C. Bùi Thị Xuân", "D. Lê Chân"], correctAnswer: "B. Bà Triệu" },
  { id: 160, text: "Ai đã xây dựng Lũy Thầy trứ danh thời chúa Nguyễn?", options: ["A. Đào Tấn", "B. Đào Duy Từ", "C. Nguyễn Công Trứ", "D. Nguyễn Hữu Cảnh"], correctAnswer: "B. Đào Duy Từ" },
  { id: 161, text: "Người chế tạo súng và nổi dậy chống Pháp ở Vũ Quang đầu thế kỷ XX là ai?", options: ["A. Phan Đình Phùng", "B. Cao Thắng", "C. Hoàng Hoa Thám", "D. Nguyễn Thiện Thuật"], correctAnswer: "B. Cao Thắng" },
  { id: 162, text: "Vị danh thần triều Nguyễn, cũng được xem như tổ ngành Hát Bội, là ai?", options: ["A. Nguyễn Du", "B. Đào Duy Từ", "C. Nguyễn Công Trứ", "D. Mạc Đĩnh Chi"], correctAnswer: "B. Đào Duy Từ" },
  { id: 163, text: "Ngọn núi nào gắn liền với truyền thuyết Sơn Tinh Thủy Tinh?", options: ["A. Núi Ba Vì", "B. Tản Viên", "C. Núi Nưa", "D. Núi Lam Sơn"], correctAnswer: "B. Tản Viên" },
  { id: 164, text: "\"Trạng Trình\" nhận bức thư trao đổi từ một danh nho, đó là ai?", options: ["A. Nguyễn Du", "B. Nguyễn Bỉnh Khiêm", "C. Chu Văn An", "D. Lê Quý Đôn"], correctAnswer: "B. Nguyễn Bỉnh Khiêm" },
  { id: 165, text: "Ai là người soạn thảo \"Bình Ngô đại cáo\", áng văn bất hủ khẳng định chủ quyền nước ta?", options: ["A. Lê Lợi", "B. Nguyễn Trãi", "C. Trần Nguyên Hãn", "D. Nguyễn Xí"], correctAnswer: "B. Nguyễn Trãi" },
  { id: 166, text: "Nhà toán học được tôn là \"Trạng Lường\" và sáng tác \"Đại Thành Toán Pháp\" là ai?", options: ["A. Lê Quý Đôn", "B. Lương Thế Vinh", "C. Nguyễn Trường Tộ", "D. Phạm Quang Ảnh"], correctAnswer: "B. Lương Thế Vinh" },
  { id: 167, text: "Vị danh thần nào nghe theo di huấn của cha, tạm rời biên ải để giành thắng lợi toàn cục?", options: ["A. Trần Hưng Đạo", "B. Nguyễn Trãi", "C. Phạm Ngũ Lão", "D. Lê Lai"], correctAnswer: "B. Nguyễn Trãi" },
  { id: 168, text: "Ai là người khởi xướng cuộc nổi dậy ở Thái Nguyên chống Pháp?", options: ["A. Lương Ngọc Quyến", "B. Đội Cấn - Đội Cung", "C. Hoàng Hoa Thám", "D. Nguyễn Thái Học"], correctAnswer: "B. Đội Cấn - Đội Cung" },
  { id: 169, text: "Cao tăng nổi tiếng dưới triều Lý, người tham vấn cho Lý Công Uẩn, tên gì?", options: ["A. Khổng Minh Không", "B. Sư Vạn Hạnh", "C. Pháp Loa", "D. Điều Ngự Giác Hoàng"], correctAnswer: "B. Sư Vạn Hạnh" },
  { id: 170, text: "\"Đồng bào\" được bắt nguồn từ truyền thuyết mẹ đẻ bọc trăm trứng, đó là câu chuyện về ai?", options: ["A. Sơn Tinh Thủy Tinh", "B. Mẹ Âu Cơ đẻ ra bọc trăm trứng", "C. Thánh Gióng", "D. Mai An Tiêm"], correctAnswer: "B. Mẹ Âu Cơ đẻ ra bọc trăm trứng" },
  { id: 171, text: "Vua triều Lê nào nổi tiếng bạo ngược, giết hại công thần, còn được gọi là \"Vua quỷ\"?", options: ["A. Lê Chiêu Thống", "B. Lê Uy Mục", "C. Lê Tương Dực", "D. Lê Nghi Dân"], correctAnswer: "B. Lê Uy Mục" },
  { id: 172, text: "Người dùng kế sách \"công bút\" đánh lừa tướng Minh Vương Thông là ai?", options: ["A. Lê Lợi", "B. Nguyễn Trãi", "C. Trần Nguyên Hãn", "D. Lê Sát"], correctAnswer: "B. Nguyễn Trãi" },
  { id: 173, text: "Ai gây dựng cơ đồ ở vùng Mê Linh, phất cờ khởi nghĩa đánh đuổi Tô Định?", options: ["A. Bà Triệu", "B. Hai Bà Trưng", "C. Bùi Thị Xuân", "D. Lê Chân"], correctAnswer: "B. Hai Bà Trưng" },
  { id: 174, text: "Ai bôn ba nhiều nơi để thực hiện phong trào Đông Du đầu thế kỷ XX?", options: ["A. Phan Châu Trinh", "B. Phan Bội Châu", "C. Lương Văn Can", "D. Nguyễn Thái Học"], correctAnswer: "B. Phan Bội Châu" },
  { id: 175, text: "Tác phẩm \"Hoàng Lê nhất thống chí\", ghi lại biến động cuối Lê - Tây Sơn, do tập thể nào chắp bút?", options: ["A. Ngô Thì Nhậm", "B. Ngô Gia Văn Phái", "C. Nguyễn Du", "D. Phan Huy Chú"], correctAnswer: "B. Ngô Gia Văn Phái" },
  { id: 176, text: "Nhà thơ nào vì dính vào cuộc nổi loạn nên bị hành hình, gắn liền với câu \"tài hoa yểu mệnh\"?", options: ["A. Nguyễn Khuyến", "B. Cao Bá Quát", "C. Nguyễn Du", "D. Tú Xương"], correctAnswer: "B. Cao Bá Quát" },
  { id: 177, text: "Bác Hồ đọc bản Tuyên ngôn Độc lập vào năm nào?", options: ["A. 2/9/1930", "B. 2/9/1945", "C. 2/9/1954", "D. 2/9/1975"], correctAnswer: "B. 2/9/1945" },
  { id: 178, text: "Vua mở đầu triều Trần, sau khi nhà Lý suy vi, là ai?", options: ["A. Trần Thủ Độ", "B. Trần Cảnh", "C. Trần Thái Tông", "D. Trần Quốc Tuấn"], correctAnswer: "B. Trần Cảnh" },
  { id: 179, text: "Trạng nguyên vì dung mạo xấu xí của mình như hoa sen \"gần bùn mà chẳng hôi tanh\"?", options: ["A. Nguyễn Hiền", "B. Mạc Đĩnh Chi", "C. Nguyễn Bỉnh Khiêm", "D. Lương Thế Vinh"], correctAnswer: "B. Mạc Đĩnh Chi" },
  { id: 180, text: "Vị tướng dưới triều Nguyễn, được thờ tại lăng Ông ở Sài Gòn là ai?", options: ["A. Nguyễn Tri Phương", "B. Lê Văn Duyệt", "C. Trương Định", "D. Nguyễn Huỳnh Đức"], correctAnswer: "B. Lê Văn Duyệt" },
  { id: 181, text: "\"Hùm thiêng Yên Thế\" chuyên kháng Pháp, khiến giặc nhiều lần thất bại, tên là gì?", options: ["A. Đinh Công Tráng", "B. Hoàng Hoa Thám", "C. Nguyễn Thiện Thuật", "D. Phan Đình Phùng"], correctAnswer: "B. Hoàng Hoa Thám" },
  { id: 182, text: "Các chức \"Lạc Hầu\", \"Lạc Tướng\" tồn tại vào thời nào?", options: ["A. Trưng Vương", "B. Hùng Vương", "C. An Dương Vương", "D. Hai Bà Trưng"], correctAnswer: "B. Hùng Vương" },
  { id: 183, text: "Ai từng làm vua giữa chốn đồng lầy và ai dùng cờ lau tập trận lúc nhỏ?", options: ["A. Lê Lợi và Trần Quốc Toản", "B. Đinh Bộ Lĩnh và Triệu Quang Phục", "C. Lý Công Uẩn và Nguyễn Huệ", "D. Mai Hắc Đế và Phùng Hưng"], correctAnswer: "B. Đinh Bộ Lĩnh và Triệu Quang Phục" },
  { id: 184, text: "Ai gác phú nhà để lo việc nước và ai là người thắng trận Đống Đa lừng lẫy?", options: ["A. Lê Lợi và Nguyễn Huệ", "B. Trần Quốc Tuấn và Quang Trung", "C. Nguyễn Trãi và Trần Hưng Đạo", "D. Phạm Ngũ Lão và Bùi Thị Xuân"], correctAnswer: "B. Trần Quốc Tuấn và Quang Trung" },
  { id: 185, text: "Ai ba tuổi không nói cười, nghe tin nước có giặc liền vùng dậy đánh tan quân xâm lược?", options: ["A. An Dương Vương", "B. Thánh Gióng", "C. Đinh Bộ Lĩnh", "D. Mai An Tiêm"], correctAnswer: "B. Thánh Gióng" },
  { id: 186, text: "Ngày, tháng, năm nào Bác Hồ gửi bức thư cuối cùng cho ngành giáo dục?", options: ["A. 20/11/1967", "B. 15/10/1968", "C. 2/9/1969", "D. 19/5/1969"], correctAnswer: "B. 15/10/1968" },
  { id: 187, text: "\"Bà nữ tướng\" cầm cờ khởi nghĩa, cưỡi voi một ngà, vang danh chống quân Ngô là ai?", options: ["A. Trưng Trắc", "B. Bà Triệu", "C. Bùi Thị Xuân", "D. Lê Chân"], correctAnswer: "B. Bà Triệu" },
  { id: 188, text: "Sự tích bánh chưng, bánh dày thuộc đời Vua Hùng thứ mấy?", options: ["A. Vua Hùng Vương thứ 3", "B. Vua Hùng Vương thứ 6", "C. Vua Hùng Vương thứ 10", "D. Vua Hùng Vương thứ 18"], correctAnswer: "B. Vua Hùng Vương thứ 6" },
  { id: 189, text: "Vị chủ tướng nào kiên gan kháng chiến suốt mười năm, đánh bại Vương Thông ở Đông Quan?", options: ["A. Nguyễn Trãi", "B. Lê Lợi", "C. Trần Nguyên Hãn", "D. Lê Sát"], correctAnswer: "B. Lê Lợi" },
  { id: 190, text: "Ai là người khởi xướng Đông Du, và ai từng \"đập đá\" ở Côn Lôn thể hiện chí sĩ yêu nước?", options: ["A. Nguyễn Thái Học và Nguyễn An Ninh", "B. Phan Bội Châu và Phan Châu Trinh", "C. Huỳnh Thúc Kháng và Ngô Đình Diệm", "D. Trần Phú và Hà Huy Tập"], correctAnswer: "B. Phan Bội Châu và Phan Châu Trinh" },
  { id: 191, text: "Trước khi ra đi tìm đường cứu nước, Bác Hồ từng dạy học ở đâu?", options: ["A. Huế", "B. Phan Thiết", "C. Vinh", "D. Sài Gòn"], correctAnswer: "B. Phan Thiết" },
  { id: 192, text: "Ai là thủ lĩnh Việt Nam Quốc Dân Đảng, lãnh đạo khởi nghĩa Yên Bái, nêu câu nói \"Không thành công...\"?", options: ["A. Nguyễn An Ninh", "B. Nguyễn Thái Học", "C. Hoàng Hoa Thám", "D. Phạm Hồng Thái"], correctAnswer: "B. Nguyễn Thái Học" },
  { id: 193, text: "Tướng triều Nguyễn nào bảo vệ Đà Nẵng, Gia Định, khiến quân Pháp nhiều phen lao đao?", options: ["A. Trương Định", "B. Nguyễn Tri Phương", "C. Hoàng Diệu", "D. Lê Văn Duyệt"], correctAnswer: "B. Nguyễn Tri Phương" },
  { id: 194, text: "Nhà thơ Nguyễn Đình Chiểu sinh ra và lớn lên tại địa phương nào?", options: ["A. Đồng Tháp", "B. Bến Tre", "C. Long An", "D. Tiền Giang"], correctAnswer: "B. Bến Tre" },
  { id: 195, text: "Năm đầu tiên Việt Nam tổ chức kỷ niệm Ngày Nhà giáo (20/11) là năm nào?", options: ["A. 20-11-1975", "B. 20-11-1958", "C. 20-11-1982", "D. 20-11-1945"], correctAnswer: "B. 20-11-1958" },
  { id: 196, text: "Vào ngày 13/12 hằng năm, chúng ta tưởng nhớ người thầy giáo nào?", options: ["A. Nguyễn Tất Thành", "B. Phan Ngọc Hiển", "C. Trần Đại Nghĩa", "D. Nguyễn Bỉnh Khiêm"], correctAnswer: "B. Phan Ngọc Hiển" },
  { id: 197, text: "Danh tướng nhà Trần nào ngồi đan sọt, bị giáo đâm vào đùi mà không hay biết?", options: ["A. Trần Quốc Tuấn", "B. Phạm Ngũ Lão", "C. Trần Quang Khải", "D. Trần Khánh Dư"], correctAnswer: "B. Phạm Ngũ Lão" },
  { id: 198, text: "Vị tướng bơi lặn giỏi, dùng kế khoan thùng thuyền địch bảo vệ sông Bạch Đằng là ai?", options: ["A. Dã Tượng", "B. Yết Kiêu", "C. Trần Quốc Tuấn", "D. Phạm Ngũ Lão"], correctAnswer: "B. Yết Kiêu" },
  { id: 199, text: "Ai từng đánh tan quân Đường, được tôn xưng Bố Cái Đại Vương?", options: ["A. Mai Hắc Đế", "B. Phùng Hưng", "C. Ngô Quyền", "D. Dương Đình Nghệ"], correctAnswer: "B. Phùng Hưng" },  { id: 200, text: "Ai dâng bánh chưng bánh dày mừng thọ vua cha, lập nên phong tục truyền thống ngày Tết?", options: ["A. Tiết Liêu", "B. Lang Liêu", "C. Sơn Tinh", "D. Thủy Tinh"], correctAnswer: "B. Lang Liêu" },
  { id: 201, text: "Định danh điện tử là gì?", options: ["A. Là một loại chứng minh nhân dân vật lý", "B. Là danh tính của công dân trên môi trường số", "C. Là chữ ký tay được scan", "D. Là mật khẩu tài khoản ngân hàng"], correctAnswer: "B. Là danh tính của công dân trên môi trường số" },
  { id: 202, text: "Ứng dụng nào của Việt Nam hỗ trợ định danh điện tử?", options: ["A. Zalo", "B. Facebook", "C. VNeID", "D. TikTok"], correctAnswer: "C. VNeID" },
  { id: 203, text: "Định danh điện tử mức 1 có những thông tin gì?", options: ["A. Chỉ số CCCD và họ tên", "B. Số CCCD, họ tên, ngày sinh, giới tính", "C. Thông tin sinh trắc học", "D. Tất cả thông tin trên giấy tờ tùy thân"], correctAnswer: "B. Số CCCD, họ tên, ngày sinh, giới tính" },
  { id: 204, text: "Định danh điện tử mức 2 bao gồm những thông tin gì?", options: ["A. Chỉ số CCCD và họ tên", "B. Thông tin cơ bản và ảnh chân dung, vân tay", "C. Chỉ thông tin về sức khỏe", "D. Thông tin tài khoản ngân hàng"], correctAnswer: "B. Thông tin cơ bản và ảnh chân dung, vân tay" },
  { id: 205, text: "Lợi ích của việc sử dụng định danh điện tử VNeID là gì?", options: ["A. Thay thế giấy tờ tùy thân khi giao dịch hành chính", "B. Thanh toán các dịch vụ công", "C. Kê khai thuế trực tuyến", "D. Tất cả các lợi ích trên"], correctAnswer: "D. Tất cả các lợi ích trên" },
  { id: 206, text: "Hành chính công trực tuyến là gì?", options: ["A. Làm thủ tục hành chính tại trụ sở cơ quan nhà nước", "B. Làm thủ tục hành chính qua điện thoại", "C. Làm thủ tục hành chính qua môi trường mạng Internet", "D. Làm thủ tục hành chính qua bưu điện"], correctAnswer: "C. Làm thủ tục hành chính qua môi trường mạng Internet" },
  { id: 207, text: "Cổng Dịch vụ công Quốc gia có địa chỉ truy cập là gì?", options: ["A. dichvucong.gov.vn", "B. chinhphu.vn", "C. vneid.gov.vn", "D. moj.gov.vn"], correctAnswer: "A. dichvucong.gov.vn" },
  { id: 208, text: "Khi sử dụng dịch vụ công trực tuyến, người dân có thể thực hiện điều gì?", options: ["A. Nộp hồ sơ trực tuyến", "B. Theo dõi tình trạng giải quyết hồ sơ", "C. Nhận kết quả trực tuyến hoặc qua bưu điện", "D. Tất cả các việc trên"], correctAnswer: "D. Tất cả các việc trên" },
  { id: 209, text: "Để nộp hồ sơ trực tuyến trên Cổng Dịch vụ công Quốc gia, người dân cần có tài khoản gì?", options: ["A. Tài khoản Facebook", "B. Tài khoản Google", "C. Tài khoản Cổng Dịch vụ công Quốc gia hoặc VNeID", "D. Tài khoản ngân hàng"], correctAnswer: "C. Tài khoản Cổng Dịch vụ công Quốc gia hoặc VNeID" },
  { id: 210, text: "Thành phần hồ sơ khi nộp trực tuyến có cần công chứng không?", options: ["A. Luôn luôn cần công chứng", "B. Tùy thuộc vào từng thủ tục và quy định", "C. Không bao giờ cần công chứng", "D. Chỉ cần chụp ảnh mờ"], correctAnswer: "B. Tùy thuộc vào từng thủ tục và quy định" },
  { id: 211, text: "Thanh toán trực tuyến phí, lệ phí giải quyết thủ tục hành chính được thực hiện qua đâu?", options: ["A. Chỉ bằng tiền mặt", "B. Qua các cổng thanh toán trực tuyến được tích hợp", "C. Chỉ qua chuyển khoản ngân hàng", "D. Qua bưu điện"], correctAnswer: "B. Qua các cổng thanh toán trực tuyến được tích hợp" },
  { id: 212, text: "Khi gặp khó khăn khi thực hiện thủ tục hành chính trực tuyến, người dân có thể tìm hỗ trợ ở đâu?", options: ["A. Hỏi người thân", "B. Liên hệ tổng đài hỗ trợ hoặc bộ phận một cửa điện tử của cơ quan", "C. Tự tìm hiểu trên mạng", "D. Bỏ qua không làm nữa"], correctAnswer: "B. Liên hệ tổng đài hỗ trợ hoặc bộ phận một cửa điện tử của cơ quan" },
  { id: 213, text: "Việc sử dụng định danh điện tử và hành chính công trực tuyến góp phần vào mục tiêu nào của Chính phủ Việt Nam?", options: ["A. Chỉ để giảm giấy tờ", "B. Xây dựng Chính phủ số, nền kinh tế số, xã hội số", "C. Tăng cường sử dụng tiền mặt", "D. Giảm tương tác giữa người dân và cơ quan nhà nước"], correctAnswer: "B. Xây dựng Chính phủ số, nền kinh tế số, xã hội số" },
  { id: 214, text: "Độ bảo mật của định danh điện tử VNeID được đảm bảo như thế nào?", options: ["A. Không được bảo mật", "B. Được bảo vệ bởi hệ thống công nghệ thông tin hiện đại", "C. Chỉ cần mật khẩu đơn giản", "D. Chia sẻ thông tin cho người lạ"], correctAnswer: "B. Được bảo vệ bởi hệ thống công nghệ thông tin hiện đại" },
  { id: 215, text: "Khi mất điện thoại có cài VNeID, cần làm gì ngay lập tức?", options: ["A. Không làm gì cả", "B. Liên hệ cơ quan công an hoặc khóa tài khoản VNeID", "C. Mua điện thoại mới", "D. Đăng nhập trên thiết bị khác"], correctAnswer: "B. Liên hệ cơ quan công an hoặc khóa tài khoản VNeID" },
  { id: 216, text: "Cá nhân có bắt buộc phải đăng ký tài khoản định danh điện tử không?", options: ["A. Bắt buộc với tất cả mọi người", "B. Không bắt buộc, tùy nhu cầu sử dụng", "C. Chỉ bắt buộc với cán bộ công chức", "D. Chỉ bắt buộc với người kinh doanh"], correctAnswer: "B. Không bắt buộc, tùy nhu cầu sử dụng" },
  { id: 217, text: "Đăng ký tài khoản định danh điện tử mức 1 được thực hiện ở đâu?", options: ["A. Tại nhà", "B. Qua ứng dụng VNeID trên điện thoại", "C. Tại trụ sở công an xã, phường, thị trấn", "D. Tại ngân hàng"], correctAnswer: "B. Qua ứng dụng VNeID trên điện thoại" },
  { id: 218, text: "Đăng ký tài khoản định danh điện tử mức 2 được thực hiện ở đâu?", options: ["A. Tại nhà", "B. Qua ứng dụng VNeID trên điện thoại", "C. Tại trụ sở công an xã, phường, thị trấn", "D. Tại bưu điện"], correctAnswer: "C. Tại trụ sở công an xã, phường, thị trấn" },
  { id: 219, text: "Khi sử dụng VNeID, các thông tin cá nhân có được chia sẻ công khai không?", options: ["A. Được chia sẻ công khai cho mọi người", "B. Không được chia sẻ công khai, chỉ sử dụng để xác minh danh tính khi cần thiết", "C. Chia sẻ tùy ý người dùng", "D. Chỉ chia sẻ trên mạng xã hội"], correctAnswer: "B. Không được chia sẻ công khai, chỉ sử dụng để xác minh danh tính khi cần thiết" },
  { id: 220, text: "Việc tích hợp các giấy tờ vào VNeID mang lại lợi ích gì?", options: ["A. Giảm số lượng giấy tờ cần mang theo", "B. Thuận tiện khi thực hiện các giao dịch", "C. Tiết kiệm thời gian và chi phí", "D. Tất cả các lợi ích trên"], correctAnswer: "D. Tất cả các lợi ích trên" },
  { id: 221, text: "Cổng Dịch vụ công Quốc gia cung cấp dịch vụ công cho đối tượng nào?", options: ["A. Chỉ cho cán bộ nhà nước", "B. Chỉ cho doanh nghiệp", "C. Cho cả cá nhân và doanh nghiệp", "D. Chỉ cho người nước ngoài"], correctAnswer: "C. Cho cả cá nhân và doanh nghiệp" },
  { id: 222, text: "Thủ tục hành chính trực tuyến mức độ 3 là gì?", options: ["A. Chỉ cho phép nộp hồ sơ trực tuyến", "B. Cho phép nộp hồ sơ trực tuyến và thanh toán trực tuyến", "C. Cho phép nộp hồ sơ trực tuyến, thanh toán trực tuyến và nhận kết quả trực tuyến", "D. Chỉ cung cấp thông tin về thủ tục"], correctAnswer: "B. Cho phép nộp hồ sơ trực tuyến và thanh toán trực tuyến" },
  { id: 223, text: "Thủ tục hành chính trực tuyến mức độ 4 là gì?", options: ["A. Chỉ cho phép nộp hồ sơ trực tuyến", "B. Cho phép nộp hồ sơ trực tuyến và thanh toán trực tuyến", "C. Cho phép nộp hồ sơ trực tuyến, thanh toán trực tuyến và nhận kết quả trực tuyến hoặc qua bưu điện", "D. Chỉ cung cấp thông tin về thủ tục"], correctAnswer: "C. Cho phép nộp hồ sơ trực tuyến, thanh toán trực tuyến và nhận kết quả trực tuyến hoặc qua bưu điện" },
  { id: 224, text: "Chữ ký số có thể được sử dụng trong các giao dịch hành chính công trực tuyến không?", options: ["A. Không thể sử dụng", "B. Có thể sử dụng để ký các văn bản điện tử", "C. Chỉ dùng để ký email", "D. Chỉ dùng để ký hình ảnh"], correctAnswer: "B. Có thể sử dụng để ký các văn bản điện tử" },
  { id: 225, text: "Khi nộp hồ sơ trực tuyến, cần chú ý điều gì về định dạng tệp đính kèm?", options: ["A. Định dạng nào cũng được", "B. Cần tuân thủ các định dạng được quy định trên Cổng Dịch vụ công", "C. Chỉ chấp nhận file ảnh", "D. Chỉ chấp nhận file nén"], correctAnswer: "B. Cần tuân thủ các định dạng được quy định trên Cổng Dịch vụ công" },
  { id: 226, text: "Việc khai thác thông tin từ Cơ sở dữ liệu quốc gia về dân cư thông qua VNeID giúp ích gì?", options: ["A. Tra cứu thông tin cá nhân", "B. Giảm yêu cầu xuất trình giấy tờ nhiều lần", "C. Đảm bảo tính chính xác của thông tin", "D. Tất cả các lợi ích trên"], correctAnswer: "D. Tất cả các lợi ích trên" },
  { id: 227, text: "Ứng dụng VNeID có thể hiển thị những thông tin nào đã được tích hợp?", options: ["A. Thông tin thẻ BHYT", "B. Thông tin giấy phép lái xe", "C. Thông tin đăng ký xe", "D. Tất cả các thông tin trên (nếu đã tích hợp thành công)"], correctAnswer: "D. Tất cả các thông tin trên (nếu đã tích hợp thành công)" },
  { id: 228, text: "Khi quên mật khẩu đăng nhập Cổng Dịch vụ công Quốc gia, cần làm gì?", options: ["A. Tạo tài khoản mới", "B. Sử dụng chức năng quên mật khẩu và làm theo hướng dẫn", "C. Đến cơ quan nhà nước để lấy lại", "D. Nhờ người khác đăng nhập hộ"], correctAnswer: "B. Sử dụng chức năng quên mật khẩu và làm theo hướng dẫn" },
  { id: 229, text: "Hệ thống thông tin giải quyết thủ tục hành chính cấp bộ, cấp tỉnh được gọi chung là gì?", options: ["A. Cổng thông tin điện tử", "B. Hệ thống một cửa điện tử", "C. Cổng Dịch vụ công", "D. Hệ thống quản lý văn bản"], correctAnswer: "B. Hệ thống một cửa điện tử" },
  { id: 230, text: "Lợi ích của việc theo dõi tình trạng hồ sơ trực tuyến là gì?", options: ["A. Biết được tiến độ giải quyết hồ sơ", "B. Chủ động về thời gian nhận kết quả", "C. Không cần đến trực tiếp cơ quan", "D. Tất cả các lợi ích trên"], correctAnswer: "D. Tất cả các lợi ích trên" },
  { id: 231, text: "Việc cung cấp dịch vụ công trực tuyến giúp cơ quan nhà nước điều gì?", options: ["A. Giảm tải công việc giấy tờ", "B. Tăng tính công khai, minh bạch", "C. Phục vụ người dân tốt hơn", "D. Tất cả các điều trên"], correctAnswer: "D. Tất cả các điều trên" },
  { id: 232, text: "Khi nhận được thông báo giả mạo về hồ sơ dịch vụ công trực tuyến, cần làm gì?", options: ["A. Làm theo hướng dẫn trong thông báo", "B. Cung cấp thông tin cá nhân theo yêu cầu", "C. Kiểm tra thông tin trên Cổng Dịch vụ công chính thức hoặc liên hệ cơ quan", "D. Bỏ qua không làm gì"], correctAnswer: "C. Kiểm tra thông tin trên Cổng Dịch vụ công chính thức hoặc liên hệ cơ quan" },
  { id: 233, text: "Định danh điện tử VNeID có giá trị sử dụng ở đâu?", options: ["A. Chỉ trong tỉnh/thành phố đăng ký", "B. Trên toàn quốc và thay thế các giấy tờ đã tích hợp", "C. Chỉ khi đi du lịch", "D. Chỉ dùng để đăng nhập website"], correctAnswer: "B. Trên toàn quốc và thay thế các giấy tờ đã tích hợp" },
  { id: 234, text: "Làm sao để biết một dịch vụ công có hỗ trợ trực tuyến hay không?", options: ["A. Hỏi người dân khác", "B. Tra cứu trên Cổng Dịch vụ công Quốc gia hoặc cổng dịch vụ công cấp bộ/tỉnh", "C. Đến trực tiếp cơ quan để hỏi", "D. Xem quảng cáo trên TV"], correctAnswer: "B. Tra cứu trên Cổng Dịch vụ công Quốc gia hoặc cổng dịch vụ công cấp bộ/tỉnh" },
  { id: 235, text: "Vai trò của Cơ sở dữ liệu quốc gia về dân cư trong định danh điện tử là gì?", options: ["A. Lưu trữ thông tin cá nhân của công dân", "B. Cung cấp thông tin xác thực cho định danh điện tử", "C. Kết nối với các cơ sở dữ liệu chuyên ngành khác", "D. Tất cả các vai trò trên"], correctAnswer: "D. Tất cả các vai trò trên" },
  { id: 236, text: "Thanh toán phí dịch vụ công trực tuyến có những hình thức nào phổ biến?", options: ["A. Chỉ bằng thẻ ngân hàng", "B. Qua ví điện tử, tài khoản ngân hàng, Mobile Money", "C. Chỉ bằng tiền mặt", "D. Chỉ qua bưu điện"], correctAnswer: "B. Qua ví điện tử, tài khoản ngân hàng, Mobile Money" },
  { id: 237, text: "Khi nộp hồ sơ trực tuyến, cần đảm bảo điều gì về chất lượng ảnh chụp/scan giấy tờ?", options: ["A. Chụp càng mờ càng tốt", "B. Ảnh/scan rõ nét, đầy đủ thông tin, đúng định dạng", "C. Chỉ chụp một phần giấy tờ", "D. Không cần chụp giấy tờ"], correctAnswer: "B. Ảnh/scan rõ nét, đầy đủ thông tin, đúng định dạng" },
  { id: 238, text: "Người dân có thể tra cứu thông tin gì trên Cổng Dịch vụ công Quốc gia?", options: ["A. Thông tin về thủ tục hành chính", "B. Tình trạng giải quyết hồ sơ", "C. Thông tin liên hệ của cơ quan giải quyết", "D. Tất cả các thông tin trên"], correctAnswer: "D. Tất cả các thông tin trên" },
  { id: 239, text: "Khi sử dụng dịch vụ công trực tuyến, làm sao để nhận kết quả hồ sơ?", options: ["A. Đến trực tiếp cơ quan nhận", "B. Nhận qua bưu điện", "C. Nhận bản điện tử trên Cổng Dịch vụ công hoặc qua email/SMS", "D. Tất cả các hình thức trên tùy thủ tục"], correctAnswer: "D. Tất cả các hình thức trên tùy thủ tục" },
  { id: 240, text: "Mục tiêu của việc triển khai dịch vụ công trực tuyến là gì?", options: ["A. Giảm sự tương tác giữa người dân và cán bộ", "B. Nâng cao chất lượng phục vụ người dân và doanh nghiệp", "C. Tăng cường công việc cho cán bộ", "D. Chỉ để hiện đại hóa"], correctAnswer: "B. Nâng cao chất lượng phục vụ người dân và doanh nghiệp" },
  { id: 241, text: "Khi sử dụng tài khoản VNeID để đăng nhập Cổng Dịch vụ công Quốc gia, có cần đăng ký tài khoản riêng trên Cổng nữa không?", options: ["A. Vẫn cần đăng ký tài khoản riêng", "B. Không cần đăng ký tài khoản riêng trên Cổng Dịch vụ công Quốc gia nữa", "C. Tùy từng trường hợp", "D. Chỉ dùng VNeID để tra cứu"], correctAnswer: "B. Không cần đăng ký tài khoản riêng trên Cổng Dịch vụ công Quốc gia nữa" },
  { id: 242, text: "Thông tin về cư trú của công dân có thể được kiểm tra qua VNeID không?", options: ["A. Không thể kiểm tra", "B. Có thể kiểm tra nếu thông tin đã được cập nhật và tích hợp", "C. Chỉ kiểm tra được thông tin tạm trú", "D. Chỉ kiểm tra được thông tin thường trú"], correctAnswer: "B. Có thể kiểm tra nếu thông tin đã được cập nhật và tích hợp" },
  { id: 243, text: "Việc sử dụng dịch vụ công trực tuyến giúp tiết kiệm những chi phí nào?", options: ["A. Chi phí đi lại", "B. Chi phí in ấn hồ sơ", "C. Chi phí thời gian chờ đợi", "D. Tất cả các chi phí trên"], correctAnswer: "D. Tất cả các chi phí trên" },
  { id: 244, text: "Khi nộp hồ sơ trực tuyến, làm sao để biết hồ sơ đã được gửi thành công?", options: ["A. Không có thông báo", "B. Hệ thống sẽ có thông báo nộp thành công và cung cấp mã số hồ sơ", "C. Chỉ cần thấy nút gửi", "D. Gửi xong là được"], correctAnswer: "B. Hệ thống sẽ có thông báo nộp thành công và cung cấp mã số hồ sơ" },
  { id: 245, text: "Có thể ủy quyền cho người khác sử dụng tài khoản định danh điện tử của mình không?", options: ["A. Có thể ủy quyền tùy ý", "B. Không được ủy quyền, tài khoản định danh điện tử là của cá nhân và phải tự quản lý", "C. Chỉ ủy quyền cho người thân", "D. Chỉ ủy quyền khi đi vắng"], correctAnswer: "B. Không được ủy quyền, tài khoản định danh điện tử là của cá nhân và phải tự quản lý" },
  { id: 246, text: "Khi thực hiện thủ tục hành chính trực tuyến mà gặp lỗi hệ thống, cần làm gì?", options: ["A. Bỏ qua không làm nữa", "B. Thử lại sau", "C. Liên hệ bộ phận hỗ trợ kỹ thuật của Cổng Dịch vụ công hoặc cơ quan liên quan", "D. Tự sửa lỗi"], correctAnswer: "C. Liên hệ bộ phận hỗ trợ kỹ thuật của Cổng Dịch vụ công hoặc cơ quan liên quan" },
  { id: 247, text: "Lợi ích của việc sử dụng chữ ký số trong hành chính công trực tuyến là gì?", options: ["A. Thay thế chữ ký tay trên văn bản điện tử", "B. Đảm bảo tính toàn vẹn và chống chối bỏ của văn bản", "C. Rút ngắn thời gian xử lý hồ sơ", "D. Tất cả các lợi ích trên"], correctAnswer: "D. Tất cả các lợi ích trên" },
  { id: 248, text: "Các thông báo liên quan đến giải quyết hồ sơ dịch vụ công trực tuyến thường được gửi qua đâu?", options: ["A. Chỉ qua bưu điện", "B. Qua email, SMS, hoặc trên Cổng Dịch vụ công/ứng dụng VNeID", "C. Chỉ gọi điện thoại thông báo", "D. Chỉ gửi qua mạng xã hội"], correctAnswer: "B. Qua email, SMS, hoặc trên Cổng Dịch vụ công/ứng dụng VNeID" },
  { id: 249, text: "Khi cần bổ sung hồ sơ cho thủ tục hành chính trực tuyến, làm sao để thực hiện?", options: ["A. Nộp lại hồ sơ từ đầu", "B. Truy cập lại hồ sơ đã nộp trên Cổng Dịch vụ công và tải lên các tài liệu bổ sung theo yêu cầu", "C. Đến trực tiếp cơ quan để bổ sung", "D. Gửi qua email cá nhân"], correctAnswer: "B. Truy cập lại hồ sơ đã nộp trên Cổng Dịch vụ công và tải lên các tài liệu bổ sung theo yêu cầu" },  { id: 250, text: "Định danh điện tử và hành chính công trực tuyến góp phần vào việc phòng chống tham nhũng như thế nào?", options: ["A. Không liên quan", "B. Tăng tính công khai, minh bạch, giảm tiếp xúc trực tiếp, hạn chế tiêu cực", "C. Làm tăng cơ hội tham nhũng", "D. Chỉ liên quan đến kinh tế"], correctAnswer: "B. Tăng tính công khai, minh bạch, giảm tiếp xúc trực tiếp, hạn chế tiêu cực" },
  { id: 251, text: "Để đảm bảo an toàn khi sử dụng Cổng Dịch vụ công Quốc gia, cần chú ý điều gì?", options: ["A. Đăng nhập ở nơi công cộng và lưu mật khẩu", "B. Chỉ truy cập qua địa chỉ chính thức (dichvucong.gov.vn) và bảo vệ tài khoản", "C. Chia sẻ tài khoản cho người khác", "D. Sử dụng mật khẩu yếu"], correctAnswer: "B. Chỉ truy cập qua địa chỉ chính thức (dichvucong.gov.vn) và bảo vệ tài khoản" },
  { id: 252, text: "Chức năng chính của trình duyệt web là gì?", options: ["A. Soạn thảo văn bản", "B. Vẽ hình", "C. Truy cập Internet", "D. Nghe nhạc"], correctAnswer: "C. Truy cập Internet" },
  { id: 253, text: "Email là gì?", options: ["A. Tin nhắn văn bản", "B. Hộp thư điện tử", "C. Trang web", "D. Phần mềm diệt virus"], correctAnswer: "B. Hộp thư điện tử" },
  { id: 254, text: "Thiết bị nào được sử dụng để nhập dữ liệu bằng cách chạm vào màn hình?", options: ["A. Bàn phím", "B. Chuột", "C. Màn hình cảm ứng", "D. Máy in"], correctAnswer: "C. Màn hình cảm ứng" },
  { id: 255, text: "Công nghệ nào cho phép thanh toán không dùng tiền mặt bằng cách chạm điện thoại vào máy POS?", options: ["A. Bluetooth", "B. Wi-Fi", "C. NFC (Near-Field Communication)", "D. Hồng ngoại"], correctAnswer: "C. NFC (Near-Field Communication)" },
  { id: 256, text: "Để bảo vệ tài khoản trực tuyến, ngoài mật khẩu, bạn có thể sử dụng phương pháp bảo mật nào khác?", options: ["A. Chia sẻ mật khẩu cho bạn bè", "B. Xác thực hai yếu tố (2FA)", "C. Ghi mật khẩu ra giấy dán lên màn hình", "D. Sử dụng cùng một mật khẩu cho nhiều tài khoản"], correctAnswer: "B. Xác thực hai yếu tố (2FA)" },
  { id: 257, text: "Khi nhận được cuộc gọi hoặc tin nhắn yêu cầu cung cấp mã OTP, bạn nên làm gì?", options: ["A. Cung cấp mã OTP ngay lập tức", "B. Từ chối cung cấp và kiểm tra lại giao dịch hoặc liên hệ ngân hàng/dịch vụ chính thức", "C. Chia sẻ cho người gọi nếu họ tự xưng là nhân viên ngân hàng", "D. Bỏ qua không làm gì"], correctAnswer: "B. Từ chối cung cấp và kiểm tra lại giao dịch hoặc liên hệ ngân hàng/dịch vụ chính thức" },
  { id: 258, text: "Phần mềm độc hại (malware) là gì?", options: ["A. Phần mềm giúp tăng tốc máy tính", "B. Phần mềm được thiết kế để gây hại hoặc truy cập trái phép vào hệ thống máy tính", "C. Phần mềm để vẽ đồ họa", "D. Phần mềm chơi nhạc"], correctAnswer: "B. Phần mềm được thiết kế để gây hại hoặc truy cập trái phép vào hệ thống máy tính" },
  { id: 259, text: "Đâu là ví dụ về nền tảng học trực tuyến phổ biến tại Việt Nam?", options: ["A. Shopee", "B. Lazada", "C. Zoom/Google Meet/Microsoft Teams", "D. Grab"], correctAnswer: "C. Zoom/Google Meet/Microsoft Teams" },
  { id: 260, text: "Để tham gia lớp học trực tuyến, bạn cần có những thiết bị gì?", options: ["A. Máy chơi game", "B. Điện thoại hoặc máy tính có kết nối Internet và phần mềm học trực tuyến", "C. Máy in và giấy", "D. Chỉ cần tivi"], correctAnswer: "B. Điện thoại hoặc máy tính có kết nối Internet và phần mềm học trực tuyến" },
  { id: 261, text: "Khi tìm kiếm thông tin trên Internet, làm sao để đánh giá độ tin cậy của một website?", options: ["A. Xem website có giao diện đẹp không", "B. Kiểm tra nguồn thông tin, tác giả, ngày cập nhật, và so sánh với các nguồn uy tín khác", "C. Tin vào tất cả những gì đọc được", "D. Xem số lượng người truy cập"], correctAnswer: "B. Kiểm tra nguồn thông tin, tác giả, ngày cập nhật, và so sánh với các nguồn uy tín khác" },
  { id: 262, text: "Đâu là ví dụ về dịch vụ công trực tuyến?", options: ["A. Mua sắm online", "B. Xem phim trực tuyến", "C. Đăng ký tạm trú/tạm vắng qua mạng", "D. Chơi game online"], correctAnswer: "C. Đăng ký tạm trú/tạm vắng qua mạng" },
  { id: 263, text: "Khi sử dụng mạng xã hội, hành vi nào sau đây là nên tránh?", options: ["A. Chia sẻ khoảnh khắc đời thường với bạn bè", "B. Tham gia các hội nhóm học tập", "C. Tiết lộ quá nhiều thông tin cá nhân nhạy cảm (số điện thoại, địa chỉ nhà, số CMND)", "D. Kết nối với người thân"], correctAnswer: "C. Tiết lộ quá nhiều thông tin cá nhân nhạy cảm (số điện thoại, địa chỉ nhà, số CMND)" },
  { id: 264, text: "Ứng dụng nào thường được sử dụng để liên lạc bằng văn bản và giọng nói qua Internet?", options: ["A. Google Sheets", "B. Microsoft Word", "C. Zalo/Viber/WhatsApp", "D. Adobe Photoshop"], correctAnswer: "C. Zalo/Viber/WhatsApp" },
  { id: 265, text: "Lợi ích chính của mua sắm trực tuyến (online shopping) là gì?", options: ["A. Tốn nhiều thời gian đi lại", "B. Có nhiều lựa chọn sản phẩm, so sánh giá dễ dàng, mua sắm mọi lúc mọi nơi", "C. Chỉ mua được một số ít sản phẩm", "D. Giá cả luôn đắt hơn mua trực tiếp"], correctAnswer: "B. Có nhiều lựa chọn sản phẩm, so sánh giá dễ dàng, mua sắm mọi lúc mọi nơi" },
  { id: 266, text: "Khi bán hàng trực tuyến, bạn cần chú ý điều gì để tạo uy tín?", options: ["A. Đăng thông tin sản phẩm sai sự thật", "B. Sử dụng hình ảnh sản phẩm kém chất lượng", "C. Cung cấp thông tin liên hệ rõ ràng, mô tả sản phẩm chính xác, phản hồi khách hàng nhanh chóng", "D. Không cần quan tâm đến đánh giá của khách hàng"], correctAnswer: "C. Cung cấp thông tin liên hệ rõ ràng, mô tả sản phẩm chính xác, phản hồi khách hàng nhanh chóng" },
  { id: 267, text: "Công nghệ nào giúp các thiết bị trong nhà (đèn, quạt, tivi...) kết nối và điều khiển từ xa qua điện thoại?", options: ["A. Công nghệ 2G", "B. Công nghệ nhà thông minh (Smart Home)", "C. Công nghệ in 3D", "D. Công nghệ thực tế ảo"], correctAnswer: "B. Công nghệ nhà thông minh (Smart Home)" },
  { id: 268, text: "Để đảm bảo an toàn cho trẻ em khi sử dụng Internet, phụ huynh nên làm gì?", options: ["A. Cho trẻ tự do truy cập bất kỳ nội dung nào", "B. Thiết lập các biện pháp kiểm soát truy cập, hướng dẫn trẻ về an toàn trực tuyến, đồng hành cùng trẻ khi sử dụng mạng", "C. Không cho trẻ sử dụng bất kỳ thiết bị điện tử nào", "D. Mặc kệ trẻ muốn làm gì thì làm"], correctAnswer: "B. Thiết lập các biện pháp kiểm soát truy cập, hướng dẫn trẻ về an toàn trực tuyến, đồng hành cùng trẻ khi sử dụng mạng" },
  { id: 269, text: "Khi điện thoại hoặc máy tính hoạt động chậm, bạn nên làm gì trước tiên?", options: ["A. Mua thiết bị mới ngay lập tức", "B. Khởi động lại thiết bị, xóa bớt ứng dụng không cần thiết, kiểm tra virus", "C. Đập bỏ thiết bị", "D. Để nguyên và hy vọng nó nhanh lên"], correctAnswer: "B. Khởi động lại thiết bị, xóa bớt ứng dụng không cần thiết, kiểm tra virus" },
  { id: 270, text: "Lợi ích của việc sao lưu dữ liệu (backup) là gì?", options: ["A. Làm tốn dung lượng lưu trữ", "B. Giúp khôi phục lại dữ liệu khi thiết bị gặp sự cố hoặc bị mất", "C. Không có lợi ích gì", "D. Chỉ làm cho máy tính chậm hơn"], correctAnswer: "B. Giúp khôi phục lại dữ liệu khi thiết bị gặp sự cố hoặc bị mất" },
  { id: 271, text: "Phần mềm nào sau đây dùng để gõ văn bản?", options: ["A. Excel", "B. PowerPoint", "C. Word", "D. Photoshop"], correctAnswer: "C. Word" },
  { id: 272, text: "Tác hại của việc sử dụng thiết bị số quá lâu là gì?", options: ["A. Tăng khả năng tập trung", "B. Tăng cường trí nhớ", "C. Mỏi mắt, giảm chú ý", "D. Không ảnh hưởng"], correctAnswer: "C. Mỏi mắt, giảm chú ý" },
  { id: 273, text: "Mạng xã hội phổ biến nhất ở Việt Nam hiện nay là:", options: ["A. Facebook", "B. Twitter", "C. TikTok", "D. Instagram"], correctAnswer: "A. Facebook" },
  { id: 274, text: "Khi nhận được tin nhắn lạ chứa liên kết, bạn nên:", options: ["A. Mở ngay liên kết", "B. Chia sẻ cho người khác", "C. Bỏ qua hoặc xóa", "D. Trả lời lại"], correctAnswer: "C. Bỏ qua hoặc xóa" },
  { id: 275, text: "Thiết bị nào sau đây KHÔNG phải là thiết bị thông minh?", options: ["A. Máy tính bảng", "B. Điện thoại cục gạch", "C. Laptop", "D. Điện thoại thông minh"], correctAnswer: "B. Điện thoại cục gạch" },
  { id: 276, text: "Lưu trữ đám mây là gì?", options: ["A. Lưu trên ổ cứng", "B. Lưu dữ liệu trên Internet", "C. Lưu vào USB", "D. Lưu trên giấy"], correctAnswer: "B. Lưu dữ liệu trên Internet" },
  { id: 277, text: "Khi sử dụng Internet, cần tuân thủ điều gì?", options: ["A. Tự do tuyệt đối", "B. Không cần kiểm soát", "C. Quy định pháp luật và đạo đức", "D. Chỉ cần biết dùng"], correctAnswer: "C. Quy định pháp luật và đạo đức" },
  { id: 278, text: "Đâu là phần mềm dùng để trình chiếu?", options: ["A. Word", "B. Excel", "C. PowerPoint", "D. Paint"], correctAnswer: "C. PowerPoint" },
  { id: 279, text: "Muốn tìm kiếm thông tin trên Internet, bạn dùng gì?", options: ["A. Trình duyệt web", "B. Máy in", "C. Webcam", "D. Bàn phím"], correctAnswer: "A. Trình duyệt web" },
  { id: 280, text: "Thông tin cá nhân nên được chia sẻ như thế nào trên mạng?", options: ["A. Công khai mọi nơi", "B. Chỉ chia sẻ với người tin cậy", "C. Gửi cho người lạ", "D. Đăng lên mạng xã hội"], correctAnswer: "B. Chỉ chia sẻ với người tin cậy" },
  { id: 281, text: "Ứng dụng nào dùng để gọi video?", options: ["A. YouTube", "B. Zalo", "C. Facebook", "D. Google Maps"], correctAnswer: "B. Zalo" },
  { id: 282, text: "Khi cài đặt phần mềm, bạn nên:", options: ["A. Cài tất cả không kiểm tra", "B. Đọc kỹ quyền truy cập trước khi chấp nhận", "C. Cài phần mềm lạ từ Internet", "D. Không cần kiểm tra gì cả"], correctAnswer: "B. Đọc kỹ quyền truy cập trước khi chấp nhận" },
  { id: 283, text: "Thiết bị nào có thể chụp ảnh?", options: ["A. Máy giặt", "B. Bàn phím", "C. Điện thoại thông minh", "D. Chuột máy tính"], correctAnswer: "C. Điện thoại thông minh" },
  { id: 284, text: "Công nghệ nào giúp kết nối không dây giữa các thiết bị gần nhau?", options: ["A. Bluetooth", "B. USB", "C. HDMI", "D. Dây mạng"], correctAnswer: "A. Bluetooth" },
  { id: 285, text: "Khi điện thoại yêu cầu cập nhật phần mềm, bạn nên:", options: ["A. Luôn từ chối", "B. Tắt nguồn", "C. Cập nhật để tăng bảo mật và hiệu năng", "D. Gỡ ứng dụng"], correctAnswer: "C. Cập nhật để tăng bảo mật và hiệu năng" },
  { id: 286, text: "“Tin giả” là gì?", options: ["A. Thông tin đúng", "B. Thông tin sai lệch, bịa đặt", "C. Thông tin chính thức", "D. Bài viết hài hước"], correctAnswer: "B. Thông tin sai lệch, bịa đặt" },
  { id: 287, text: "Ví dụ về hành vi vi phạm pháp luật trên mạng là:", options: ["A. Đăng ảnh cá nhân", "B. Bình luận tích cực", "C. Phát tán tin giả, xúc phạm người khác", "D. Mua hàng online"], correctAnswer: "C. Phát tán tin giả, xúc phạm người khác" },
  { id: 288, text: "Mật khẩu mạnh nên bao gồm:", options: ["A. Toàn chữ thường", "B. Tên người thân", "C. Ký tự đặc biệt, số và chữ", "D. Ngày sinh"], correctAnswer: "C. Ký tự đặc biệt, số và chữ" },
  { id: 289, text: "Google Translate là công cụ dùng để:", options: ["A. Tạo ảnh", "B. Dịch ngôn ngữ", "C. Chơi game", "D. Vẽ bản đồ"], correctAnswer: "B. Dịch ngôn ngữ" },
  { id: 290, text: "Cần làm gì để bảo vệ thiết bị khỏi virus?", options: ["A. Tắt mạng", "B. Cài phần mềm diệt virus", "C. Không dùng thiết bị", "D. Tăng độ sáng màn hình"], correctAnswer: "B. Cài phần mềm diệt virus" },
  { id: 291, text: "Chia sẻ thông tin sai sự thật trên mạng là:", options: ["A. Được phép", "B. Không bị sao cả", "C. Hành vi vi phạm", "D. Cách kiếm lượt xem"], correctAnswer: "C. Hành vi vi phạm" },
  { id: 292, text: "Các thiết bị thông minh có thể kết nối với nhau qua:", options: ["A. Internet", "B. Giấy viết", "C. Âm thanh", "D. Mực in"], correctAnswer: "A. Internet" },
  { id: 293, text: "Tài khoản mạng xã hội nên có:", options: ["A. Thông tin thật", "B. Ảnh người nổi tiếng", "C. Không cần thông tin", "D. Mật khẩu yếu"], correctAnswer: "A. Thông tin thật" },
  { id: 294, text: "Để nhận tiền trợ cấp online, người dân cần có:", options: ["A. CMND giấy", "B. Giấy xác nhận viết tay", "C. Tài khoản ngân hàng hoặc ví điện tử", "D. Sổ hộ khẩu"], correctAnswer: "C. Tài khoản ngân hàng hoặc ví điện tử" },
  { id: 295, text: "Mạng xã hội có thể gây hại nếu:", options: ["A. Sử dụng hợp lý", "B. Sử dụng quá nhiều và thiếu kiểm soát", "C. Dùng để học tập", "D. Dùng để chia sẻ thông tin chính thống"], correctAnswer: "B. Sử dụng quá nhiều và thiếu kiểm soát" },
  { id: 296, text: "Hình thức tấn công phổ biến qua mạng là:", options: ["A. Phishing (giả mạo để đánh cắp thông tin)", "B. Hút bụi", "C. Gọi điện thoại", "D. Chơi game"], correctAnswer: "A. Phishing (giả mạo để đánh cắp thông tin)" },
  { id: 297, text: "Ứng dụng Zalo có thể dùng để:", options: ["A. Nấu ăn", "B. Mua đất", "C. Nhắn tin, gọi điện, gửi tài liệu", "D. Viết sách"], correctAnswer: "C. Nhắn tin, gọi điện, gửi tài liệu" },
  { id: 298, text: "Muốn học trực tuyến, bạn cần:", options: ["A. Tivi", "B. Bảng trắng", "C. Điện thoại hoặc máy tính có Internet", "D. Giấy viết"], correctAnswer: "C. Điện thoại hoặc máy tính có Internet" },
  { id: 299, text: "Đăng nhập tài khoản ở nơi công cộng nên:", options: ["A. Không cần đăng xuất", "B. Lưu mật khẩu", "C. Đăng xuất sau khi sử dụng", "D. Giao máy cho người khác"], correctAnswer: "C. Đăng xuất sau khi sử dụng" },  { id: 300, text: "Để đảm bảo an toàn khi dùng mạng xã hội, nên:", options: ["A. Tin mọi thông tin", "B. Không kiểm tra nguồn", "C. Chỉ chia sẻ thông tin từ nguồn uy tín", "D. Đăng bất kỳ gì mình muốn"], correctAnswer: "C. Chỉ chia sẻ thông tin từ nguồn uy tín" },
  { id: 301, text: "Mục đích của mã OTP là gì?", options: ["A. Làm đẹp giao diện", "B. Mã dùng 1 lần để xác minh", "C. Đổi hình nền", "D. Mở khóa wifi"], correctAnswer: "B. Mã dùng 1 lần để xác minh" },
  { id: 302, text: "Đâu là ví điện tử phổ biến ở Việt Nam?", options: ["A. TikTok", "B. Shopee", "C. MoMo", "D. Excel"], correctAnswer: "C. MoMo" },
  { id: 303, text: "Đăng nhập vào tài khoản ngân hàng điện tử nên dùng gì?", options: ["A. Tên người yêu", "B. Mật khẩu đơn giản", "C. Mật khẩu mạnh và mã OTP", "D. Chia sẻ cho người thân"], correctAnswer: "C. Mật khẩu mạnh và mã OTP" },
  { id: 304, text: "“Tấn công mạng” là:", options: ["A. Chơi game trực tuyến", "B. Học trực tuyến", "C. Hành vi xâm nhập, phá hoại qua Internet", "D. Gửi email bình thường"], correctAnswer: "C. Hành vi xâm nhập, phá hoại qua Internet" },
  { id: 305, text: "Ứng dụng nào hỗ trợ định vị và chỉ đường?", options: ["A. Excel", "B. Google Maps", "C. Facebook", "D. Zalo"], correctAnswer: "B. Google Maps" },
  { id: 306, text: "Zalo là ứng dụng của nước nào phát triển?", options: ["A. Nhật Bản", "B. Mỹ", "C. Việt Nam", "D. Hàn Quốc"], correctAnswer: "C. Việt Nam" },
  { id: 307, text: "Tại sao không nên chia sẻ mật khẩu?", options: ["A. Mất quyền kiểm soát tài khoản", "B. Giúp người khác dễ dùng", "C. Không sao cả", "D. Đỡ mất công nhớ"], correctAnswer: "A. Mất quyền kiểm soát tài khoản" },
  { id: 308, text: "Ứng dụng nào giúp chỉnh sửa văn bản?", options: ["A. Word", "B. TikTok", "C. YouTube", "D. Paint"], correctAnswer: "A. Word" },
  { id: 309, text: "Các thiết bị nào sau đây được gọi là thiết bị đầu vào?", options: ["A. Loa", "B. Bàn phím, chuột", "C. Màn hình", "D. Máy in"], correctAnswer: "B. Bàn phím, chuột" },
  { id: 310, text: "Email rác thường chứa:", options: ["A. Lời mời lừa đảo, quảng cáo", "B. Tin tức chính thống", "C. Tài liệu học tập", "D. Bài tập về nhà"], correctAnswer: "A. Lời mời lừa đảo, quảng cáo" },
  { id: 311, text: "Hành vi nào là vi phạm đạo đức trên mạng?", options: ["A. Chia sẻ tin đúng", "B. Giúp đỡ cộng đồng", "C. Bình luận xúc phạm, phân biệt", "D. Đọc tin tức"], correctAnswer: "C. Bình luận xúc phạm, phân biệt" },
  { id: 312, text: "Để xem video hướng dẫn học tập, bạn nên vào đâu?", options: ["A. Google Maps", "B. Excel", "C. YouTube", "D. Zing MP3"], correctAnswer: "C. YouTube" },
  { id: 313, text: "Khi tài khoản mạng xã hội bị mất quyền truy cập, bạn nên:", options: ["A. Bỏ qua", "B. Tạo tài khoản mới", "C. Báo cáo vi phạm và lấy lại qua email", "D. Nhờ người khác lấy giùm"], correctAnswer: "C. Báo cáo vi phạm và lấy lại qua email" },
  { id: 314, text: "Ứng dụng nào sau đây giúp họp, học trực tuyến?", options: ["A. Zoom", "B. Paint", "C. TikTok", "D. CapCut"], correctAnswer: "A. Zoom" },
  { id: 315, text: "“Tin nhắn rác” là:", options: ["A. Tin quan trọng", "B. Tin từ bạn bè", "C. Tin lặp lại, quảng cáo không mong muốn", "D. Tin ngân hàng"], correctAnswer: "C. Tin lặp lại, quảng cáo không mong muốn" },
  { id: 316, text: "Để kiểm tra độ tin cậy của thông tin, bạn nên:", options: ["A. Đọc nhiều nguồn uy tín", "B. Tin vào cảm giác", "C. Hỏi bạn bè", "D. Xem lượt thích"], correctAnswer: "A. Đọc nhiều nguồn uy tín" },
  { id: 317, text: "Lợi ích của công nghệ số với người dân là:", options: ["A. Kết nối, học tập, mua sắm tiện lợi", "B. Tăng chi phí", "C. Tăng thời gian chờ đợi", "D. Không có lợi gì"], correctAnswer: "A. Kết nối, học tập, mua sắm tiện lợi" },
  { id: 318, text: "Để tránh bị lừa đảo qua mạng, bạn cần:", options: ["A. Không cung cấp thông tin cá nhân", "B. Đọc kỹ các điều khoản dịch vụ", "C. Tin tưởng vào mọi lời mời", "D. Cung cấp tài khoản ngân hàng khi được yêu cầu"], correctAnswer: "A. Không cung cấp thông tin cá nhân" },
  { id: 319, text: "Phần mềm diệt virus giúp bảo vệ thiết bị khỏi:", options: ["A. Nhạc nền", "B. Virus, phần mềm độc hại", "C. Video", "D. Đồ họa"], correctAnswer: "B. Virus, phần mềm độc hại" },
  { id: 320, text: "Để tăng hiệu suất làm việc trên máy tính, bạn cần:", options: ["A. Dùng nhiều ứng dụng cùng lúc", "B. Thường xuyên cập nhật phần mềm", "C. Dùng phần mềm lạ", "D. Tắt tất cả các ứng dụng"], correctAnswer: "B. Thường xuyên cập nhật phần mềm" },
  { id: 321, text: "Những thiết bị nào dưới đây không cần kết nối Internet?", options: ["A. Máy tính", "B. Máy in", "C. Điện thoại thông minh", "D. Laptop"], correctAnswer: "B. Máy in" },
  { id: 322, text: "Cách nào để đảm bảo sự riêng tư trên Internet?", options: ["A. Sử dụng mật khẩu mạnh", "B. Dùng thông tin thật hết mức", "C. Chia sẻ mọi thông tin cá nhân", "D. Mở tất cả các liên kết"], correctAnswer: "A. Sử dụng mật khẩu mạnh" },
  { id: 323, text: "Các dịch vụ ngân hàng điện tử cho phép người dùng làm gì?", options: ["A. Gửi tiền trực tuyến", "B. Đọc tin tức", "C. Chơi game", "D. Xem video"], correctAnswer: "A. Gửi tiền trực tuyến" },
  { id: 324, text: "Điều gì là nguy hiểm khi sử dụng Wi-Fi công cộng?", options: ["A. Wi-Fi miễn phí", "B. Mất kết nối nhanh", "C. Nguy cơ bị hack, đánh cắp thông tin", "D. Tín hiệu mạnh"], correctAnswer: "C. Nguy cơ bị hack, đánh cắp thông tin" },
  { id: 325, text: "Kết nối Bluetooth được sử dụng để:", options: ["A. Truyền tải dữ liệu qua mạng di động", "B. Kết nối các thiết bị gần nhau mà không cần dây", "C. Kết nối với điện thoại cố định", "D. Dùng để truyền hình ảnh từ xa"], correctAnswer: "B. Kết nối các thiết bị gần nhau mà không cần dây" },
  { id: 326, text: "Bạn cần sử dụng ứng dụng nào để gọi video trực tiếp với người khác?", options: ["A. Facebook", "B. YouTube", "C. Google Meet", "D. Word"], correctAnswer: "C. Google Meet" },
  { id: 327, text: "Bạn có thể mua hàng trực tuyến ở đâu?", options: ["A. Các website bán hàng", "B. Chỉ qua cửa hàng vật lý", "C. Qua quảng cáo trên TV", "D. Chỉ trên điện thoại"], correctAnswer: "A. Các website bán hàng" },
  { id: 328, text: "Các trò chơi trực tuyến có thể gây ra tác hại gì?", options: ["A. Giúp nâng cao kỹ năng giao tiếp", "B. Lãng phí thời gian nếu chơi quá nhiều", "C. Không ảnh hưởng gì", "D. Tăng cường trí nhớ"], correctAnswer: "B. Lãng phí thời gian nếu chơi quá nhiều" },
  { id: 329, text: "Dịch vụ “Cloud storage” là gì?", options: ["A. Lưu trữ dữ liệu trên đám mây, không cần thiết thiết bị vật lý", "B. Lưu trữ dữ liệu trên ổ cứng của bạn", "C. Chỉ lưu trữ dữ liệu âm thanh", "D. Lưu trữ video trực tiếp"], correctAnswer: "A. Lưu trữ dữ liệu trên đám mây, không cần thiết thiết bị vật lý" },
  { id: 330, text: "Để chia sẻ hình ảnh với bạn bè qua mạng, bạn có thể dùng ứng dụng nào?", options: ["A. Google Photos", "B. Zalo", "C. Instagram", "D. Tất cả các lựa chọn trên"], correctAnswer: "D. Tất cả các lựa chọn trên" },
  { id: 331, text: "Đâu là nguyên tắc quan trọng khi sử dụng mạng xã hội?", options: ["A. Đăng mọi thứ về mình", "B. Bảo vệ quyền riêng tư của bản thân", "C. Chia sẻ mọi thông tin tài chính", "D. Đọc tất cả thông tin từ một nguồn"], correctAnswer: "B. Bảo vệ quyền riêng tư của bản thân" },
  { id: 332, text: "Hành vi nào sau đây là vi phạm khi sử dụng Internet?", options: ["A. Mua hàng trực tuyến", "B. Cung cấp thông tin cá nhân cho người lạ", "C. Tìm kiếm thông tin giáo dục", "D. Chia sẻ thông tin với bạn bè"], correctAnswer: "B. Cung cấp thông tin cá nhân cho người lạ" },
  { id: 333, text: "Ví dụ nào sau đây là sử dụng Internet an toàn?", options: ["A. Đăng nhập tài khoản ngân hàng trên thiết bị công cộng", "B. Kiểm tra email từ nguồn không rõ", "C. Đảm bảo mật khẩu mạnh và không chia sẻ", "D. Dùng ứng dụng không rõ nguồn gốc"], correctAnswer: "C. Đảm bảo mật khẩu mạnh và không chia sẻ" },
  { id: 334, text: "Những yếu tố nào giúp tạo mật khẩu an toàn?", options: ["A. Chỉ dùng ngày sinh", "B. Dùng tên người thân", "C. Kết hợp chữ, số, ký tự đặc biệt", "D. Đặt mật khẩu dễ nhớ"], correctAnswer: "C. Kết hợp chữ, số, ký tự đặc biệt" },
  { id: 335, text: "Tạo tài khoản email cần cung cấp thông tin gì?", options: ["A. Tên người dùng và mật khẩu", "B. Địa chỉ nhà", "C. Số điện thoại của bạn bè", "D. Địa chỉ ngân hàng"], correctAnswer: "A. Tên người dùng và mật khẩu" },
  { id: 336, text: "Tác hại của việc sử dụng mật khẩu yếu là gì?", options: ["A. Không thể đăng nhập vào tài khoản", "B. Dễ bị hack tài khoản", "C. Giúp tài khoản dễ nhớ hơn", "D. Không ảnh hưởng gì"], correctAnswer: "B. Dễ bị hack tài khoản" },
  { id: 337, text: "Phần mềm chống virus giúp bảo vệ thiết bị khỏi:", options: ["A. Nhạc nền", "B. Virus, phần mềm độc hại", "C. Video", "D. Đồ họa"], correctAnswer: "B. Virus, phần mềm độc hại" },
  { id: 338, text: "Khi cài đặt phần mềm trên máy tính, bạn cần chú ý điều gì?", options: ["A. Bỏ qua yêu cầu của phần mềm", "B. Tải phần mềm từ nguồn uy tín", "C. Cài phần mềm từ bất kỳ website nào", "D. Tắt tất cả các phần mềm diệt virus"], correctAnswer: "B. Tải phần mềm từ nguồn uy tín" },
  { id: 339, text: "Các website bán hàng trực tuyến thường yêu cầu thông tin gì?", options: ["A. Chỉ địa chỉ email", "B. Thông tin thẻ tín dụng và địa chỉ giao hàng", "C. Chỉ cần tên người mua", "D. Thông tin tài khoản mạng xã hội"], correctAnswer: "B. Thông tin thẻ tín dụng và địa chỉ giao hàng" },
  { id: 340, text: "Cần tránh làm gì khi sử dụng dịch vụ ngân hàng điện tử?", options: ["A. Chỉ truy cập qua mạng Wi-Fi bảo mật", "B. Cung cấp mật khẩu cho người khác", "C. Kiểm tra các giao dịch ngay", "D. Lưu mật khẩu trên máy tính"], correctAnswer: "B. Cung cấp mật khẩu cho người khác" },
  { id: 341, text: "Một trong những mối nguy hiểm trên Internet là:", options: ["A. Gửi email cho bạn bè", "B. Tải phần mềm từ nguồn không rõ", "C. Xem video học trực tuyến", "D. Đọc sách điện tử"], correctAnswer: "B. Tải phần mềm từ nguồn không rõ" },
  { id: 342, text: "Một số phần mềm tạo sự tiện lợi trong việc quản lý tài chính cá nhân là:", options: ["A. Excel, Google Sheets", "B. Word, PowerPoint", "C. Tất cả các phần mềm đồ họa", "D. Trình duyệt web"], correctAnswer: "A. Excel, Google Sheets" },
  { id: 343, text: "Để sử dụng Google Drive, bạn cần có:", options: ["A. Tài khoản Google", "B. Phần mềm độc hại", "C. Tài khoản ngân hàng", "D. Máy tính bàn"], correctAnswer: "A. Tài khoản Google" },
  { id: 344, text: "Thông tin trên mạng có thể sai sự thật nếu:", options: ["A. Được đăng từ một website uy tín", "B. Chỉ là tin tức mới cập nhật", "C. Được đăng mà không kiểm chứng", "D. Được chia sẻ từ người thân"], correctAnswer: "C. Được đăng mà không kiểm chứng" },
  { id: 345, text: "Chia sẻ tài liệu công việc qua mạng cần chú ý điều gì?", options: ["A. Chia sẻ tất cả các tài liệu với bạn bè", "B. Đảm bảo tài liệu không chứa thông tin nhạy cảm", "C. Đảm bảo tài liệu có độ bảo mật thấp", "D. Không cần kiểm tra trước khi chia sẻ"], correctAnswer: "B. Đảm bảo tài liệu không chứa thông tin nhạy cảm" },
  { id: 346, text: "Để giữ an toàn khi mua hàng trực tuyến, bạn nên:", options: ["A. Mua hàng từ những website không rõ nguồn gốc", "B. Kiểm tra độ bảo mật của website", "C. Cung cấp thông tin thẻ tín dụng cho người bán", "D. Không kiểm tra thông tin người bán"], correctAnswer: "B. Kiểm tra độ bảo mật của website" },
  { id: 347, text: "Điều gì nên tránh khi sử dụng mạng xã hội?", options: ["A. Đọc thông tin giáo dục", "B. Chia sẻ thông tin cá nhân quá mức", "C. Đăng bài viết sáng tạo", "D. Chia sẻ thông tin từ nguồn uy tín"], correctAnswer: "B. Chia sẻ thông tin cá nhân quá mức" },
  { id: 348, text: "Để kiểm soát thời gian sử dụng điện thoại, bạn nên làm gì?", options: ["A. Dùng ứng dụng theo dõi thời gian sử dụng", "B. Không cần kiểm soát", "C. Chơi game suốt ngày", "D. Đọc báo liên tục"], correctAnswer: "A. Dùng ứng dụng theo dõi thời gian sử dụng" },
  { id: 349, text: "Một trong những lợi ích của việc sử dụng công nghệ số là gì?", options: ["A. Giảm hiệu quả công việc", "B. Tiết kiệm thời gian và công sức", "C. Làm việc ít hiệu quả hơn", "D. Không giúp ích gì"], correctAnswer: "B. Tiết kiệm thời gian và công sức" },  { id: 350, text: "Thiết bị nào sau đây có thể kết nối Internet?", options: ["A. Tivi thường", "B. Đèn bàn", "C. Điện thoại thông minh", "D. Quạt máy"], correctAnswer: "C. Điện thoại thông minh" },
  { id: 351, text: "Đâu là một ví dụ về mạng xã hội?", options: ["A. Microsoft Word", "B. Google Maps", "C. Facebook", "D. Máy tính Casio"], correctAnswer: "C. Facebook" },
  { id: 352, text: "Để gửi thư điện tử (email), bạn cần có?", options: ["A. Tài khoản email", "B. Máy in", "C. Điện thoại bàn", "D. USB"], correctAnswer: "A. Tài khoản email" },
  { id: 353, text: "Thuật ngữ \"Wi-Fi\" liên quan đến?", options: ["A. Kết nối mạng không dây", "B. Pin dự phòng", "C. Loa Bluetooth", "D. Cáp sạc điện thoại"], correctAnswer: "A. Kết nối mạng không dây" },
  { id: 354, text: "Ứng dụng nào sau đây dùng để xem video trực tuyến?", options: ["A. Zalo", "B. Excel", "C. YouTube", "D. Calculator"], correctAnswer: "C. YouTube" },
  { id: 355, text: "Phần mềm độc hại (virus) máy tính có thể gây ra điều gì?", options: ["A. Làm máy chạy nhanh hơn", "B. Tăng dung lượng lưu trữ", "C. Đánh cắp thông tin cá nhân", "D. Cải thiện chất lượng hình ảnh"], correctAnswer: "C. Đánh cắp thông tin cá nhân" },
  { id: 356, text: "Đâu là một trình duyệt web phổ biến?", options: ["A. Adobe Photoshop", "B. WinRAR", "C. Skype", "D. Google Chrome"], correctAnswer: "D. Google Chrome" },
  { id: 357, text: "Lưu trữ đám mây (Cloud Storage) là gì?", options: ["A. Lưu dữ liệu trên ổ cứng máy tính", "B. Lưu dữ liệu trên thẻ nhớ", "C. Lưu dữ liệu trực tuyến trên máy chủ từ xa", "D. Lưu dữ liệu trên đĩa CD"], correctAnswer: "C. Lưu dữ liệu trực tuyến trên máy chủ từ xa" },
  { id: 358, text: "Mật khẩu mạnh nên bao gồm những gì?", options: ["A. Chỉ chữ cái thường", "B. Tên của bạn", "C. Kết hợp chữ hoa, chữ thường, số và ký tự đặc biệt", "D. Ngày sinh của bạn"], correctAnswer: "C. Kết hợp chữ hoa, chữ thường, số và ký tự đặc biệt" },
  { id: 359, text: "Mã QR (QR Code) thường được sử dụng để làm gì?", options: ["A. Nghe nhạc", "B. Chỉnh sửa ảnh", "C. Truy cập nhanh thông tin hoặc liên kết web", "D. Soạn thảo văn bản"], correctAnswer: "C. Truy cập nhanh thông tin hoặc liên kết web" },
  { id: 360, text: "GPS là viết tắt của hệ thống nào?", options: ["A. Hệ thống định vị toàn cầu", "B. Hệ thống giải trí gia đình", "C. Hệ thống quản lý bán hàng", "D. Hệ thống phòng cháy chữa cháy"], correctAnswer: "A. Hệ thống định vị toàn cầu" },
  { id: 361, text: "Định dạng tệp nào thường được sử dụng cho hình ảnh?", options: ["A. .mp3", "B. .docx", "C. .jpg", "D. .pdf"], correctAnswer: "C. .jpg" },
  { id: 362, text: "Hệ điều hành nào được phát triển bởi Apple cho iPhone?", options: ["A. Android", "B. Windows", "C. iOS", "D. Linux"], correctAnswer: "C. iOS" },
  { id: 363, text: "CPU trong máy tính là viết tắt của?", options: ["A. Bộ xử lý trung tâm", "B. Card đồ họa", "C. Bộ nhớ truy cập ngẫu nhiên", "D. Ổ đĩa cứng"], correctAnswer: "A. Bộ xử lý trung tâm" },
  { id: 364, text: "\"Sao lưu\" (Backup) dữ liệu có nghĩa là gì?", options: ["A. Xóa dữ liệu vĩnh viễn", "B. Chia sẻ dữ liệu với người khác", "C. Mã hóa dữ liệu", "D. Tạo bản sao của dữ liệu để phòng trường hợp mất mát"], correctAnswer: "D. Tạo bản sao của dữ liệu để phòng trường hợp mất mát" },
  { id: 365, text: "Bluetooth là công nghệ dùng để làm gì?", options: ["A. Kết nối Internet tốc độ cao", "B. Lưu trữ dữ liệu trực tuyến", "C. Thực hiện cuộc gọi video", "D. Kết nối các thiết bị ở khoảng cách gần không cần dây"], correctAnswer: "D. Kết nối các thiết bị ở khoảng cách gần không cần dây" },
  { id: 366, text: "Đâu là một ví dụ về thiết bị nhập (Input device) cho máy tính?", options: ["A. Màn hình", "B. Loa", "C. Bàn phím", "D. Máy in"], correctAnswer: "C. Bàn phím" },
  { id: 367, text: "Thương mại điện tử (E-commerce) là gì?", options: ["A. Gửi thư điện tử", "B. Mua bán hàng hóa và dịch vụ qua Internet", "C. Học trực tuyến", "D. Chơi game online"], correctAnswer: "B. Mua bán hàng hóa và dịch vụ qua Internet" },
  { id: 368, text: "URL là viết tắt của?", options: ["A. Universal Resource Locator (Địa chỉ tài nguyên thống nhất)", "B. User Registration Link (Liên kết đăng ký người dùng)", "C. Uniform Rendering Language (Ngôn ngữ kết xuất đồng nhất)", "D. Underlying Routing Logic (Logic định tuyến cơ bản)"], correctAnswer: "A. Universal Resource Locator (Địa chỉ tài nguyên thống nhất)" },
  { id: 369, text: "Phần mềm nào dùng để tạo bảng tính?", options: ["A. Microsoft Word", "B. Microsoft Excel", "C. Microsoft PowerPoint", "D. Adobe Reader"], correctAnswer: "B. Microsoft Excel" },
  { id: 370, text: "RAM trong máy tính là viết tắt của?", options: ["A. Read Access Memory", "B. Realtime Application Management", "C. Remote Administration Module", "D. Random Access Memory (Bộ nhớ truy cập ngẫu nhiên)"], correctAnswer: "D. Random Access Memory (Bộ nhớ truy cập ngẫu nhiên)" },
  { id: 371, text: "HTTPS ở đầu địa chỉ web có ý nghĩa gì?", options: ["A. Trang web này tải nhanh hơn", "B. Đây là trang web chỉ dành cho thành viên", "C. Kết nối đến trang web này được mã hóa và an toàn", "D. Trang web này có nhiều hình ảnh"], correctAnswer: "C. Kết nối đến trang web này được mã hóa và an toàn" },
  { id: 372, text: "AI là viết tắt của?", options: ["A. Artificial Intelligence (Trí tuệ nhân tạo)", "B. Automated Installation", "C. Advanced Interface", "D. Application Integration"], correctAnswer: "A. Artificial Intelligence (Trí tuệ nhân tạo)" },
  { id: 373, text: "Làm thế nào để bảo vệ mắt khi sử dụng máy tính thường xuyên?", options: ["A. Tăng độ sáng màn hình tối đa", "B. Để màn hình gần mắt nhất có thể", "C. Không bao giờ chớp mắt", "D. Nghỉ giải lao và nhìn ra xa định kỳ"], correctAnswer: "D. Nghỉ giải lao và nhìn ra xa định kỳ" },
  { id: 374, text: "Đâu là một ví dụ về phần cứng (Hardware) máy tính?", options: ["A. Hệ điều hành Windows", "B. Trình duyệt Chrome", "C. Con chuột máy tính", "D. Phần mềm diệt virus"], correctAnswer: "C. Con chuột máy tính" },
  { id: 375, text: "Spam trong email là gì?", options: ["A. Thư quan trọng từ ngân hàng", "B. Thư từ bạn bè và gia đình", "C. Thư rác hoặc thư quảng cáo không mong muốn", "D. Thư nháp chưa gửi"], correctAnswer: "C. Thư rác hoặc thư quảng cáo không mong muốn" },
  { id: 376, text: "Hệ điều hành Android thường được sử dụng trên thiết bị nào?", options: ["A. Máy tính bảng và điện thoại thông minh (không phải của Apple)", "B. Máy tính để bàn của Apple (iMac)", "C. Máy tính xách tay MacBook", "D. Đồng hồ Apple Watch"], correctAnswer: "A. Máy tính bảng và điện thoại thông minh (không phải của Apple)" },
  { id: 377, text: "Mạng LAN là viết tắt của?", options: ["A. Large Area Network", "B. Local Area Network (Mạng cục bộ)", "C. Long Antenna Network", "D. Logical Access Node"], correctAnswer: "B. Local Area Network (Mạng cục bộ)" },
  { id: 378, text: "Chức năng chính của tường lửa (Firewall) là gì?", options: ["A. Tăng tốc độ Internet", "B. Lưu trữ mật khẩu", "C. Quét virus", "D. Ngăn chặn truy cập trái phép vào mạng máy tính"], correctAnswer: "D. Ngăn chặn truy cập trái phép vào mạng máy tính" },
  { id: 379, text: "Định dạng tệp .PDF thường dùng để làm gì?", options: ["A. Lưu trữ nhạc", "B. Chỉnh sửa ảnh", "C. Lập trình ứng dụng", "D. Chia sẻ tài liệu mà vẫn giữ nguyên định dạng"], correctAnswer: "D. Chia sẻ tài liệu mà vẫn giữ nguyên định dạng" },
  { id: 380, text: "Thuật ngữ \"Download\" có nghĩa là gì?", options: ["A. Gửi dữ liệu lên mạng", "B. Xóa dữ liệu khỏi máy tính", "C. Tải dữ liệu từ mạng về máy tính hoặc thiết bị", "D. In tài liệu"], correctAnswer: "C. Tải dữ liệu từ mạng về máy tính hoặc thiết bị" },
  { id: 381, text: "Thuật ngữ \"Upload\" có nghĩa là gì?", options: ["A. Tải dữ liệu từ mạng về máy", "B. Sao chép dữ liệu sang USB", "C. Cài đặt phần mềm", "D. Gửi dữ liệu từ máy tính hoặc thiết bị lên mạng"], correctAnswer: "D. Gửi dữ liệu từ máy tính hoặc thiết bị lên mạng" },
  { id: 382, text: "Đâu là một ví dụ về thiết bị lưu trữ di động?", options: ["A. Ổ cứng trong máy tính (HDD)", "B. USB Flash Drive", "C. Bộ xử lý (CPU)", "D. Màn hình máy tính"], correctAnswer: "B. USB Flash Drive" },
  { id: 383, text: "\"Cookie\" trong ngữ cảnh trình duyệt web là gì?", options: ["A. Một loại bánh quy", "B. Một loại virus máy tính", "C. Một tính năng trang trí cho website", "D. Các tệp nhỏ lưu trữ thông tin duyệt web của người dùng"], correctAnswer: "D. Các tệp nhỏ lưu trữ thông tin duyệt web của người dùng" },
  { id: 384, text: "Phần mềm nguồn mở (Open Source Software) là gì?", options: ["A. Phần mềm rất đắt tiền", "B. Phần mềm chỉ chạy được trên một hệ điều hành nhất định", "C. Phần mềm có mã nguồn công khai, cho phép mọi người xem, sửa đổi và chia sẻ", "D. Phần mềm đã lỗi thời"], correctAnswer: "C. Phần mềm có mã nguồn công khai, cho phép mọi người xem, sửa đổi và chia sẻ" },
  { id: 385, text: "Đâu là một nguy cơ khi sử dụng mạng Wi-Fi công cộng không bảo mật?", options: ["A. Tốc độ mạng chậm hơn", "B. Điện thoại nhanh hết pin hơn", "C. Không thể truy cập mạng xã hội", "D. Dữ liệu cá nhân có thể bị đánh cắp"], correctAnswer: "D. Dữ liệu cá nhân có thể bị đánh cắp" },
  { id: 386, text: "Học trực tuyến (E-learning) liên quan đến việc gì?", options: ["A. Mua sắm trên mạng", "B. Chơi game đối kháng", "C. Xem phim tại rạp", "D. Học tập thông qua các phương tiện điện tử và Internet"], correctAnswer: "D. Học tập thông qua các phương tiện điện tử và Internet" },
  { id: 387, text: "Định dạng tệp .MP3 thường chứa loại dữ liệu nào?", options: ["A. Văn bản", "B. Hình ảnh", "C. Âm thanh", "D. Video"], correctAnswer: "C. Âm thanh" },
  { id: 388, text: "Thuật ngữ \"Livestream\" có nghĩa là gì?", options: ["A. Ghi lại video để xem sau", "B. Chỉnh sửa video đã quay", "C. Tải video lên YouTube", "D. Phát video trực tiếp trên Internet"], correctAnswer: "D. Phát video trực tiếp trên Internet" },
  { id: 389, text: "Đâu là một ví dụ về ứng dụng nhắn tin tức thời?", options: ["A. Google Maps", "B. WhatsApp / Zalo", "C. Spotify", "D. Gmail"], correctAnswer: "B. WhatsApp / Zalo" },
  { id: 390, text: "Mục đích chính của việc cập nhật phần mềm là gì?", options: ["A. Làm chậm máy tính", "B. Thay đổi giao diện người dùng", "C. Vá lỗi bảo mật và cải thiện tính năng", "D. Giảm dung lượng lưu trữ"], correctAnswer: "C. Vá lỗi bảo mật và cải thiện tính năng" },
  { id: 391, text: "Trong địa chỉ email \"user@example.com\", phần nào là tên miền?", options: ["A. user", "B. @", "C. example.com", "D. .com"], correctAnswer: "C. example.com" },
  { id: 392, text: "Đâu là một ví dụ về công cụ tìm kiếm trên Internet?", options: ["A. Google", "B. Facebook", "C. Dropbox", "D. Twitter"], correctAnswer: "A. Google" },
  { id: 393, text: "Thực tế ảo (VR - Virtual Reality) là công nghệ mô phỏng môi trường nào?", options: ["A. Môi trường âm thanh nổi", "B. Môi trường mạng xã hội", "C. Môi trường ba chiều do máy tính tạo ra", "D. Môi trường làm việc văn phòng"], correctAnswer: "C. Môi trường ba chiều do máy tính tạo ra" },
  { id: 394, text: "Thuật ngữ \"ISP\" là viết tắt của?", options: ["A. Internal System Program", "B. International Software Protocol", "C. Integrated Security Platform", "D. Internet Service Provider (Nhà cung cấp dịch vụ Internet)"], correctAnswer: "D. Internet Service Provider (Nhà cung cấp dịch vụ Internet)" },
  { id: 395, text: "Đâu là một ví dụ về thiết bị xuất (Output device) cho máy tính?", options: ["A. Webcam", "B. Microphone", "C. Máy in", "D. Bàn phím"], correctAnswer: "C. Máy in" },
  { id: 396, text: "\"Phishing\" là hình thức tấn công mạng nhằm mục đích gì?", options: ["A. Làm hỏng phần cứng máy tính", "B. Tăng tốc độ kết nối mạng", "C. Cài đặt phần mềm diệt virus", "D. Lừa đảo để lấy thông tin nhạy cảm (mật khẩu, thẻ tín dụng)"], correctAnswer: "D. Lừa đảo để lấy thông tin nhạy cảm (mật khẩu, thẻ tín dụng)" },
  { id: 397, text: "Hệ thống số nhị phân (Binary System) sử dụng hai chữ số nào?", options: ["A. 0 và 1", "B. 1 và 2", "C. A và B", "D. 9 và 10"], correctAnswer: "A. 0 và 1" },
  { id: 398, text: "Công nghệ NFC (Near Field Communication) thường dùng để làm gì?", options: ["A. Kết nối Wi-Fi tầm xa", "B. Định vị GPS", "C. Truyền dữ liệu và thanh toán không tiếp xúc ở khoảng cách rất gần", "D. Xem video chất lượng cao"], correctAnswer: "C. Truyền dữ liệu và thanh toán không tiếp xúc ở khoảng cách rất gần" },
  { id: 399, text: "Phần mềm bảng tính (Spreadsheet) như Excel thường dùng để làm gì?", options: ["A. Soạn thảo văn bản dài", "B. Thiết kế đồ họa", "C. Tổ chức, phân tích và tính toán dữ liệu dạng bảng", "D. Chỉnh sửa video"], correctAnswer: "C. Tổ chức, phân tích và tính toán dữ liệu dạng bảng" },  { id: 400, text: "Thuật ngữ \"Cybersecurity\" (An ninh mạng) đề cập đến việc gì?", options: ["A. Thiết kế website hấp dẫn", "B. Phát triển trò chơi trực tuyến", "C. Quảng cáo sản phẩm trên mạng xã hội", "D. Bảo vệ hệ thống máy tính và mạng khỏi các mối đe dọa kỹ thuật số"], correctAnswer: "D. Bảo vệ hệ thống máy tính và mạng khỏi các mối đe dọa kỹ thuật số" },
  { id: 401, text: "Định dạng tệp .ZIP hoặc .RAR dùng để làm gì?", options: ["A. Nén nhiều tệp thành một tệp nhỏ hơn để dễ lưu trữ và chia sẻ", "B. Lưu trữ video độ phân giải cao", "C. Chạy ứng dụng phần mềm", "D. Lưu trữ cơ sở dữ liệu"], correctAnswer: "A. Nén nhiều tệp thành một tệp nhỏ hơn để dễ lưu trữ và chia sẻ" },
  { id: 402, text: "Thuật ngữ \"Thuật toán\" (Algorithm) trong khoa học máy tính là gì?", options: ["A. Một loại phần cứng máy tính", "B. Một ngôn ngữ lập trình", "C. Một loại virus", "D. Một tập hợp các quy tắc hoặc hướng dẫn để giải quyết một vấn đề hoặc hoàn thành một nhiệm vụ"], correctAnswer: "D. Một tập hợp các quy tắc hoặc hướng dẫn để giải quyết một vấn đề hoặc hoàn thành một nhiệm vụ" },
  { id: 403, text: "Điện toán đám mây (Cloud Computing) cho phép người dùng làm gì?", options: ["A. Chỉ lưu trữ dữ liệu trên máy tính cá nhân", "B. Tăng tốc độ in ấn", "C. Cải thiện chất lượng âm thanh loa", "D. Truy cập tài nguyên máy tính (lưu trữ, phần mềm) qua Internet"], correctAnswer: "D. Truy cập tài nguyên máy tính (lưu trữ, phần mềm) qua Internet" },
  { id: 404, text: "Mã hóa (Encryption) dữ liệu nhằm mục đích gì?", options: ["A. Làm cho dữ liệu dễ đọc hơn", "B. Xóa dữ liệu vĩnh viễn", "C. Tăng kích thước tệp dữ liệu", "D. Chuyển đổi dữ liệu thành một dạng mã để ngăn chặn truy cập trái phép"], correctAnswer: "D. Chuyển đổi dữ liệu thành một dạng mã để ngăn chặn truy cập trái phép" },
  { id: 405, text: "Podcast là gì?", options: ["A. Một tệp âm thanh hoặc video kỹ thuật số có thể tải xuống hoặc nghe/xem trực tuyến, thường theo dạng chuỗi", "B. Một chương trình truyền hình trực tiếp", "C. Một loại game di động", "D. Một công cụ chỉnh sửa ảnh"], correctAnswer: "A. Một tệp âm thanh hoặc video kỹ thuật số có thể tải xuống hoặc nghe/xem trực tuyến, thường theo dạng chuỗi" },
  { id: 406, text: "HTML là viết tắt của?", options: ["A. High Tech Markup Language", "B. Home Tool Management Logic", "C. HyperText Markup Language (Ngôn ngữ đánh dấu siêu văn bản)", "D. Hyperlink Transfer Method Language"], correctAnswer: "C. HyperText Markup Language (Ngôn ngữ đánh dấu siêu văn bản)" },
  { id: 407, text: "Đâu là một ví dụ về thiết bị đeo thông minh (Wearable device)?", options: ["A. Máy tính để bàn", "B. Máy chiếu", "C. Ổ cứng gắn ngoài", "D. Đồng hồ thông minh (Smartwatch)"], correctAnswer: "D. Đồng hồ thông minh (Smartwatch)" },
  { id: 408, text: "Mục đích của việc sử dụng \"Giỏ hàng\" (Shopping Cart) trên trang web thương mại điện tử là gì?", options: ["A. Lưu trữ mật khẩu", "B. So sánh giá sản phẩm", "C. Đọc đánh giá sản phẩm", "D. Tạm thời giữ các mặt hàng bạn muốn mua trước khi thanh toán"], correctAnswer: "D. Tạm thời giữ các mặt hàng bạn muốn mua trước khi thanh toán" },
  { id: 409, text: "IoT (Internet of Things) là khái niệm chỉ việc gì?", options: ["A. Một mạng xã hội mới", "B. Một loại tiền điện tử", "C. Kết nối các thiết bị vật lý hàng ngày với Internet", "D. Một dịch vụ lưu trữ đám mây"], correctAnswer: "C. Kết nối các thiết bị vật lý hàng ngày với Internet" },
  { id: 410, text: "Đâu là một phương pháp xác thực hai yếu tố (Two-Factor Authentication)?", options: ["A. Chỉ sử dụng mật khẩu", "B. Sử dụng tên đăng nhập", "C. Sử dụng mật khẩu và mã gửi đến điện thoại", "D. Sử dụng câu hỏi bí mật"], correctAnswer: "C. Sử dụng mật khẩu và mã gửi đến điện thoại" },
  { id: 411, text: "Đâu là một rủi ro của việc chia sẻ quá nhiều thông tin cá nhân trên mạng?", options: ["A. Nhận được nhiều lời khen", "B. Tài khoản mạng xã hội trở nên phổ biến hơn", "C. Máy tính chạy nhanh hơn", "D. Bị đánh cắp danh tính hoặc lừa đảo"], correctAnswer: "D. Bị đánh cắp danh tính hoặc lừa đảo" },
  { id: 412, text: "Bookmark (Đánh dấu trang) trong trình duyệt web dùng để làm gì?", options: ["A. Xóa lịch sử duyệt web", "B. Chặn quảng cáo", "C. Lưu lại địa chỉ các trang web yêu thích để truy cập nhanh", "D. Dịch trang web sang ngôn ngữ khác"], correctAnswer: "C. Lưu lại địa chỉ các trang web yêu thích để truy cập nhanh" },
  { id: 413, text: "Gigabyte (GB) là đơn vị dùng để đo lường gì?", options: ["A. Dung lượng lưu trữ dữ liệu", "B. Tốc độ xử lý của CPU", "C. Độ phân giải màn hình", "D. Tốc độ kết nối Internet"], correctAnswer: "A. Dung lượng lưu trữ dữ liệu" },
  { id: 414, text: "Thanh địa chỉ (Address Bar) trong trình duyệt web dùng để làm gì?", options: ["A. Tìm kiếm từ khóa trên trang web hiện tại", "B. Hiển thị các tab đang mở", "C. Điều chỉnh âm lượng video", "D. Nhập địa chỉ (URL) của trang web muốn truy cập"], correctAnswer: "D. Nhập địa chỉ (URL) của trang web muốn truy cập" },
  { id: 415, text: "Phần mềm trình chiếu (Presentation Software) như PowerPoint dùng để làm gì?", options: ["A. Viết mã lập trình", "B. Quản lý email", "C. Nghe nhạc", "D. Tạo các bài thuyết trình với văn bản, hình ảnh, hiệu ứng"], correctAnswer: "D. Tạo các bài thuyết trình với văn bản, hình ảnh, hiệu ứng" },
  { id: 416, text: "Sao chép (Copy) và Dán (Paste) là thao tác dùng để làm gì?", options: ["A. Xóa tệp tin", "B. Đổi tên tệp tin", "C. Tạo bản sao của văn bản hoặc tệp tin và đặt nó ở vị trí khác", "D. Nén tệp tin"], correctAnswer: "C. Tạo bản sao của văn bản hoặc tệp tin và đặt nó ở vị trí khác" },
  { id: 417, text: "Đâu là một ví dụ về hệ điều hành cho máy tính?", options: ["A. Windows / macOS / Linux", "B. Microsoft Office", "C. Google Chrome", "D. Adobe Photoshop"], correctAnswer: "A. Windows / macOS / Linux" },
  { id: 418, text: "Biểu tượng \"Thùng rác\" (Recycle Bin/Trash) trên máy tính chứa gì?", options: ["A. Các tệp tin hệ thống quan trọng", "B. Các ứng dụng đã cài đặt", "C. Các tệp tin và thư mục đã bị xóa tạm thời", "D. Các bản sao lưu dữ liệu"], correctAnswer: "C. Các tệp tin và thư mục đã bị xóa tạm thời" },
  { id: 419, text: "Tên miền \".gov\" thường được sử dụng bởi tổ chức nào?", options: ["A. Cơ quan chính phủ", "B. Tổ chức giáo dục", "C. Công ty thương mại", "D. Tổ chức phi lợi nhuận"], correctAnswer: "A. Cơ quan chính phủ" },
  { id: 420, text: "Tên miền \".edu\" thường được sử dụng bởi tổ chức nào?", options: ["A. Cơ quan chính phủ", "B. Công ty mạng", "C. Tổ chức quân sự", "D. Tổ chức giáo dục (trường học, đại học)"], correctAnswer: "D. Tổ chức giáo dục (trường học, đại học)" },
  { id: 421, text: "Tên miền \".org\" thường được sử dụng bởi tổ chức nào?", options: ["A. Công ty thương mại", "B. Cá nhân", "C. Các tổ chức (thường là phi lợi nhuận)", "D. Cơ quan chính phủ"], correctAnswer: "C. Các tổ chức (thường là phi lợi nhuận)" },
  { id: 422, text: "Selfie là gì?", options: ["A. Một bức ảnh phong cảnh", "B. Một video hướng dẫn nấu ăn", "C. Một bức ảnh tự chụp bản thân, thường bằng điện thoại hoặc webcam", "D. Một bài viết trên blog"], correctAnswer: "C. Một bức ảnh tự chụp bản thân, thường bằng điện thoại hoặc webcam" },
  { id: 423, text: "Hashtag (#) trên mạng xã hội dùng để làm gì?", options: ["A. Đánh dấu và phân loại nội dung theo chủ đề", "B. Nhắc đến một người dùng khác", "C. Tạo liên kết đến trang web khác", "D. Thể hiện cảm xúc"], correctAnswer: "A. Đánh dấu và phân loại nội dung theo chủ đề" },
  { id: 424, text: "Emoji là gì?", options: ["A. Một loại mật khẩu", "B. Một ứng dụng chỉnh sửa ảnh", "C. Các biểu tượng hình ảnh nhỏ dùng để thể hiện cảm xúc hoặc ý tưởng", "D. Một đơn vị tiền tệ kỹ thuật số"], correctAnswer: "C. Các biểu tượng hình ảnh nhỏ dùng để thể hiện cảm xúc hoặc ý tưởng" },
  { id: 425, text: "Thuật ngữ \"Big Data\" (Dữ liệu lớn) đề cập đến điều gì?", options: ["A. Một tệp tin có kích thước rất lớn", "B. Một loại cơ sở dữ liệu quan hệ", "C. Việc sao lưu dữ liệu thường xuyên", "D. Các tập hợp dữ liệu cực lớn và phức tạp, đòi hỏi công cụ xử lý đặc biệt"], correctAnswer: "D. Các tập hợp dữ liệu cực lớn và phức tạp, đòi hỏi công cụ xử lý đặc biệt" },
  { id: 426, text: "API (Application Programming Interface) là gì?", options: ["A. Một ứng dụng di động phổ biến", "B. Một ngôn ngữ lập trình mới", "C. Một loại phần cứng mạng", "D. Một tập hợp các quy tắc và giao thức cho phép các phần mềm khác nhau giao tiếp với nhau"], correctAnswer: "D. Một tập hợp các quy tắc và giao thức cho phép các phần mềm khác nhau giao tiếp với nhau" },
  { id: 427, text: "In 3D là quá trình gì?", options: ["A. Tạo ra vật thể ba chiều từ một mô hình kỹ thuật số bằng cách đắp lớp vật liệu", "B. In tài liệu màu trên giấy", "C. Xem phim 3D tại rạp", "D. Thiết kế logo 3D trên máy tính"], correctAnswer: "A. Tạo ra vật thể ba chiều từ một mô hình kỹ thuật số bằng cách đắp lớp vật liệu" },
  { id: 428, text: "Đâu là một lợi ích của việc sử dụng chữ ký số (Digital Signature)?", options: ["A. Làm cho tài liệu trông đẹp hơn", "B. Tăng tốc độ gửi email", "C. Xác thực nguồn gốc và tính toàn vẹn của tài liệu điện tử", "D. Giảm kích thước tệp tài liệu"], correctAnswer: "C. Xác thực nguồn gốc và tính toàn vẹn của tài liệu điện tử" },
  { id: 429, text: "Drone (Máy bay không người lái) thường được điều khiển như thế nào?", options: ["A. Bằng suy nghĩ", "B. Chỉ bay theo lộ trình định sẵn", "C. Bằng giọng nói", "D. Từ xa bằng bộ điều khiển hoặc phần mềm"], correctAnswer: "D. Từ xa bằng bộ điều khiển hoặc phần mềm" },
  { id: 430, text: "Thuật ngữ \"Clickbait\" thường dùng để mô tả điều gì?", options: ["A. Một liên kết an toàn và đáng tin cậy", "B. Một loại quảng cáo bật lên (pop-up)", "C. Nội dung (thường là tiêu đề) gây tò mò quá mức để thu hút lượt nhấp chuột, nhưng nội dung bên trong thường không đáp ứng kỳ vọng", "D. Một nút bấm để mua hàng trực tuyến"], correctAnswer: "C. Nội dung (thường là tiêu đề) gây tò mò quá mức để thu hút lượt nhấp chuột, nhưng nội dung bên trong thường không đáp ứng kỳ vọng" },
  { id: 431, text: "Deepfake là công nghệ sử dụng AI để làm gì?", options: ["A. Phân tích dữ liệu lớn", "B. Dịch thuật ngôn ngữ tự động", "C. Tự động lái xe ô tô", "D. Tạo ra các video hoặc hình ảnh giả mạo, ghép mặt người này vào người khác một cách thuyết phục"], correctAnswer: "D. Tạo ra các video hoặc hình ảnh giả mạo, ghép mặt người này vào người khác một cách thuyết phục" },
  { id: 432, text: "Xác thực sinh trắc học (Biometric Authentication) sử dụng yếu tố nào để nhận dạng?", options: ["A. Mật khẩu và mã PIN", "B. Thẻ từ và thẻ chip", "C. Câu hỏi bí mật", "D. Các đặc điểm sinh học duy nhất của cá nhân (vân tay, khuôn mặt, mống mắt)"], correctAnswer: "D. Các đặc điểm sinh học duy nhất của cá nhân (vân tay, khuôn mặt, mống mắt)" },
  { id: 433, text: "Đâu là một ví dụ về dịch vụ streaming nhạc?", options: ["A. Netflix", "B. Spotify / Apple Music / Zing MP3", "C. Google Drive", "D. Kindle"], correctAnswer: "B. Spotify / Apple Music / Zing MP3" },
  { id: 434, text: "Đâu là một ví dụ về dịch vụ streaming phim và chương trình TV?", options: ["A. Spotify", "B. Netflix / Hulu / HBO Max", "C. Dropbox", "D. Audible"], correctAnswer: "B. Netflix / Hulu / HBO Max" },
  { id: 435, text: "Thuật ngữ \"Bandwidth\" (Băng thông) trong mạng máy tính thường đề cập đến điều gì?", options: ["A. Độ trễ của kết nối mạng", "B. Số lượng thiết bị tối đa có thể kết nối vào mạng", "C. Lượng dữ liệu tối đa có thể truyền qua kết nối mạng trong một khoảng thời gian nhất định", "D. Cường độ tín hiệu Wi-Fi"], correctAnswer: "C. Lượng dữ liệu tối đa có thể truyền qua kết nối mạng trong một khoảng thời gian nhất định" },
  { id: 436, text: "Độ phân giải màn hình (Screen Resolution) được đo bằng đơn vị nào?", options: ["A. Gigahertz (GHz)", "B. Pixel (Điểm ảnh)", "C. Megabyte (MB)", "D. Decibel (dB)"], correctAnswer: "B. Pixel (Điểm ảnh)" },
  { id: 437, text: "VPN (Virtual Private Network) được sử dụng để làm gì?", options: ["A. Tạo một kết nối mạng riêng ảo, an toàn qua một mạng công cộng (như Internet)", "B. Tăng tốc độ tải tệp", "C. Quản lý mật khẩu", "D. Chặn tất cả quảng cáo"], correctAnswer: "A. Tạo một kết nối mạng riêng ảo, an toàn qua một mạng công cộng (như Internet)" },
  { id: 438, text: "Screenshot (Chụp ảnh màn hình) là thao tác gì?", options: ["A. Quay video màn hình", "B. In nội dung trên màn hình ra giấy", "C. Chia sẻ màn hình với người khác", "D. Chụp lại hình ảnh đang hiển thị trên màn hình máy tính hoặc điện thoại"], correctAnswer: "D. Chụp lại hình ảnh đang hiển thị trên màn hình máy tính hoặc điện thoại" },
  { id: 439, text: "Thuật ngữ \"Bug\" trong phần mềm có nghĩa là gì?", options: ["A. Một tính năng mới", "B. Một bản cập nhật bảo mật", "C. Một lỗi hoặc khiếm khuyết trong chương trình máy tính", "D. Một tài liệu hướng dẫn"], correctAnswer: "C. Một lỗi hoặc khiếm khuyết trong chương trình máy tính" },
  { id: 440, text: "Thuật ngữ \"Digital Footprint\" (Dấu chân kỹ thuật số) là gì?", options: ["A. Kích thước giày của bạn khi mua online", "B. Một ứng dụng theo dõi sức khỏe", "C. Chữ ký điện tử của bạn", "D. Dấu vết dữ liệu bạn để lại khi hoạt động trực tuyến"], correctAnswer: "D. Dấu vết dữ liệu bạn để lại khi hoạt động trực tuyến" },
  { id: 441, text: "Một trình quản lý mật khẩu (Password Manager) giúp bạn làm gì?", options: ["A. Tạo ra các mật khẩu yếu", "B. Chia sẻ mật khẩu công khai", "C. Lưu trữ và quản lý an toàn nhiều mật khẩu phức tạp", "D. Quên mật khẩu dễ dàng hơn"], correctAnswer: "C. Lưu trữ và quản lý an toàn nhiều mật khẩu phức tạp" },
  { id: 442, text: "Đâu là một lợi ích của việc sử dụng phần mềm diệt virus?", options: ["A. Bảo vệ máy tính khỏi phần mềm độc hại", "B. Làm máy tính nóng hơn", "C. Tăng dung lượng RAM", "D. Cải thiện tốc độ đánh máy"], correctAnswer: "A. Bảo vệ máy tính khỏi phần mềm độc hại" },
  { id: 443, text: "Metadata (Siêu dữ liệu) của một tệp tin ảnh có thể chứa thông tin gì?", options: ["A. Nội dung văn bản trong ảnh", "B. Ngày chụp, loại máy ảnh, vị trí (nếu có)", "C. Danh sách bạn bè trên mạng xã hội", "D. Lịch sử duyệt web"], correctAnswer: "B. Ngày chụp, loại máy ảnh, vị trí (nếu có)" },
  { id: 444, text: "Giao diện người dùng đồ họa (GUI - Graphical User Interface) cho phép người dùng tương tác với máy tính bằng cách nào?", options: ["A. Thông qua các yếu tố đồ họa như biểu tượng, cửa sổ, nút bấm", "B. Chỉ bằng các dòng lệnh văn bản", "C. Bằng tín hiệu sóng não", "D. Chỉ bằng giọng nói"], correctAnswer: "A. Thông qua các yếu tố đồ họa như biểu tượng, cửa sổ, nút bấm" },
  { id: 445, text: "Tốc độ làm tươi (Refresh Rate) của màn hình, đo bằng Hertz (Hz), ảnh hưởng đến điều gì?", options: ["A. Độ sáng của màn hình", "B. Mức tiêu thụ điện năng", "C. Độ mượt của hình ảnh chuyển động", "D. Số lượng màu sắc hiển thị"], correctAnswer: "C. Độ mượt của hình ảnh chuyển động" },
  { id: 446, text: "Đâu là một ví dụ về phần mềm độc hại tống tiền (Ransomware)?", options: ["A. Phần mềm khóa dữ liệu người dùng và đòi tiền chuộc để mở khóa", "B. Phần mềm hiển thị quảng cáo không mong muốn", "C. Phần mềm theo dõi hoạt động người dùng", "D. Phần mềm giúp tăng tốc máy tính"], correctAnswer: "A. Phần mềm khóa dữ liệu người dùng và đòi tiền chuộc để mở khóa" },
  { id: 447, text: "Công nghệ nhận dạng ký tự quang học (OCR - Optical Character Recognition) dùng để làm gì?", options: ["A. Nhận dạng khuôn mặt", "B. Nhận dạng giọng nói", "C. Dịch ngôn ngữ", "D. Chuyển đổi hình ảnh văn bản (từ ảnh quét hoặc ảnh chụp) thành văn bản có thể chỉnh sửa được trên máy tính"], correctAnswer: "D. Chuyển đổi hình ảnh văn bản (từ ảnh quét hoặc ảnh chụp) thành văn bản có thể chỉnh sửa được trên máy tính" },
  { id: 448, text: "Thuật ngữ \"Dark Web\" đề cập đến phần nào của Internet?", options: ["A. Các trang web có giao diện tối", "B. Các diễn đàn dành cho game thủ", "C. Một phần của Internet không được lập chỉ mục bởi các công cụ tìm kiếm thông thường, cần phần mềm đặc biệt để truy cập và thường liên quan đến các hoạt động ẩn danh hoặc bất hợp pháp", "D. Mạng nội bộ của một công ty"], correctAnswer: "C. Một phần của Internet không được lập chỉ mục bởi các công cụ tìm kiếm thông thường, cần phần mềm đặc biệt để truy cập và thường liên quan đến các hoạt động ẩn danh hoặc bất hợp pháp" },
  { id: 449, text: "Blockchain là công nghệ nền tảng của loại tài sản kỹ thuật số nào?", options: ["A. Điểm thưởng khách hàng thân thiết", "B. Cổ phiếu công ty", "C. Tiền điện tử (Cryptocurrency) như Bitcoin", "D. Tài khoản game trực tuyến"], correctAnswer: "C. Tiền điện tử (Cryptocurrency) như Bitcoin" },  { id: 450, text: "Công nghệ số là gì?", options: ["A. Là sự biến đổi và áp dụng các tiến bộ công nghệ để thay đổi cách thức hoạt động từ truyền thống sang mô hình tối ưu hóa kỹ thuật số", "B. Là việc sử dụng máy tính để tính toán", "C. Chỉ là việc sử dụng điện thoại thông minh", "D. Là việc gửi email và lướt web"], correctAnswer: "A. Là sự biến đổi và áp dụng các tiến bộ công nghệ để thay đổi cách thức hoạt động từ truyền thống sang mô hình tối ưu hóa kỹ thuật số" },
  { id: 451, text: "Chuyển đổi số là quá trình thay đổi ______ và toàn diện của cá nhân, tổ chức dựa trên các công nghệ số.", options: ["A. Từ từ", "B. Tổng thể", "C. Một phần", "D. Ngẫu nhiên"], correctAnswer: "B. Tổng thể" },
  { id: 452, text: "Đâu KHÔNG phải là một công nghệ số nền tảng cho chuyển đổi số?", options: ["A. Dữ liệu lớn (Big Data)", "B. Internet vạn vật (IoT)", "C. Điện toán đám mây (Cloud Computing)", "D. Máy đánh chữ"], correctAnswer: "D. Máy đánh chữ" },
  { id: 453, text: "Mục tiêu chính của chuyển đổi số là gì?", options: ["A. Tăng số lượng nhân viên", "B. Quay trở lại phương thức làm việc truyền thống", "C. Nâng cao hiệu quả hoạt động, tăng khả năng cạnh tranh và tạo ra giá trị mới", "D. Giảm tương tác với khách hàng"], correctAnswer: "C. Nâng cao hiệu quả hoạt động, tăng khả năng cạnh tranh và tạo ra giá trị mới" },
  { id: 454, text: "Chuyển đổi số diễn ra ở những lĩnh vực nào trong đời sống và kinh tế?", options: ["A. Chỉ trong lĩnh vực công nghệ thông tin", "B. Chỉ trong các doanh nghiệp lớn", "C. Hầu hết các lĩnh vực", "D. Chỉ trong các cơ quan nhà nước"], correctAnswer: "C. Hầu hết các lĩnh vực" },
  { id: 455, text: "Bản chất của chuyển đổi số là gì?", options: ["A. Chỉ đơn thuần là mua sắm công nghệ mới", "B. Chỉ tập trung vào việc tự động hóa", "C. Là việc sử dụng mạng xã hội", "D. Là quá trình tái cơ cấu toàn diện về cách thức tổ chức hoạt động và tư duy"], correctAnswer: "D. Là quá trình tái cơ cấu toàn diện về cách thức tổ chức hoạt động và tư duy" },
  { id: 456, text: "Yếu tố quan trọng để chuyển đổi số thành công là gì?", options: ["A. Có ngân sách thật lớn", "B. Sao chép mô hình của người khác", "C. Chỉ cần có phần mềm hiện đại", "D. Sự cam kết từ tầng lãnh đạo và sự hỗ trợ từ toàn bộ tổ chức"], correctAnswer: "D. Sự cam kết từ tầng lãnh đạo và sự hỗ trợ từ toàn bộ tổ chức" },
  { id: 457, text: "Công nghệ số giúp kết nối vạn vật thông qua internet được gọi là gì?", options: ["A. Big Data", "B. AI", "C. IoT (Internet of Things)", "D. Blockchain"], correctAnswer: "C. IoT (Internet of Things)" },
  { id: 458, text: "Việc phân tích và xử lý các tập dữ liệu cực lớn và phức tạp được gọi là gì?", options: ["A. Dữ liệu lớn (Big Data)", "B. Điện toán đám mây", "C. Trí tuệ nhân tạo (AI)", "D. Thực tế ảo (VR)"], correctAnswer: "A. Dữ liệu lớn (Big Data)" },
  { id: 459, text: "Lưu trữ và truy cập dữ liệu, ứng dụng qua internet thay vì trên máy chủ vật lý gọi là gì?", options: ["A. Mạng xã hội", "B. Thương mại điện tử", "C. Điện toán đám mây (Cloud Computing)", "D. Chữ ký số"], correctAnswer: "C. Điện toán đám mây (Cloud Computing)" },
  { id: 460, text: "Công nghệ mô phỏng quá trình tư duy và học hỏi của con người bằng máy móc được gọi là gì?", options: ["A. IoT", "B. Big Data", "C. Trí tuệ nhân tạo (AI)", "D. Công nghệ sinh học"], correctAnswer: "C. Trí tuệ nhân tạo (AI)" },
  { id: 461, text: "Công nghệ chuỗi khối, giúp giao dịch an toàn và minh bạch, được gọi là gì?", options: ["A. Điện toán đám mây", "B. IoT", "C. Blockchain", "D. Big Data"], correctAnswer: "C. Blockchain" },
  { id: 462, text: "Chuyển đổi số trong một doanh nghiệp có thể giúp:", options: ["A. Giảm tương tác với khách hàng", "B. Tăng chi phí hoạt động", "C. Tối ưu hóa quy trình làm việc và tăng cường hiệu suất", "D. Chỉ phục vụ cho mục đích quảng cáo"], correctAnswer: "C. Tối ưu hóa quy trình làm việc và tăng cường hiệu suất" },
  { id: 463, text: "Công dân số là gì?", options: ["A. Người chỉ sử dụng điện thoại", "B. Người sống hoàn toàn không sử dụng công nghệ", "C. Công dân có khả năng sử dụng công nghệ số để tham gia vào đời sống kinh tế, xã hội", "D. Người chỉ làm việc trong ngành công nghệ thông tin"], correctAnswer: "C. Công dân có khả năng sử dụng công nghệ số để tham gia vào đời sống kinh tế, xã hội" },
  { id: 464, text: "Chính phủ số là gì?", options: ["A. Là chính phủ chỉ sử dụng máy tính", "B. Là chính phủ hoạt động hiệu quả, minh bạch dựa trên nền tảng công nghệ số", "C. Là chính phủ không tương tác với người dân qua mạng", "D. Là chính phủ chỉ cung cấp dịch vụ trực tiếp"], correctAnswer: "B. Là chính phủ hoạt động hiệu quả, minh bạch dựa trên nền tảng công nghệ số" },
  { id: 465, text: "Kinh tế số là gì?", options: ["A. Là nền kinh tế chỉ dựa vào tiền mặt", "B. Là nền kinh tế mà hoạt động sản xuất, kinh doanh dựa chủ yếu vào công nghệ số", "C. Là nền kinh tế không có sự cạnh tranh", "D. Là nền kinh tế chỉ có các cửa hàng truyền thống"], correctAnswer: "B. Là nền kinh tế mà hoạt động sản xuất, kinh doanh dựa chủ yếu vào công nghệ số" },
  { id: 466, text: "Đâu là ví dụ về chuyển đổi số trong giáo dục?", options: ["A. Chỉ sử dụng sách giáo khoa truyền thống", "B. Xây dựng các lớp học trực tuyến, nền tảng học tập số", "C. Giảm số lượng giáo viên", "D. Không cho học sinh sử dụng máy tính"], correctAnswer: "B. Xây dựng các lớp học trực tuyến, nền tảng học tập số" },
  { id: 467, text: "Đâu là ví dụ về chuyển đổi số trong y tế?", options: ["A. Chỉ khám chữa bệnh tại bệnh viện", "B. Áp dụng hồ sơ bệnh án điện tử, khám chữa bệnh từ xa", "C. Giảm số lượng bác sĩ", "D. Không sử dụng thiết bị y tế hiện đại"], correctAnswer: "B. Áp dụng hồ sơ bệnh án điện tử, khám chữa bệnh từ xa" },
  { id: 468, text: "Đâu là ví dụ về chuyển đổi số trong du lịch?", options: ["A. Chỉ bán vé trực tiếp tại quầy", "B. Phát triển ứng dụng đặt tour, đặt phòng trực tuyến, trải nghiệm thực tế ảo", "C. Giảm số lượng khách du lịch", "D. Không quảng bá du lịch trên mạng"], correctAnswer: "B. Phát triển ứng dụng đặt tour, đặt phòng trực tuyến, trải nghiệm thực tế ảo" },
  { id: 469, text: "Lợi ích của chuyển đổi số đối với người dân là gì?", options: ["A. Phải đi lại nhiều hơn để làm thủ tục", "B. Tiếp cận dịch vụ công nhanh chóng, tiện lợi, minh bạch hơn", "C. Tốn kém nhiều chi phí hơn", "D. Bị hạn chế thông tin"], correctAnswer: "B. Tiếp cận dịch vụ công nhanh chóng, tiện lợi, minh bạch hơn" },
  { id: 470, text: "Chuyển đổi số giúp doanh nghiệp nhỏ và vừa như thế nào?", options: ["A. Khó khăn hơn trong việc tiếp cận khách hàng", "B. Giúp tối ưu hóa quy trình, giảm chi phí và mở rộng thị trường", "C. Phải đóng cửa do cạnh tranh công nghệ", "D. Không có lợi ích gì"], correctAnswer: "B. Giúp tối ưu hóa quy trình, giảm chi phí và mở rộng thị trường" },
  { id: 471, text: "Thành phần cốt lõi của chuyển đổi số bao gồm: Công nghệ, ______ và Tổ chức/Quy trình.", options: ["A. Con người", "B. Tiền bạc", "C. Máy móc", "D. Văn phòng"], correctAnswer: "A. Con người" },
  { id: 472, text: "Khi nói về chuyển đổi số, yếu tố \"Con người\" đề cập đến điều gì?", options: ["A. Chỉ số lượng nhân viên", "B. Sự thay đổi về tư duy, kỹ năng và văn hóa làm việc của con người", "C. Việc thay thế con người bằng máy móc", "D. Giảm vai trò của con người"], correctAnswer: "B. Sự thay đổi về tư duy, kỹ năng và văn hóa làm việc của con người" },
  { id: 473, text: "Yếu tố \"Tổ chức/Quy trình\" trong chuyển đổi số đề cập đến điều gì?", options: ["A. Chỉ cấu trúc bộ máy tổ chức", "B. Việc tái thiết kế các quy trình làm việc để phù hợp với môi trường số", "C. Giữ nguyên quy trình làm việc cũ", "D. Tăng thêm các bước thủ tục"], correctAnswer: "B. Việc tái thiết kế các quy trình làm việc để phù hợp với môi trường số" },
  { id: 474, text: "Một trong những thách thức khi thực hiện chuyển đổi số là gì?", options: ["A. Quá dễ dàng để thực hiện", "B. Sự thiếu sẵn sàng về kỹ năng số và tâm lý ngại thay đổi", "C. Chi phí ban đầu quá thấp", "D. Có quá nhiều chuyên gia hỗ trợ"], correctAnswer: "B. Sự thiếu sẵn sàng về kỹ năng số và tâm lý ngại thay đổi" },
  { id: 475, text: "Lợi ích lớn nhất của mua sắm trực tuyến là gì?", options: ["A. Phải di chuyển đến cửa hàng", "B. Tiết kiệm thời gian, linh hoạt về thời gian và địa điểm mua sắm", "C. Bị giới hạn lựa chọn sản phẩm", "D. Khó so sánh giá cả"], correctAnswer: "B. Tiết kiệm thời gian, linh hoạt về thời gian và địa điểm mua sắm" },
  { id: 476, text: "Khi mua sắm trực tuyến, bạn có thể dễ dàng so sánh điều gì giữa các cửa hàng khác nhau?", options: ["A. Chỉ hình ảnh sản phẩm", "B. Số lượng nhân viên bán hàng", "C. Diện tích cửa hàng", "D. Giá cả và chất lượng sản phẩm thông qua đánh giá của người mua trước"], correctAnswer: "D. Giá cả và chất lượng sản phẩm thông qua đánh giá của người mua trước" },
  { id: 477, text: "Hình thức thanh toán nào KHÔNG phải là thanh toán không dùng tiền mặt?", options: ["A. Chuyển khoản ngân hàng", "B. Thanh toán bằng ví điện tử", "C. Thanh toán bằng tiền mặt", "D. Thanh toán bằng thẻ tín dụng/ghi nợ"], correctAnswer: "C. Thanh toán bằng tiền mặt" },
  { id: 478, text: "Lợi ích của thanh toán không dùng tiền mặt đối với người dân là gì?", options: ["A. Tiện lợi, an toàn, nhanh chóng và dễ dàng quản lý chi tiêu", "B. Mất nhiều thời gian hơn", "C. Khó kiểm soát số dư tài khoản", "D. Phải mang theo nhiều tiền mặt"], correctAnswer: "A. Tiện lợi, an toàn, nhanh chóng và dễ dàng quản lý chi tiêu" },
  { id: 479, text: "Lợi ích của thanh toán không dùng tiền mặt đối với nền kinh tế là gì?", options: ["A. Tăng chi phí in ấn tiền", "B. Khó thu hút vốn đầu tư", "C. Hạn chế lạm phát, tăng cường hiệu quả phòng chống tham nhũng", "D. Giảm sự minh bạch trong giao dịch"], correctAnswer: "C. Hạn chế lạm phát, tăng cường hiệu quả phòng chống tham nhũng" },
  { id: 480, text: "Học trực tuyến mang lại lợi ích gì về thời gian và địa điểm?", options: ["A. Linh hoạt về thời gian và địa điểm học tập", "B. Chỉ học được vào giờ cố định tại trường", "C. Phải đến trung tâm học", "D. Bị giới hạn địa lý"], correctAnswer: "A. Linh hoạt về thời gian và địa điểm học tập" },
  { id: 481, text: "Học trực tuyến giúp tiết kiệm chi phí nào?", options: ["A. Chi phí đăng ký học", "B. Chi phí mua sách", "C. Chi phí thuê gia sư", "D. Chi phí đi lại, ăn ở (đối với học viên ở xa)"], correctAnswer: "D. Chi phí đi lại, ăn ở (đối với học viên ở xa)" },
  { id: 482, text: "Khi học trực tuyến, người học có thể tiếp cận nguồn tài liệu như thế nào?", options: ["A. Phong phú và đa dạng từ nhiều nguồn khác nhau trên internet", "B. Hạn chế tài liệu", "C. Chỉ tài liệu do giáo viên cung cấp", "D. Không có tài liệu tham khảo"], correctAnswer: "A. Phong phú và đa dạng từ nhiều nguồn khác nhau trên internet" },
  { id: 483, text: "Học trực tuyến có thể giúp rèn luyện kỹ năng gì?", options: ["A. Kỹ năng ghi chép truyền thống", "B. Kỹ năng sử dụng bảng đen", "C. Kỹ năng đọc sách giấy", "D. Kỹ năng làm việc nhóm và giao tiếp số"], correctAnswer: "D. Kỹ năng làm việc nhóm và giao tiếp số" },
  { id: 484, text: "Việc sử dụng công nghệ số trong giao thông (ví dụ: bản đồ số, ứng dụng gọi xe) mang lại lợi ích gì?", options: ["A. Tắc nghẽn giao thông hơn", "B. Khó tìm đường", "C. Di chuyển thuận tiện, tiết kiệm thời gian và chi phí", "D. Tăng chi phí di chuyển"], correctAnswer: "C. Di chuyển thuận tiện, tiết kiệm thời gian và chi phí" },
  { id: 485, text: "Ứng dụng công nghệ số trong y tế giúp người dân như thế nào?", options: ["A. Khó tiếp cận dịch vụ y tế", "B. Phải chờ đợi lâu hơn", "C. Dễ dàng đặt lịch khám, tư vấn sức khỏe từ xa", "D. Chỉ khám được ở bệnh viện lớn"], correctAnswer: "C. Dễ dàng đặt lịch khám, tư vấn sức khỏe từ xa" },
  { id: 486, text: "Công nghệ số giúp hoạt động giải trí của con người trở nên đa dạng hơn như thế nào?", options: ["A. Tiếp cận phim ảnh, âm nhạc, trò chơi trực tuyến dễ dàng", "B. Chỉ có thể xem TV", "C. Giới hạn các loại hình giải trí", "D. Phải mua đĩa CD/DVD"], correctAnswer: "A. Tiếp cận phim ảnh, âm nhạc, trò chơi trực tuyến dễ dàng" },
  { id: 487, text: "Việc đọc sách báo trên thiết bị điện tử thay vì sách báo giấy mang lại lợi ích gì?", options: ["A. Tốn kém nhiều không gian lưu trữ", "B. Chất lượng hình ảnh kém", "C. Thuận tiện mang theo, dễ dàng tìm kiếm thông tin", "D. Khó chia sẻ thông tin"], correctAnswer: "C. Thuận tiện mang theo, dễ dàng tìm kiếm thông tin" },
  { id: 488, text: "Công nghệ số giúp kết nối và giao tiếp giữa mọi người như thế nào?", options: ["A. Nhanh chóng, dễ dàng qua mạng xã hội, ứng dụng nhắn tin, gọi video", "B. Khó khăn hơn trong việc liên lạc", "C. Chỉ liên lạc được ở khoảng cách gần", "D. Tốn nhiều chi phí liên lạc"], correctAnswer: "A. Nhanh chóng, dễ dàng qua mạng xã hội, ứng dụng nhắn tin, gọi video" },
  { id: 489, text: "Công nghệ số góp phần vào việc bảo vệ môi trường như thế nào?", options: ["A. Tăng lượng rác thải điện tử", "B. Tiêu thụ nhiều năng lượng hơn", "C. Gây ô nhiễm không khí", "D. Giảm sử dụng giấy tờ, hạn chế di chuyển, tiết kiệm năng lượng"], correctAnswer: "D. Giảm sử dụng giấy tờ, hạn chế di chuyển, tiết kiệm năng lượng" },
  { id: 490, text: "Việc làm việc từ xa (remote work) được hỗ trợ bởi công nghệ số mang lại lợi ích gì cho người lao động?", options: ["A. Giảm sự linh hoạt", "B. Khó cân bằng cuộc sống và công việc", "C. Bị cô lập", "D. Linh hoạt thời gian, địa điểm làm việc, tiết kiệm chi phí đi lại"], correctAnswer: "D. Linh hoạt thời gian, địa điểm làm việc, tiết kiệm chi phí đi lại" },
  { id: 491, text: "Công nghệ số giúp người khuyết tật hòa nhập cộng đồng tốt hơn như thế nào?", options: ["A. Cung cấp các công cụ hỗ trợ tiếp cận thông tin, giao tiếp", "B. Tạo ra rào cản", "C. Giảm cơ hội việc làm", "D. Khó tham gia các hoạt động xã hội"], correctAnswer: "A. Cung cấp các công cụ hỗ trợ tiếp cận thông tin, giao tiếp" },
  { id: 492, text: "Việc sử dụng bản đồ số (ví dụ: Google Maps) có lợi ích gì khi di chuyển?", options: ["A. Dễ bị lạc đường", "B. Chỉ dẫn sai đường", "C. Tiêu tốn nhiều dữ liệu di động", "D. Tìm đường nhanh chóng, chính xác, cập nhật tình hình giao thông"], correctAnswer: "D. Tìm đường nhanh chóng, chính xác, cập nhật tình hình giao thông" },
  { id: 493, text: "Công nghệ số giúp việc học ngoại ngữ trở nên dễ dàng hơn như thế nào?", options: ["A. Tiếp cận các ứng dụng, nền tảng học trực tuyến, tài liệu đa phương tiện phong phú", "B. Khó tìm tài liệu học", "C. Chỉ học được qua sách giấy", "D. Cần có giáo viên trực tiếp"], correctAnswer: "A. Tiếp cận các ứng dụng, nền tảng học trực tuyến, tài liệu đa phương tiện phong phú" },
  { id: 494, text: "Việc sử dụng ví điện tử để thanh toán giúp bạn làm gì?", options: ["A. Phải mang theo nhiều tiền mặt", "B. Khó theo dõi lịch sử giao dịch", "C. Thanh toán nhanh chóng, tiện lợi chỉ với thiết bị di động", "D. Chỉ dùng được ở một vài nơi"], correctAnswer: "C. Thanh toán nhanh chóng, tiện lợi chỉ với thiết bị di động" },
  { id: 495, text: "Cổng Dịch vụ công Quốc gia là gì?", options: ["A. Là trang web để chơi game", "B. Là trang web chỉ để đọc tin tức", "C. Là nơi mua sắm trực tuyến", "D. Là nền tảng trực tuyến cung cấp các dịch vụ công của cơ quan nhà nước cho người dân và doanh nghiệp"], correctAnswer: "D. Là nền tảng trực tuyến cung cấp các dịch vụ công của cơ quan nhà nước cho người dân và doanh nghiệp" },
  { id: 496, text: "Sử dụng Cổng Dịch vụ công Quốc gia mang lại lợi ích gì cho người dân và doanh nghiệp?", options: ["A. Tiết kiệm thời gian, chi phí đi lại, thực hiện thủ tục hành chính nhanh chóng, minh bạch", "B. Mất nhiều thời gian và công sức hơn", "C. Thủ tục phức tạp hơn", "D. Chỉ giải quyết được một vài thủ tục đơn giản"], correctAnswer: "A. Tiết kiệm thời gian, chi phí đi lại, thực hiện thủ tục hành chính nhanh chóng, minh bạch" },
  { id: 497, text: "VNeID là ứng dụng gì?", options: ["A. Ứng dụng đặt đồ ăn", "B. Ứng dụng nghe nhạc", "C. Ứng dụng chỉnh sửa ảnh", "D. Ứng dụng định danh điện tử do Bộ Công an phát triển"], correctAnswer: "D. Ứng dụng định danh điện tử do Bộ Công an phát triển" },
  { id: 498, text: "VNeID giúp người dân thay thế các loại giấy tờ vật lý nào?", options: ["A. Căn cước công dân, giấy phép lái xe, thẻ bảo hiểm y tế... (tích hợp thông tin)", "B. Chỉ thẻ ngân hàng", "C. Chỉ giấy khai sinh", "D. Chỉ hộ chiếu"], correctAnswer: "A. Căn cước công dân, giấy phép lái xe, thẻ bảo hiểm y tế... (tích hợp thông tin)" },
  { id: 499, text: "Sử dụng VNeID mang lại lợi ích gì?", options: ["A. Phải mang theo nhiều giấy tờ hơn", "B. Khó xác minh danh tính", "C. Chỉ sử dụng được ở một số địa điểm", "D. Thuận tiện khi thực hiện các thủ tục hành chính, giao dịch, giảm rủi ro mất mát giấy tờ"], correctAnswer: "D. Thuận tiện khi thực hiện các thủ tục hành chính, giao dịch, giảm rủi ro mất mát giấy tờ" },  { id: 500, text: "Dịch vụ công trực tuyến về bảo hiểm xã hội giúp người dân làm gì?", options: ["A. Chỉ nộp hồ sơ giấy trực tiếp", "B. Khó tra cứu thông tin", "C. Chỉ xem được thông tin cơ bản", "D. Tra cứu thông tin đóng BHXH, BHYT, quá trình tham gia, chế độ được hưởng, nộp tiền trực tuyến"], correctAnswer: "D. Tra cứu thông tin đóng BHXH, BHYT, quá trình tham gia, chế độ được hưởng, nộp tiền trực tuyến" },
  { id: 501, text: "Ứng dụng VssID của Bảo hiểm xã hội Việt Nam cung cấp những thông tin gì?", options: ["A. Chỉ thông tin về y tế", "B. Chỉ thông tin về lương", "C. Thông tin về thời tiết", "D. Thông tin về quá trình tham gia BHXH, BHYT, BHTN, lịch sử khám chữa bệnh BHYT"], correctAnswer: "D. Thông tin về quá trình tham gia BHXH, BHYT, BHTN, lịch sử khám chữa bệnh BHYT" },
  { id: 502, text: "Dịch vụ công trực tuyến trong lĩnh vực y tế giúp người dân làm gì?", options: ["A. Chỉ đặt lịch khám trực tiếp", "B. Khó tiếp cận bác sĩ", "C. Đặt lịch khám online, tra cứu thông tin y tế, tư vấn sức khỏe từ xa", "D. Chỉ dùng để xem thông tin bệnh viện"], correctAnswer: "C. Đặt lịch khám online, tra cứu thông tin y tế, tư vấn sức khỏe từ xa" },
  { id: 503, text: "Việc nộp thuế trực tuyến mang lại lợi ích gì cho doanh nghiệp và cá nhân?", options: ["A. Tốn kém nhiều thời gian", "B. Thủ tục phức tạp hơn", "C. Nhanh chóng, chính xác, tiết kiệm thời gian và chi phí đi lại", "D. Chỉ nộp được ở một vài chi cục thuế"], correctAnswer: "C. Nhanh chóng, chính xác, tiết kiệm thời gian và chi phí đi lại" },
  { id: 504, text: "Dịch vụ công trực tuyến về đăng ký kinh doanh giúp doanh nghiệp làm gì?", options: ["A. Phải đến trực tiếp cơ quan đăng ký", "B. Mất nhiều thời gian chờ đợi", "C. Đăng ký thành lập, thay đổi thông tin doanh nghiệp trực tuyến", "D. Chỉ áp dụng cho doanh nghiệp lớn"], correctAnswer: "C. Đăng ký thành lập, thay đổi thông tin doanh nghiệp trực tuyến" },
  { id: 505, text: "Việc cấp phiếu lý lịch tư pháp trực tuyến là một ví dụ về dịch vụ công trực tuyến ở mức độ nào?", options: ["A. Mức độ 1 (Cung cấp thông tin)", "B. Mức độ 2 (Tải mẫu đơn)", "C. Mức độ 3 (Nộp và tiếp nhận hồ sơ trực tuyến)", "D. Mức độ 4 (Thanh toán trực tuyến và nhận kết quả trực tuyến)"], correctAnswer: "D. Mức độ 4 (Thanh toán trực tuyến và nhận kết quả trực tuyến)" },
  { id: 506, text: "Lợi ích của việc sử dụng dịch vụ công trực tuyến mức độ cao (3, 4) là gì?", options: ["A. Có thể hoàn thành thủ tục mọi lúc, mọi nơi, giảm thiểu việc đi lại", "B. Vẫn phải đến cơ quan nhà nước nhiều lần", "C. Thủ tục rườm rà hơn", "D. Chỉ áp dụng cho một số đối tượng"], correctAnswer: "A. Có thể hoàn thành thủ tục mọi lúc, mọi nơi, giảm thiểu việc đi lại" },
  { id: 507, text: "Cổng Dịch vụ công Quốc gia được quản lý bởi cơ quan nào?", options: ["A. Văn phòng Chính phủ", "B. Bộ Y tế", "C. Bộ Giáo dục và Đào tạo", "D. Bộ Công Thương"], correctAnswer: "A. Văn phòng Chính phủ" },
  { id: 508, text: "Khi sử dụng dịch vụ công trực tuyến, bạn cần đảm bảo điều gì về thông tin cá nhân?", options: ["A. Có thể chia sẻ thoải mái", "B. Không cần quan tâm đến bảo mật", "C. Cung cấp thông tin sai lệch", "D. Bảo mật thông tin cá nhân và tài khoản"], correctAnswer: "D. Bảo mật thông tin cá nhân và tài khoản" },
  { id: 509, text: "Dịch vụ công trực tuyến giúp tăng cường tính ______ trong giải quyết thủ tục hành chính.", options: ["A. Minh bạch", "B. Phức tạp", "C. Chậm chạp", "D. Tùy tiện"], correctAnswer: "A. Minh bạch" },
  { id: 510, text: "Việc tích hợp các dịch vụ công lên Cổng Dịch vụ công Quốc gia nhằm mục đích gì?", options: ["A. Tạo sự thuận tiện, tập trung cho người dân và doanh nghiệp khi thực hiện các thủ tục", "B. Làm cho thủ tục phức tạp hơn", "C. Giảm số lượng dịch vụ công", "D. Chỉ phục vụ cho một vài ngành"], correctAnswer: "A. Tạo sự thuận tiện, tập trung cho người dân và doanh nghiệp khi thực hiện các thủ tục" },
  { id: 511, text: "VNeID sử dụng công nghệ gì để xác thực danh tính người dùng?", options: ["A. Nhận diện giọng nói", "B. Nhận diện chữ viết", "C. Chỉ dùng mật khẩu", "D. Sinh trắc học (vân tay, khuôn mặt) và mã QR"], correctAnswer: "D. Sinh trắc học (vân tay, khuôn mặt) và mã QR" },
  { id: 512, text: "Tra cứu mã số BHXH và thông tin thẻ BHYT có thể thực hiện ở đâu?", options: ["A. Chỉ tại cơ quan BHXH", "B. Chỉ qua điện thoại", "C. Trên các trang web không chính thức", "D. Trên Cổng Dịch vụ công BHXH Việt Nam hoặc ứng dụng VssID"], correctAnswer: "D. Trên Cổng Dịch vụ công BHXH Việt Nam hoặc ứng dụng VssID" },
  { id: 513, text: "Đăng ký khai sinh trực tuyến là một ví dụ về dịch vụ công trực tuyến trong lĩnh vực nào?", options: ["A. Tư pháp", "B. Giáo dục", "C. Y tế", "D. Giao thông"], correctAnswer: "A. Tư pháp" },
  { id: 514, text: "Việc xin cấp giấy phép xây dựng trực tuyến giúp giảm bớt thủ tục nào?", options: ["A. Thủ tục nộp thuế", "B. Thủ tục mua vật liệu xây dựng", "C. Thủ tục thuê nhân công", "D. Thủ tục nộp hồ sơ giấy và chờ đợi tại cơ quan nhà nước"], correctAnswer: "D. Thủ tục nộp hồ sơ giấy và chờ đợi tại cơ quan nhà nước" },
  { id: 515, text: "Lừa đảo trực tuyến là gì?", options: ["A. Là việc mua sắm trên mạng", "B. Là việc đọc báo online", "C. Là việc chơi game online", "D. Là hành vi gian lận trên không gian mạng nhằm chiếm đoạt thông tin hoặc tài sản"], correctAnswer: "D. Là hành vi gian lận trên không gian mạng nhằm chiếm đoạt thông tin hoặc tài sản" },
  { id: 516, text: "Làm thế nào để nhận biết một email lừa đảo (phishing email)?", options: ["A. Email có nội dung rất chuyên nghiệp", "B. Email từ ngân hàng của bạn", "C. Email quảng cáo sản phẩm", "D. Email yêu cầu cung cấp thông tin cá nhân nhạy cảm (mật khẩu, số thẻ tín dụng), có lỗi chính tả hoặc đường link lạ"], correctAnswer: "D. Email yêu cầu cung cấp thông tin cá nhân nhạy cảm (mật khẩu, số thẻ tín dụng), có lỗi chính tả hoặc đường link lạ" },
  { id: 517, text: "Khi nhận được tin nhắn/cuộc gọi từ số lạ yêu cầu chuyển tiền gấp, bạn nên làm gì?", options: ["A. Ngay lập tức chuyển tiền theo yêu cầu", "B. Cung cấp mã OTP ngay lập tức", "C. Chia sẻ thông tin với bạn bè trên mạng xã hội", "D. Giữ bình tĩnh, xác minh thông tin bằng cách gọi lại cho người thân hoặc cơ quan liên quan qua số điện thoại chính thức"], correctAnswer: "D. Giữ bình tĩnh, xác minh thông tin bằng cách gọi lại cho người thân hoặc cơ quan liên quan qua số điện thoại chính thức" },
  { id: 518, text: "Đâu là dấu hiệu của một trang web giả mạo?", options: ["A. Tên miền quen thuộc", "B. Có chứng chỉ bảo mật SSL (biểu tượng ổ khóa xanh)", "C. Cung cấp thông tin đầy đủ", "D. Tên miền có lỗi chính tả, giao diện sơ sài, không có thông tin liên hệ rõ ràng"], correctAnswer: "D. Tên miền có lỗi chính tả, giao diện sơ sài, không có thông tin liên hệ rõ ràng" },
  { id: 519, text: "Bạn nên làm gì với mật khẩu của mình?", options: ["A. Sử dụng một mật khẩu cho tất cả các tài khoản", "B. Ghi mật khẩu ra giấy và dán ở màn hình máy tính", "C. Sử dụng mật khẩu đơn giản để dễ nhớ", "D. Thay đổi mật khẩu định kỳ và không chia sẻ cho bất kỳ ai"], correctAnswer: "D. Thay đổi mật khẩu định kỳ và không chia sẻ cho bất kỳ ai" },
  { id: 520, text: "Xác thực hai yếu tố (2FA) là gì?", options: ["A. Chỉ đăng nhập bằng mật khẩu", "B. Chỉ cần nhập tên đăng nhập", "C. Sử dụng chung tài khoản với người khác", "D. Yêu cầu hai hình thức xác minh danh tính khi đăng nhập (ví dụ: mật khẩu và mã OTP gửi đến điện thoại)"], correctAnswer: "D. Yêu cầu hai hình thức xác minh danh tính khi đăng nhập (ví dụ: mật khẩu và mã OTP gửi đến điện thoại)" },
  { id: 521, text: "Lợi ích của việc sử dụng xác thực hai yếu tố (2FA) là gì?", options: ["A. Giảm bảo mật tài khoản", "B. Gây khó khăn khi đăng nhập", "C. Không có tác dụng gì", "D. Tăng cường đáng kể tính bảo mật cho tài khoản của bạn"], correctAnswer: "D. Tăng cường đáng kể tính bảo mật cho tài khoản của bạn" },
  { id: 522, text: "Bạn nên cẩn trọng khi tải xuống tệp đính kèm từ đâu?", options: ["A. Email từ người quen", "B. Email từ đồng nghiệp", "C. Email hoặc tin nhắn từ người lạ, không rõ nguồn gốc", "D. Email từ sếp"], correctAnswer: "C. Email hoặc tin nhắn từ người lạ, không rõ nguồn gốc" },
  { id: 523, text: "Phần mềm độc hại (malware) là gì?", options: ["A. Là phần mềm diệt virus", "B. Là trò chơi giải trí", "C. Là ứng dụng văn phòng", "D. Là phần mềm được thiết kế để gây hại cho máy tính hoặc đánh cắp thông tin"], correctAnswer: "D. Là phần mềm được thiết kế để gây hại cho máy tính hoặc đánh cắp thông tin" },
  { id: 524, text: "Làm thế nào để bảo vệ máy tính khỏi phần mềm độc hại?", options: ["A. Tắt phần mềm diệt virus", "B. Tải phần mềm từ các nguồn không tin cậy", "C. Mở tất cả các email đính kèm", "D. Cài đặt phần mềm diệt virus uy tín và cập nhật thường xuyên, cẩn trọng khi tải tệp từ internet"], correctAnswer: "D. Cài đặt phần mềm diệt virus uy tín và cập nhật thường xuyên, cẩn trọng khi tải tệp từ internet" },
  { id: 525, text: "Bạn nên làm gì khi sử dụng mạng Wi-Fi công cộng?", options: ["A. Thoải mái truy cập các trang web nhạy cảm", "B. Chia sẻ mật khẩu Wi-Fi với người lạ", "C. Tải xuống nhiều tệp", "D. Hạn chế truy cập thông tin cá nhân, giao dịch ngân hàng và sử dụng VPN nếu có thể"], correctAnswer: "D. Hạn chế truy cập thông tin cá nhân, giao dịch ngân hàng và sử dụng VPN nếu có thể" },
  { id: 526, text: "Tấn công phishing nhằm mục đích gì?", options: ["A. Chia sẻ kiến thức hữu ích", "B. Lừa đảo để lấy cắp thông tin cá nhân, tài khoản, mật khẩu", "C. Cung cấp dịch vụ miễn phí", "D. Giới thiệu sản phẩm mới"], correctAnswer: "B. Lừa đảo để lấy cắp thông tin cá nhân, tài khoản, mật khẩu" },
  { id: 527, text: "Khi nhận được yêu cầu cung cấp thông tin cá nhân qua điện thoại, bạn nên làm gì?", options: ["A. Không cung cấp thông tin và xác minh lại với tổ chức/cá nhân liên quan qua kênh liên lạc chính thức", "B. Cung cấp ngay thông tin được yêu cầu", "C. Chia sẻ thông tin với bất kỳ ai hỏi", "D. Giả vờ không nghe thấy"], correctAnswer: "A. Không cung cấp thông tin và xác minh lại với tổ chức/cá nhân liên quan qua kênh liên lạc chính thức" },
  { id: 528, text: "Đâu là cách bảo vệ thông tin cá nhân trên mạng xã hội?", options: ["A. Công khai tất cả thông tin", "B. Chấp nhận tất cả lời mời kết bạn", "C. Chia sẻ mật khẩu tài khoản", "D. Cài đặt quyền riêng tư chặt chẽ, cẩn trọng khi chấp nhận lời mời kết bạn từ người lạ"], correctAnswer: "D. Cài đặt quyền riêng tư chặt chẽ, cẩn trọng khi chấp nhận lời mời kết bạn từ người lạ" },
  { id: 529, text: "Mã độc tống tiền (Ransomware) là loại phần mềm độc hại làm gì?", options: ["A. Hiển thị quảng cáo", "B. Mã hóa dữ liệu của nạn nhân và yêu cầu trả tiền để giải mã", "C. Tăng tốc độ máy tính", "D. Xóa các tệp không cần thiết"], correctAnswer: "B. Mã hóa dữ liệu của nạn nhân và yêu cầu trả tiền để giải mã" },
  { id: 530, text: "Bạn nên làm gì để phòng tránh mã độc tống tiền?", options: ["A. Mở tất cả các tệp đính kèm trong email", "B. Tắt chức năng sao lưu", "C. Tải phần mềm từ các nguồn không chính thức", "D. Sao lưu dữ liệu thường xuyên, cẩn trọng với email và đường link lạ, cập nhật phần mềm diệt virus"], correctAnswer: "D. Sao lưu dữ liệu thường xuyên, cẩn trọng với email và đường link lạ, cập nhật phần mềm diệt virus" },
  { id: 531, text: "Lừa đảo \"việc nhẹ lương cao\" trên mạng thường có dấu hiệu gì?", options: ["A. Yêu cầu đặt cọc hoặc thanh toán trước khi bắt đầu công việc", "B. Cung cấp thông tin rõ ràng về công ty và công việc", "C. Lương thưởng hợp lý", "D. Không yêu cầu bất kỳ khoản phí nào"], correctAnswer: "A. Yêu cầu đặt cọc hoặc thanh toán trước khi bắt đầu công việc" },
  { id: 532, text: "Khi trình duyệt web hiển thị cảnh báo về trang web không an toàn, bạn nên làm gì?", options: ["A. Bỏ qua cảnh báo và tiếp tục truy cập", "B. Cung cấp thông tin cá nhân", "C. Tải xuống tệp từ trang web đó", "D. Đóng trang web ngay lập tức"], correctAnswer: "D. Đóng trang web ngay lập tức" },
  { id: 533, text: "Nên sử dụng trình quản lý mật khẩu để làm gì?", options: ["A. Lưu trữ mật khẩu đơn giản", "B. Chia sẻ mật khẩu với người khác", "C. Giảm số lượng mật khẩu cần nhớ", "D. Tạo và lưu trữ các mật khẩu phức tạp một cách an toàn"], correctAnswer: "D. Tạo và lưu trữ các mật khẩu phức tạp một cách an toàn" },
  { id: 534, text: "Tấn công DDoS (Distributed Denial of Service) là gì?", options: ["A. Tấn công nhằm đánh cắp dữ liệu", "B. Tấn công nhằm thay đổi nội dung trang web", "C. Tấn công làm quá tải hệ thống máy chủ, khiến dịch vụ bị gián đoạn", "D. Tấn công nhằm lây lan virus"], correctAnswer: "C. Tấn công làm quá tải hệ thống máy chủ, khiến dịch vụ bị gián đoạn" },
  { id: 535, text: "Để bảo vệ tài khoản ngân hàng trực tuyến, bạn nên làm gì?", options: ["A. Chia sẻ thông tin đăng nhập", "B. Giao dịch trên các trang web không có https", "C. Không kiểm tra sao kê ngân hàng", "D. Sử dụng mật khẩu mạnh, bật xác thực hai yếu tố, không truy cập từ mạng Wi-Fi công cộng không bảo mật"], correctAnswer: "D. Sử dụng mật khẩu mạnh, bật xác thực hai yếu tố, không truy cập từ mạng Wi-Fi công cộng không bảo mật" },
  { id: 536, text: "Kỹ thuật \"social engineering\" trong an toàn thông tin là gì?", options: ["A. Sử dụng công nghệ phức tạp để tấn công hệ thống", "B. Thao túng tâm lý con người để lấy thông tin hoặc truy cập trái phép", "C. Chỉ liên quan đến mạng xã hội", "D. Xây dựng phần mềm bảo mật"], correctAnswer: "B. Thao túng tâm lý con người để lấy thông tin hoặc truy cập trái phép" },
  { id: 537, text: "Khi nhận được yêu cầu cập nhật thông tin tài khoản qua một đường link trong email, bạn nên làm gì?", options: ["A. Click vào link và cập nhật thông tin ngay", "B. Chia sẻ đường link với người khác", "C. Không click vào link và truy cập trực tiếp vào trang web chính thức của dịch vụ để kiểm tra", "D. Phản hồi lại email với thông tin cá nhân"], correctAnswer: "C. Không click vào link và truy cập trực tiếp vào trang web chính thức của dịch vụ để kiểm tra" },
  { id: 538, text: "Nên cẩn trọng với các quảng cáo trực tuyến nào?", options: ["A. Quảng cáo từ các thương hiệu lớn", "B. Quảng cáo sản phẩm thông thường", "C. Quảng cáo từ các trang web uy tín", "D. Quảng cáo hứa hẹn lợi nhuận \"khủng\" một cách dễ dàng hoặc yêu cầu cung cấp thông tin cá nhân nhạy cảm"], correctAnswer: "D. Quảng cáo hứa hẹn lợi nhuận \"khủng\" một cách dễ dàng hoặc yêu cầu cung cấp thông tin cá nhân nhạy cảm" },
  { id: 539, text: "Lừa đảo qua điện thoại (vishing) là gì?", options: ["A. Lừa đảo qua email", "B. Lừa đảo qua cuộc gọi điện thoại", "C. Lừa đảo qua tin nhắn SMS", "D. Lừa đảo qua mạng xã hội"], correctAnswer: "B. Lừa đảo qua cuộc gọi điện thoại" },
  { id: 540, text: "Khi sử dụng các ứng dụng trên điện thoại, bạn nên kiểm tra quyền truy cập của ứng dụng vào đâu?", options: ["A. Không cần kiểm tra", "B. Chỉ kiểm tra dung lượng ứng dụng", "C. Chỉ kiểm tra tên nhà phát triển", "D. Quyền truy cập vào danh bạ, vị trí, ảnh, micro... để đảm bảo phù hợp với chức năng của ứng dụng"], correctAnswer: "D. Quyền truy cập vào danh bạ, vị trí, ảnh, micro... để đảm bảo phù hợp với chức năng của ứng dụng" },
  { id: 541, text: "Nên làm gì với các thiết bị điện tử cũ không còn sử dụng?", options: ["A. Bán lại cho người lạ mà không xóa dữ liệu", "B. Vứt bỏ trực tiếp vào thùng rác", "C. Giữ lại tất cả dữ liệu", "D. Xóa sạch dữ liệu cá nhân trước khi bán, cho tặng hoặc tiêu hủy"], correctAnswer: "D. Xóa sạch dữ liệu cá nhân trước khi bán, cho tặng hoặc tiêu hủy" },
  { id: 542, text: "Lợi ích của việc sử dụng mạng riêng ảo (VPN) là gì?", options: ["A. Giúp ẩn địa chỉ IP và mã hóa dữ liệu khi truy cập internet, tăng tính riêng tư và bảo mật", "B. Giảm tốc độ internet", "C. Chỉ dùng để xem phim", "D. Không có tác dụng bảo mật"], correctAnswer: "A. Giúp ẩn địa chỉ IP và mã hóa dữ liệu khi truy cập internet, tăng tính riêng tư và bảo mật" },
  { id: 543, text: "Đâu là một dấu hiệu cảnh báo của lừa đảo \"Romans lừa đảo\"?", options: ["A. Yêu cầu chuyển tiền để nhận quà tặng từ nước ngoài", "B. Gửi quà tặng mà không yêu cầu gì", "C. Chỉ trò chuyện thông thường", "D. Cung cấp thông tin cá nhân đầy đủ"], correctAnswer: "A. Yêu cầu chuyển tiền để nhận quà tặng từ nước ngoài" },
  { id: 544, text: "Khi nhận được tin nhắn SMS chứa đường link lạ, bạn nên làm gì?", options: ["A. Click vào đường link để xem nội dung", "B. Không click vào đường link và xóa tin nhắn", "C. Chuyển tiếp tin nhắn cho người khác", "D. Phản hồi lại tin nhắn"], correctAnswer: "B. Không click vào đường link và xóa tin nhắn" },
  { id: 545, text: "Việc cập nhật hệ điều hành và phần mềm trên thiết bị có lợi ích gì về an toàn thông tin?", options: ["A. Làm giảm hiệu suất thiết bị", "B. Không có tác dụng gì", "C. Tăng nguy cơ bị tấn công", "D. Vá các lỗ hổng bảo mật và tăng cường khả năng chống lại các mối đe dọa mới"], correctAnswer: "D. Vá các lỗ hổng bảo mật và tăng cường khả năng chống lại các mối đe dọa mới" },
  { id: 546, text: "Nên làm gì khi phát hiện tài khoản trực tuyến của mình bị xâm nhập?", options: ["A. Giữ im lặng và không làm gì cả", "B. Chia sẻ thông tin với mọi người", "C. Tạo một tài khoản mới và bỏ qua tài khoản cũ", "D. Thay đổi mật khẩu ngay lập tức, thông báo cho nhà cung cấp dịch vụ và kiểm tra các hoạt động đáng ngờ"], correctAnswer: "D. Thay đổi mật khẩu ngay lập tức, thông báo cho nhà cung cấp dịch vụ và kiểm tra các hoạt động đáng ngờ" },
  { id: 547, text: "An toàn thông tin là trách nhiệm của ai?", options: ["A. Chỉ của các chuyên gia bảo mật", "B. Chỉ của các tổ chức lớn", "C. Chỉ của nhà cung cấp dịch vụ", "D. Của tất cả mọi người sử dụng công nghệ số"], correctAnswer: "D. Của tất cả mọi người sử dụng công nghệ số" },
  { id: 548, text: "Công nghệ số thay đổi cách chúng ta làm việc như thế nào?", options: ["A. Làm việc chậm hơn", "B. Giảm sự hợp tác", "C. Chỉ làm việc thủ công", "D. Tăng năng suất, tạo ra các công việc mới và cho phép làm việc từ xa"], correctAnswer: "D. Tăng năng suất, tạo ra các công việc mới và cho phép làm việc từ xa" },
  { id: 549, text: "Đâu là ví dụ về công nghệ số trong nông nghiệp?", options: ["A. Chỉ sử dụng công cụ thô sơ", "B. Giảm diện tích trồng trọt", "C. Không sử dụng phân bón", "D. Áp dụng IoT để giám sát cây trồng, vật nuôi; sử dụng máy bay không người lái"], correctAnswer: "D. Áp dụng IoT để giám sát cây trồng, vật nuôi; sử dụng máy bay không người lái" },  { id: 550, text: "Thành phố thông minh (Smart City) là gì?", options: ["A. Là thành phố chỉ có nhiều tòa nhà cao tầng", "B. Là thành phố không có internet", "C. Là thành phố chỉ sử dụng năng lượng truyền thống", "D. Là thành phố ứng dụng công nghệ số để quản lý hạ tầng, nâng cao chất lượng cuộc sống"], correctAnswer: "D. Là thành phố ứng dụng công nghệ số để quản lý hạ tầng, nâng cao chất lượng cuộc sống" },
  { id: 551, text: "Lợi ích của việc học trực tuyến theo tốc độ cá nhân là gì?", options: ["A. Phải theo kịp tốc độ của người khác", "B. Cho phép người học tập trung vào những phần khó và bỏ qua phần đã nắm vững", "C. Bị giới hạn thời gian học", "D. Khó ôn tập lại bài"], correctAnswer: "B. Cho phép người học tập trung vào những phần khó và bỏ qua phần đã nắm vững" },
  { id: 552, text: "Thanh toán QR Code là hình thức thanh toán không dùng tiền mặt như thế nào?", options: ["A. Sử dụng máy POS", "B. Thanh toán bằng thẻ cào điện thoại", "C. Sử dụng điện thoại quét mã để chuyển tiền", "D. Thanh toán bằng tiền xu"], correctAnswer: "C. Sử dụng điện thoại quét mã để chuyển tiền" },
  { id: 553, text: "Cổng Dịch vụ công Quốc gia giúp người dân tra cứu thông tin về điều gì?", options: ["A. Kết quả xổ số", "B. Lịch chiếu phim", "C. Thông tin khuyến mãi", "D. Tình trạng giải quyết hồ sơ thủ tục hành chính"], correctAnswer: "D. Tình trạng giải quyết hồ sơ thủ tục hành chính" },
  { id: 554, text: "Khi tạo mật khẩu, bạn nên tránh sử dụng thông tin nào?", options: ["A. Các ký tự ngẫu nhiên", "B. Kết hợp chữ và số", "C. Các ký tự đặc biệt", "D. Thông tin cá nhân dễ đoán như tên, ngày sinh, số điện thoại"], correctAnswer: "D. Thông tin cá nhân dễ đoán như tên, ngày sinh, số điện thoại" },
  { id: 555, text: "Lừa đảo qua tin nhắn SMS (smishing) là gì?", options: ["A. Lừa đảo qua email", "B. Lừa đảo qua mạng xã hội", "C. Lừa đảo qua cuộc gọi điện thoại", "D. Lừa đảo qua tin nhắn SMS"], correctAnswer: "D. Lừa đảo qua tin nhắn SMS" },
  { id: 556, text: "An toàn thông tin nhằm đảm bảo các yếu tố cốt lõi nào?", options: ["A. Tính bảo mật, tính toàn vẹn và tính sẵn sàng của thông tin", "B. Chỉ tính bảo mật", "C. Chỉ tính khả dụng", "D. Chỉ tính chính xác"], correctAnswer: "A. Tính bảo mật, tính toàn vẹn và tính sẵn sàng của thông tin" },
  { id: 557, text: "Tính toàn vẹn (Integrity) trong an toàn thông tin nghĩa là gì?", options: ["A. Thông tin chỉ có thể được xem bởi người được phép", "B. Thông tin luôn sẵn sàng để truy cập", "C. Thông tin chính xác, đầy đủ và không bị thay đổi trái phép", "D. Thông tin được sao lưu thường xuyên"], correctAnswer: "C. Thông tin chính xác, đầy đủ và không bị thay đổi trái phép" },
  { id: 558, text: "Tính sẵn sàng (Availability) trong an toàn thông tin nghĩa là gì?", options: ["A. Thông tin được bảo vệ khỏi virus", "B. Thông tin được mã hóa", "C. Thông tin và hệ thống luôn sẵn sàng để người dùng hợp pháp truy cập khi cần", "D. Thông tin chỉ được lưu trữ ở một nơi"], correctAnswer: "C. Thông tin và hệ thống luôn sẵn sàng để người dùng hợp pháp truy cập khi cần" },
  { id: 559, text: "Tấn công \"man-in-the-middle\" là gì?", options: ["A. Tấn công trực tiếp vào máy chủ", "B. Kẻ tấn công chặn và nghe lén hoặc thay đổi dữ liệu truyền giữa hai bên", "C. Tấn công làm sập mạng", "D. Tấn công phát tán thư rác"], correctAnswer: "B. Kẻ tấn công chặn và nghe lén hoặc thay đổi dữ liệu truyền giữa hai bên" },
  { id: 560, text: "Làm thế nào để phòng tránh tấn công \"man-in-the-middle\"?", options: ["A. Sử dụng mạng Wi-Fi công cộng không bảo mật", "B. Không sử dụng internet", "C. Chia sẻ thông tin cá nhân trên mạng", "D. Sử dụng kết nối HTTPS, VPN và cẩn trọng khi truy cập mạng công cộng"], correctAnswer: "D. Sử dụng kết nối HTTPS, VPN và cẩn trọng khi truy cập mạng công cộng" },
  { id: 561, text: "Lừa đảo đầu tư trực tuyến thường có dấu hiệu gì?", options: ["A. Hứa hẹn lợi nhuận cao, rủi ro thấp và yêu cầu chuyển tiền gấp", "B. Cung cấp thông tin rõ ràng về dự án và công ty", "C. Không yêu cầu bất kỳ khoản phí nào", "D. Có giấy phép hoạt động đầy đủ"], correctAnswer: "A. Hứa hẹn lợi nhuận cao, rủi ro thấp và yêu cầu chuyển tiền gấp" },
  { id: 562, text: "Khi sử dụng các dịch vụ trực tuyến, nên tạo mật khẩu riêng biệt cho những tài khoản quan trọng nào?", options: ["A. Tất cả các tài khoản đều dùng chung mật khẩu", "B. Chỉ tài khoản giải trí", "C. Chỉ tài khoản mua sắm", "D. Email chính, tài khoản ngân hàng, mạng xã hội"], correctAnswer: "D. Email chính, tài khoản ngân hàng, mạng xã hội" },
  { id: 563, text: "Phần mềm diệt virus có chức năng chính là gì?", options: ["A. Phát hiện, ngăn chặn và loại bỏ phần mềm độc hại", "B. Tăng tốc độ internet", "C. Chỉnh sửa ảnh", "D. Nghe nhạc"], correctAnswer: "A. Phát hiện, ngăn chặn và loại bỏ phần mềm độc hại" },
  { id: 564, text: "Nên làm gì khi nhận được yêu cầu xác nhận thông tin thẻ tín dụng qua điện thoại hoặc email?", options: ["A. Cung cấp thông tin ngay lập tức", "B. Chia sẻ thông tin với bạn bè", "C. Không cung cấp thông tin và liên hệ trực tiếp với ngân hàng qua số điện thoại chính thức", "D. Trả lời email với thông tin thẻ"], correctAnswer: "C. Không cung cấp thông tin và liên hệ trực tiếp với ngân hàng qua số điện thoại chính thức" },
  { id: 565, text: "Lợi ích của việc sao lưu dữ liệu lên đám mây là gì?", options: ["A. Tốn kém nhiều chi phí", "B. Dễ bị mất dữ liệu", "C. Chỉ sao lưu được một ít dữ liệu", "D. An toàn, tiện lợi, có thể truy cập từ nhiều thiết bị và địa điểm"], correctAnswer: "D. An toàn, tiện lợi, có thể truy cập từ nhiều thiết bị và địa điểm" },
  { id: 566, text: "Nên cẩn trọng với các cuộc thi hoặc chương trình tặng quà trên mạng xã hội yêu cầu cung cấp thông tin cá nhân hoặc chia sẻ bài viết công khai?", options: ["A. Nên tham gia hết để nhận quà", "B. Chia sẻ thông tin cá nhân thoải mái", "C. Không cần kiểm tra gì cả", "D. Nên kiểm tra độ uy tín của nguồn và cẩn trọng với việc cung cấp thông tin cá nhân"], correctAnswer: "D. Nên kiểm tra độ uy tín của nguồn và cẩn trọng với việc cung cấp thông tin cá nhân" },
  { id: 567, text: "Lừa đảo \"giả danh\" (impersonation) là gì?", options: ["A. Lừa đảo bằng cách giả mạo người khác (người thân, bạn bè, cơ quan chức năng)", "B. Lừa đảo bằng cách gửi thư rác", "C. Lừa đảo bằng cách tạo trang web giả mạo", "D. Lừa đảo bằng cách tấn công hệ thống"], correctAnswer: "A. Lừa đảo bằng cách giả mạo người khác (người thân, bạn bè, cơ quan chức năng)" },
  { id: 568, text: "Khi cài đặt ứng dụng mới, nên đọc kỹ điều khoản sử dụng và quyền riêng tư để biết ứng dụng thu thập thông tin gì?", options: ["A. Nên đọc kỹ", "B. Không cần đọc", "C. Chỉ đọc phần giới thiệu", "D. Chỉ đọc tên ứng dụng"], correctAnswer: "A. Nên đọc kỹ" },
  { id: 569, text: "Nên làm gì khi nhận được thông báo trúng thưởng các giải thưởng lớn mà bạn không tham gia?", options: ["A. Liên hệ ngay để nhận giải", "B. Chia sẻ thông báo lên mạng xã hội", "C. Cung cấp thông tin ngân hàng để nhận tiền", "D. Coi chừng lừa đảo, không cung cấp thông tin cá nhân và không chuyển bất kỳ khoản phí nào"], correctAnswer: "D. Coi chừng lừa đảo, không cung cấp thông tin cá nhân và không chuyển bất kỳ khoản phí nào" },
  { id: 570, text: "Việc sử dụng mật khẩu khác nhau cho các tài khoản quan trọng giúp giảm thiểu rủi ro gì?", options: ["A. Khó nhớ mật khẩu hơn", "B. Tăng nguy cơ bị hack", "C. Không có tác dụng gì", "D. Nếu một tài khoản bị lộ mật khẩu, các tài khoản khác sẽ không bị ảnh hưởng"], correctAnswer: "D. Nếu một tài khoản bị lộ mật khẩu, các tài khoản khác sẽ không bị ảnh hưởng" },
  { id: 571, text: "Firewall (Tường lửa) có chức năng gì trong an toàn thông tin?", options: ["A. Tăng tốc độ mạng", "B. Sao lưu dữ liệu", "C. Kiểm soát luồng dữ liệu ra vào mạng và ngăn chặn truy cập trái phép", "D. Quét virus"], correctAnswer: "C. Kiểm soát luồng dữ liệu ra vào mạng và ngăn chặn truy cập trái phép" },
  { id: 572, text: "Nên cẩn trọng với các đường link rút gọn được chia sẻ trên mạng xã hội hoặc tin nhắn vì có thể dẫn đến đâu?", options: ["A. Các trang web hữu ích", "B. Các trang web độc hại, lừa đảo hoặc chứa mã độc", "C. Các trang web chính thức", "D. Các bài viết thú vị"], correctAnswer: "B. Các trang web độc hại, lừa đảo hoặc chứa mã độc" },
  { id: 573, text: "Chứng chỉ SSL (HTTPS) trên trang web có ý nghĩa gì về an toàn thông tin?", options: ["A. Trang web không an toàn", "B. Trang web chứa virus", "C. Kết nối giữa trình duyệt và trang web được mã hóa, giúp bảo vệ dữ liệu truyền đi", "D. Trang web không hoạt động"], correctAnswer: "C. Kết nối giữa trình duyệt và trang web được mã hóa, giúp bảo vệ dữ liệu truyền đi" },
  { id: 574, text: "Nên làm gì khi phát hiện hoạt động đáng ngờ trên tài khoản ngân hàng trực tuyến?", options: ["A. Không làm gì cả", "B. Chia sẻ thông tin lên mạng xã hội", "C. Thay đổi mật khẩu và tiếp tục sử dụng", "D. Liên hệ ngay với ngân hàng để được hỗ trợ"], correctAnswer: "D. Liên hệ ngay với ngân hàng để được hỗ trợ" },
  { id: 575, text: "Lừa đảo qua mạng xã hội thường sử dụng những hình thức nào?", options: ["A. Chỉ đăng bài viết thông thường", "B. Chỉ chia sẻ ảnh", "C. Chỉ kết bạn", "D. Giả mạo tài khoản, gửi tin nhắn lừa đảo, đăng bài quảng cáo sai sự thật"], correctAnswer: "D. Giả mạo tài khoản, gửi tin nhắn lừa đảo, đăng bài quảng cáo sai sự thật" },
  { id: 576, text: "Nên bật chức năng cập nhật tự động cho hệ điều hành và phần mềm để đảm bảo an toàn?", options: ["A. Nên bật", "B. Không nên bật", "C. Chỉ bật cho một số ứng dụng", "D. Không quan trọng"], correctAnswer: "A. Nên bật" },
  { id: 577, text: "Lợi ích của việc sử dụng chữ ký số trong giao dịch điện tử là gì?", options: ["A. Làm chậm quá trình giao dịch", "B. Không có giá trị pháp lý", "C. Dễ dàng bị giả mạo", "D. Xác thực danh tính người ký và đảm bảo tính toàn vẹn của văn bản"], correctAnswer: "D. Xác thực danh tính người ký và đảm bảo tính toàn vẹn của văn bản" },
  { id: 578, text: "Phishing là một dạng tấn công phi kỹ thuật (social engineering) đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 579, text: "Nên sử dụng mật khẩu mạnh và khác nhau cho từng tài khoản trực tuyến là biện pháp bảo mật cơ bản đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 580, text: "Chia sẻ mật khẩu với người thân hoặc bạn bè thân thiết là an toàn đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 581, text: "Tải phần mềm từ các trang web không chính thức hoặc quảng cáo pop-up là an toàn đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 582, text: "Kết nối mạng Wi-Fi công cộng không yêu cầu mật khẩu là an toàn để thực hiện giao dịch ngân hàng trực tuyến đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 583, text: "Sao lưu dữ liệu thường xuyên giúp bảo vệ dữ liệu khỏi mất mát do tấn công mạng hoặc hỏng hóc thiết bị đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 584, text: "Click vào các đường link trong email hoặc tin nhắn từ người lạ là an toàn đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 585, text: "Sử dụng xác thực hai yếu tố (2FA) giúp tăng cường bảo mật cho tài khoản đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 586, text: "Phần mềm độc hại (malware) có thể đánh cắp thông tin cá nhân hoặc gây hại cho thiết bị đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 587, text: "Lừa đảo qua điện thoại (vishing) là hình thức lừa đảo bằng tin nhắn SMS đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 588, text: "Kiểm tra quyền truy cập của ứng dụng trước khi cài đặt là không cần thiết đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 589, text: "Việc xóa sạch dữ liệu cá nhân trước khi thanh lý thiết bị điện tử cũ là quan trọng để bảo mật đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 590, text: "Sử dụng VPN giúp tăng tính riêng tư và bảo mật khi truy cập internet đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 591, text: "Lừa đảo \"Romans lừa đảo\" liên quan đến việc yêu cầu chuyển tiền để nhận quà từ nước ngoài đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 592, text: "Click vào đường link lạ trong tin nhắn SMS là an toàn đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" },
  { id: 593, text: "Cập nhật hệ điều hành và phần mềm giúp tăng cường bảo mật đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "A. Đúng" },
  { id: 594, text: "Khi tài khoản trực tuyến bị xâm nhập, không cần làm gì cả đúng hay sai?", options: ["A. Đúng", "B. Sai"], correctAnswer: "B. Sai" }
];
window.questions = questions;
function getRandomQuestions(count) {
  const shuffled = [...questions].sort(() => 0.5 - Math.random());
  return shuffled.slice(0, Math.min(count, shuffled.length));
}
